-- Poems batch 470
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-62','庭竹','李鹹用','唐','御定全唐诗','yuding','','[]','嫩綠與老碧，森然庭砌中。坐銷三伏景，吟起數竿風。',48,'御定全唐詩/json/645.json','["嫩綠與老碧，森然庭砌中。坐銷三伏景，吟起數竿風。", "葉影重還密，梢聲遠或通。更期春共看，桃映小花紅。"]'),
('yuding-63','早行','李鹹用','唐','御定全唐诗','yuding','','[]','家國三千里，中宵算去程。困才成蝶夢，行不待雞鳴。',48,'御定全唐詩/json/645.json','["家國三千里，中宵算去程。困才成蝶夢，行不待雞鳴。", "馬首搖殘月，鴉群起古城。發來經幾堠，村寺遠鐘聲。"]'),
('yuding-64','哭所知','李鹹用','唐','御定全唐诗','yuding','','[]','朝作青雲士，暮為玄夜人。風燈無定度，露薤亦逡巡。',48,'御定全唐詩/json/645.json','["朝作青雲士，暮為玄夜人。風燈無定度，露薤亦逡巡。", "乘馬驚新塚，書帷擺舊塵。只應從此去，何處福生民。"]'),
('yuding-65','分題雪霽望爐峰','李鹹用','唐','御定全唐诗','yuding','','[]','雪霽上庭除，爐峰勢轉孤。略無煙作帶，獨有影沈湖。',48,'御定全唐詩/json/645.json','["雪霽上庭除，爐峰勢轉孤。略無煙作帶，獨有影沈湖。", "冷觸歸鴻急，明凝落照俱。□□□□□，□□□□□。"]'),
('yuding-66','雪十二韻','李鹹用','唐','御定全唐诗','yuding','','[]','六出凝陰氣，同雲指上天。結時風乍急，集處霰長先。',144,'御定全唐詩/json/645.json','["六出凝陰氣，同雲指上天。結時風乍急，集處霰長先。", "草穗翹祥燕，陂樁葉白蓮。犬狂南陌上，竹醉小池前。", "樵徑花黏屨，漁舟玉帖舷。陣經暘谷薄，勢想朔方偏。", "樓面光搖錫，籬頭曉列錢。石苔青鹿臥，殿網素蛾穿。", "嘶馬應思塞，蹲烏似為燕。童癡為獸捏，僧愛用茶煎。", "念物希周穆，含毫愧惠連。吟闌餘興逸，還憶剡溪船。"]'),
('yuding-67','廬山','李鹹用','唐','御定全唐诗','yuding','','[]','非岳不言嶽，此山通嶽言。高人居亂世，幾處滿前軒。',240,'御定全唐詩/json/645.json','["非岳不言嶽，此山通嶽言。高人居亂世，幾處滿前軒。", "秀作神仙宅，靈為風雨根。餘陰鋪楚甸，一柱表吳門。", "靜得八公侶，雄臨九子尊。對猶青熨眼，到必冷凝魂。", "勢受重湖讓，形難七澤吞。黑岩藏晝電，紫霧泛朝暾。", "蓮墮甯唯華，玉焚堪小昆。倒松微發罅，飛瀑遠成痕。", "疊見雲容襯，棱收雪氣昏。裁詩曾困謝，作賦偶無孫。", "流礙星光撇，驚沖雁陣翻。峰奇寒倚劍，泉曲旋如盆。", "草短分雛雉，林明露擲猿。秋楓紅葉散，春石谷雷奔。", "月好虎溪路，煙深栗裏源。醉吟長易醒，夢去亦銷煩。", "有覺南方重，無疑厚地掀。輕揚聞舊俗，端用鎮元元。"]'),
('yuding-68','和吳處士題村叟壁','李鹹用','唐','御定全唐诗','yuding','','[]','因閱鄉居景，歸心寸火然。吾家依碧嶂，小檻枕清川。',240,'御定全唐詩/json/645.json','["因閱鄉居景，歸心寸火然。吾家依碧嶂，小檻枕清川。", "遠雨籠孤戍，斜陽隔斷煙。沙虛遺虎跡，水洑聚蛟涎。", "糲曲芟汀蓼，甘茶挈石泉。霜朝巡栗樹，風夜探漁船。", "戲日魚呈腹，翹灘鷺並肩。棋尋磐石淨，酒傍野花妍。", "器以鋤為利，家惟竹直錢。飯香同豆熟，湯暖摘松煎。", "睡島鳧藏足，攀藤狖凍拳。淺茅鳴鬥雉，曲枿嘯寒鳶。", "秋果楂梨澀，晨羞筍蕨鮮。衣蓑留冷閣，席草種閒田。", "椎髻擔鋪餉，龐眉識稔年。嚇鷹芻戴笠，驅犢筱充鞭。", "不重官于社，常尊食作天。穀深青靄蔽，峰迥白雲纏。", "每憶關魂夢，長誇表愛憐。覽君書壁句，誘我率成篇。"]'),
('yuding-69','謝友生遺端溪硯瓦','李鹹用','唐','御定全唐诗','yuding','','[]','尋常濡翰次，恨不到端溪。得自新知己，如逢舊解攜。',241,'御定全唐詩/json/645.json','["尋常濡翰次，恨不到端溪。得自新知己，如逢舊解攜。", "玩餘輕照乘，謝欲等懸黎。靜對勝凡客，閑窺憶好題。", "媧天補剩石，昆劍切來泥。著指痕猶濕，停旬水未低。", "呵雲潤柱礎，筆彩飲虹霓。鵒眼工諳謬，羊肝士乍刲。", "連澌光比鏡，囚墨膩於cD。書信成池黑，吟須到日西。", "正誇憂盜竊，將隱怯攀躋。捧受同交印，矜持過秉珪。", "草顛終近旭，懶癖必無嵇。用合緣鸚鵡，珍應負會稽。", "貞姿還落落，寒韻落淒淒。風月情相半，煙花思豈迷。", "宜從方袋挈，枉把短行批。淺小金為鬥，泓澄玉作堤。", "遇人依我惜，想爾與天齊。□□□□□，行時只獨齎。"]'),
('yuding-70','和殷衙推春霖即事','李咸用','唐','御定全唐诗','yuding','','[]','東風吹暖雨，潤下不能休。古道雲橫白，移時客共愁。',240,'御定全唐詩/json/645.json','["東風吹暖雨，潤下不能休。古道雲橫白，移時客共愁。", "綠沈莎似藻，紅泛葉為舟。忽起江湖興，疑鄰畎澮流。", "此時無勝會，何處滯奇遊。陣急如酣戰，點粗成亂漚。", "竹因添灑落，松得長颼飀。花慘閒庭晚，蘭深曲徑幽。", "絲牽汀鳥足，線掛嶽猿頭。天地昏同醉，寰區浩欲浮。", "柳眉低帶泣，蒲劍銳初抽。石燕翻空重，蟲羅綴滴稠。", "荷傾蛟淚盡，岩拆電鞭收。豈直望堯喜，卻懷微禹憂。", "樹滋堪采菌，磯沒懶垂鉤。腥覺聞龍氣，寒宜擁豹裘。", "名膏那作沴，思稔必通侯。蚌鷸徒喧競，笙歌罷獻酬。", "山川藏秀媚，草木逞調柔。極目非吾意，行吟獨下樓。"]'),
('yuding-0','題陳將軍別墅','李鹹用','唐','御定全唐诗','yuding','','[]','明王獵士猶疏在，岩谷安居最有才。高虎壯言知鬼伏，',40,'御定全唐詩/json/646.json','["明王獵士猶疏在，岩谷安居最有才。高虎壯言知鬼伏，", "不獨春光堪醉客，庭除長見好花開。"]'),
('yuding-1','湘浦有懷','李咸用','唐','御定全唐诗','yuding','','[]','鴻雁哀哀背朔方，餘霞倒影畫瀟湘。長汀細草愁春浪，',40,'御定全唐詩/json/646.json','["鴻雁哀哀背朔方，餘霞倒影畫瀟湘。長汀細草愁春浪，", "儂家本是持竿者，為愛明時入帝鄉。"]'),
('yuding-2','題陳處士山居','李鹹用','唐','御定全唐诗','yuding','','[]','蓮繞閑亭柳繞池，蟬吟暮色一枝枝。未逢皇澤搜遺逸，',40,'御定全唐詩/json/646.json','["蓮繞閑亭柳繞池，蟬吟暮色一枝枝。未逢皇澤搜遺逸，", "樵童牧豎勞相問，岩穴從來出帝師。"]'),
('yuding-3','和蔣進士秋日','李鹹用','唐','御定全唐诗','yuding','','[]','晚雨霏微思杪秋，不堪才子尚羈游。塵隨別騎東西急，',40,'御定全唐詩/json/646.json','["晚雨霏微思杪秋，不堪才子尚羈游。塵隨別騎東西急，", "男兒但得功名立，縱是深恩亦易酬。"]'),
('yuding-4','陳正字山居','李鹹用','唐','御定全唐诗','yuding','','[]','一葉閑飛斜照裏，江南仲蔚在蓬蒿。天衢雲險駑駘蹇，',40,'御定全唐詩/json/646.json','["一葉閑飛斜照裏，江南仲蔚在蓬蒿。天衢雲險駑駘蹇，", "此中即是神仙地，引手何妨一釣鼇。"]'),
('yuding-5','與劉三禮陳孝廉言志','李鹹用','唐','御定全唐诗','yuding','','[]','真宰無私造化均，年年分散月中春。皆期早躡青雲路，',40,'御定全唐詩/json/646.json','["真宰無私造化均，年年分散月中春。皆期早躡青雲路，", "大須審固穿楊箭，莫遣參差鬢雪新。"]'),
('yuding-6','秋日送嚴湘侍禦歸京','李鹹用','唐','御定全唐诗','yuding','','[]','蟾影珪圓湖始波，楚人相別恨偏多。知君有路升霄漢，',40,'御定全唐詩/json/646.json','["蟾影珪圓湖始波，楚人相別恨偏多。知君有路升霄漢，", "誰聽甯戚敲牛角，月落星稀一曲歌。"]'),
('yuding-7','題王處士山居','李鹹用','唐','御定全唐诗','yuding','','[]','雲木沉沉夏亦寒，此中幽隱幾經年。無多別業供王稅，',40,'御定全唐詩/json/646.json','["雲木沉沉夏亦寒，此中幽隱幾經年。無多別業供王稅，", "干戈蝟起能高臥，只個逍遙是謫仙。"]'),
('yuding-8','謝所知','李鹹用','唐','御定全唐诗','yuding','','[]','狂歌狂舞慰風塵，心下多端亦懶言。早是亂離輕歲月，',40,'御定全唐詩/json/646.json','["狂歌狂舞慰風塵，心下多端亦懶言。早是亂離輕歲月，", "卻愧此時叨厚遇，他年何以報深恩。"]'),
('yuding-9','秋望','李鹹用','唐','御定全唐诗','yuding','','[]','雲陰慘澹柳陰稀，遊子天涯一望時。風閃雁行疏又密，',40,'御定全唐詩/json/646.json','["雲陰慘澹柳陰稀，遊子天涯一望時。風閃雁行疏又密，", "未達誰能多歎息，塵埃爭損得男兒。"]'),
('yuding-10','送譚孝廉赴舉','李鹹用','唐','御定全唐诗','yuding','','[]','鼓鼙聲裏尋詩禮，戈戟林間入鎬京。好事盡從難處得，',40,'御定全唐詩/json/646.json','["鼓鼙聲裏尋詩禮，戈戟林間入鎬京。好事盡從難處得，", "吾道近來稀後進，善開金口答公卿。"]'),
('yuding-11','途中逢友人','李咸用','唐','御定全唐诗','yuding','','[]','大道將窮阮籍哀，紅塵深翳步遲回。皇天有意自寒暑，',40,'御定全唐詩/json/646.json','["大道將窮阮籍哀，紅塵深翳步遲回。皇天有意自寒暑，", "相逢且快眼前事，莫厭狂歌酒百杯。"]'),
('yuding-12','和人湘中作','李鹹用','唐','御定全唐诗','yuding','','[]','湘川湘岸兩荒涼，孤雁號空動旅腸。一棹寒波思範蠡，',40,'御定全唐詩/json/646.json','["湘川湘岸兩荒涼，孤雁號空動旅腸。一棹寒波思範蠡，", "不及東流趨廣漢，臣心日夜與天長。"]'),
('yuding-13','贈陳望堯','李鹹用','唐','御定全唐诗','yuding','','[]','若說精通事藝長，詞人爭及孝廉郎。秋螢短焰難盈案，',40,'御定全唐詩/json/646.json','["若說精通事藝長，詞人爭及孝廉郎。秋螢短焰難盈案，", "明時公道還堪信，莫遣錐鋒久在囊。"]'),
('yuding-14','宿漁家','李鹹用','唐','御定全唐诗','yuding','','[]','促杼聲繁螢影多，江邊秋興獨難過。雲遮月桂幾枝恨，',40,'御定全唐詩/json/646.json','["促杼聲繁螢影多，江邊秋興獨難過。雲遮月桂幾枝恨，", "陶家壁上精靈物，風雨未來終是梭。"]'),
('yuding-15','旅館秋夕','李鹹用','唐','御定全唐诗','yuding','','[]','牢落生涯在水鄉，只思歸去泛滄浪。秋風螢影隨高柳，',40,'御定全唐詩/json/646.json','["牢落生涯在水鄉，只思歸去泛滄浪。秋風螢影隨高柳，", "若教名路無知己，匹馬塵中是自忙。"]'),
('yuding-16','悼範攄處士','李鹹用','唐','御定全唐诗','yuding','','[]','家在五雲溪畔住，身遊巫峽作閒人。安車未至柴關外，',40,'御定全唐詩/json/646.json','["家在五雲溪畔住，身遊巫峽作閒人。安車未至柴關外，", "到頭積善成何事，天地茫茫秋又春。"]'),
('yuding-17','送人','李鹹用','唐','御定全唐诗','yuding','','[]','一軸煙花滿口香，諸侯相見肯相忘。未聞珪璧為人棄，',40,'御定全唐詩/json/646.json','["一軸煙花滿口香，諸侯相見肯相忘。未聞珪璧為人棄，", "眼前多少難甘事，自古男兒當自強。"]'),
('yuding-18','春暮途中','李咸用','唐','御定全唐诗','yuding','','[]','細雨如塵散暖空，數峰春色在雲中。須知觸目皆成恨，',40,'御定全唐詩/json/646.json','["細雨如塵散暖空，數峰春色在雲中。須知觸目皆成恨，", "誰能會得乾坤意，九土枯榮自不同。"]'),
('yuding-19','題陳正字林亭','李鹹用','唐','御定全唐诗','yuding','','[]','曉煙輕翠拂簾飛，黃葉飄零弄所思。正是低摧吾道日，',40,'御定全唐詩/json/646.json','["曉煙輕翠拂簾飛，黃葉飄零弄所思。正是低摧吾道日，", "賴有平原憐賤子，滿亭山色惜吟詩。"]'),
('yuding-20','送從兄入京','李咸用','唐','御定全唐诗','yuding','','[]','柳轉春心梅豔香，相看江上恨何長。多情流水引歸思，',40,'御定全唐詩/json/646.json','["柳轉春心梅豔香，相看江上恨何長。多情流水引歸思，", "雲帆高掛一揮手，目送煙霄雁斷行。"]'),
('yuding-21','秋夕書懷寄所知','李鹹用','唐','御定全唐诗','yuding','','[]','秋螢一點雨中飛，獨立黃昏思所知。三島路遙身汩沒，',40,'御定全唐詩/json/646.json','["秋螢一點雨中飛，獨立黃昏思所知。三島路遙身汩沒，", "不向故人言此事，異鄉誰更念棲遲。"]'),
('yuding-22','酬進士秦顒若','李鹹用','唐','御定全唐诗','yuding','','[]','鶯默平林燕別軒，相逢相笑話生前。低飛旅恨看霜葉，',40,'御定全唐詩/json/646.json','["鶯默平林燕別軒，相逢相笑話生前。低飛旅恨看霜葉，", "何勞悵望風雷便，且混魚龍黷武年。"]'),
('yuding-23','山中夜坐寄故里友生','李鹹用','唐','御定全唐诗','yuding','','[]','輾轉簷前睡不成，一床山月竹風清。蟲聲促促催鄉夢，',40,'御定全唐詩/json/646.json','["輾轉簷前睡不成，一床山月竹風清。蟲聲促促催鄉夢，", "可憐任永真堅白，淨洗雙眸看太平。"]'),
('yuding-24','物情','李鹹用','唐','御定全唐诗','yuding','','[]','誰分萬類二儀間，稟性高卑各自然。野鶴不棲蔥蒨樹，',40,'御定全唐詩/json/646.json','["誰分萬類二儀間，稟性高卑各自然。野鶴不棲蔥蒨樹，", "成是敗非如賦命，更教何處認愚賢。"]'),
('yuding-25','金谷園','李咸用','唐','御定全唐诗','yuding','','[]','石家舊地聊登望，寵辱從茲信可驚。鳥度野花迷錦障，',40,'御定全唐詩/json/646.json','["石家舊地聊登望，寵辱從茲信可驚。鳥度野花迷錦障，", "多積黃金買刑戮，千秋成得綠珠名。"]'),
('yuding-26','投所知','李鹹用','唐','御定全唐诗','yuding','','[]','手欠東堂桂一枝，家書不敢便言歸。掛簷晚雨思山閣，',40,'御定全唐詩/json/646.json','["手欠東堂桂一枝，家書不敢便言歸。掛簷晚雨思山閣，", "誰能借與摶扶勢，萬里飄飄試一飛。"]'),
('yuding-27','贈友弟','李咸用','唐','御定全唐诗','yuding','','[]','螢焰燒心雪眼勞，未逢佳夢見三刀。他時詎有鹽梅味，',40,'御定全唐詩/json/646.json','["螢焰燒心雪眼勞，未逢佳夢見三刀。他時詎有鹽梅味，", "誰能終歲搖赬尾，唯唯洋洋向碧濤。"]'),
('yuding-28','春日喜逢鄉人劉松','李咸用','唐','御定全唐诗','yuding','','[]','故人不見五春風，異地相逢嶽影中。舊業久拋耕釣侶，',40,'御定全唐詩/json/646.json','["故人不見五春風，異地相逢嶽影中。舊業久拋耕釣侶，", "莫把少年愁過日，一尊須對夕陽空。"]'),
('yuding-29','夏日別余秀才','李咸用','唐','御定全唐诗','yuding','','[]','嶽麓雲深麥雨秋，滿傾杯酒對湘流。沙邊細柳牽行色，',40,'御定全唐詩/json/646.json','["嶽麓雲深麥雨秋，滿傾杯酒對湘流。沙邊細柳牽行色，", "鏡機沖漠非吾事，自要青雲識五侯。"]'),
('yuding-30','廬陵九日','李鹹用','唐','御定全唐诗','yuding','','[]','菊花山在碧江東，冷酒清吟興莫窮。四十三年秋裏過，',40,'御定全唐詩/json/646.json','["菊花山在碧江東，冷酒清吟興莫窮。四十三年秋裏過，", "竟日開門無客至，笛聲迢遞夕陽中。"]'),
('yuding-31','和人游東林','李鹹用','唐','御定全唐诗','yuding','','[]','一從張野臥雲林，勝概誰人更解尋。黃鳥不能言往事，',40,'御定全唐詩/json/646.json','["一從張野臥雲林，勝概誰人更解尋。黃鳥不能言往事，", "始欲共君重悵望，紫霄峰外日沉沉。"]'),
('yuding-32','和彭進士秋日游靖居山寺','李鹹用','唐','御定全唐诗','yuding','','[]','秋山入望已無塵，況得閒遊謝事頻。問著盡能言祖祖，',40,'御定全唐詩/json/646.json','["秋山入望已無塵，況得閒遊謝事頻。問著盡能言祖祖，", "自笑未曾同逸步，終非宗炳社中人。"]'),
('yuding-33','和彭進士感懷','李咸用','唐','御定全唐诗','yuding','','[]','人生誰肯便甘休，遇酒逢花且共遊。若向雲衢陪驥尾，',40,'御定全唐詩/json/646.json','["人生誰肯便甘休，遇酒逢花且共遊。若向雲衢陪驥尾，", "四海英雄多獨斷，不知何者是長籌。"]'),
('yuding-34','寄題從兄坤載村居','李鹹用','唐','御定全唐诗','yuding','','[]','鄰並無非樵釣者，莊生物論宛然齊。雨中寒樹愁鴟立，',40,'御定全唐詩/json/646.json','["鄰並無非樵釣者，莊生物論宛然齊。雨中寒樹愁鴟立，", "覆巢破卵方堪懼，取次梧桐鳳且棲。"]'),
('yuding-35','送黃賓於赴舉','李鹹用','唐','御定全唐诗','yuding','','[]','秋風昨夜滿瀟湘，衰柳殘蟬思客腸。早是亂來無勝事，',40,'御定全唐詩/json/646.json','["秋風昨夜滿瀟湘，衰柳殘蟬思客腸。早是亂來無勝事，", "漁父不須探去意，一枝春褭月中央。"]'),
('yuding-36','冬日喜逢吳價','李鹹用','唐','御定全唐诗','yuding','','[]','垂楊煙薄井梧空，千里遊人駐斷蓬。志意不因多事改，',40,'御定全唐詩/json/646.json','["垂楊煙薄井梧空，千里遊人駐斷蓬。志意不因多事改，", "窮達他年如賦命，且陶真性一杯中。"]'),
('yuding-37','題劉處士居','李鹹用','唐','御定全唐诗','yuding','','[]','壓破嵐光半畝餘，竹軒蘭砌共清虛。泉經小檻聲長急，',40,'御定全唐詩/json/646.json','["壓破嵐光半畝餘，竹軒蘭砌共清虛。泉經小檻聲長急，", "干戈謾道因天意，渭水高人自釣魚。"]'),
('yuding-38','送李尊師歸臨川','李鹹用','唐','御定全唐诗','yuding','','[]','蟠桃一別幾千春，謫下人間作至人。塵外煙霞吟不盡，',40,'御定全唐詩/json/646.json','["蟠桃一別幾千春，謫下人間作至人。塵外煙霞吟不盡，", "辭我麻姑山畔去，蔡經蹤跡必相親。"]'),
('yuding-39','投知','李鹹用','唐','御定全唐诗','yuding','','[]','西望長安路幾千，遲回不為別家難。酌量才地心雖動，',40,'御定全唐詩/json/646.json','["西望長安路幾千，遲回不為別家難。酌量才地心雖動，", "嘶風重訴牽鹽恥，伯樂何妨轉眼看。"]'),
('yuding-40','吳處士寄香兼勸入道','李咸用','唐','御定全唐诗','yuding','','[]','謝寄精專一撚香，勸予朝禮仕虛皇。須知十極皆臣妾，',40,'御定全唐詩/json/646.json','["謝寄精專一撚香，勸予朝禮仕虛皇。須知十極皆臣妾，", "但居平易俟天命，便是長生不死鄉。"]'),
('yuding-41','草蟲','李鹹用','唐','御定全唐诗','yuding','','[]','如繰如織暮eV々，應節催年使我愁。行客語停孤店月，',41,'御定全唐詩/json/646.json','["如繰如織暮eV々，應節催年使我愁。行客語停孤店月，", "須付畫堂蘭燭畔，歌懷醉耳兩悠悠。"]'),
('yuding-42','詠柳','李鹹用','唐','御定全唐诗','yuding','','[]','日近煙饒還有意，東垣西掖幾千株。牽仍別恨知難盡，',40,'御定全唐詩/json/646.json','["日近煙饒還有意，東垣西掖幾千株。牽仍別恨知難盡，", "天應繡出繁華景，處處茸絲惹路衢。"]'),
('yuding-43','寄所知','李咸用','唐','御定全唐诗','yuding','','[]','曾將俎豆為兒戲，爭奈干戈阻素心。遁去不同秦客逐，',40,'御定全唐詩/json/646.json','["曾將俎豆為兒戲，爭奈干戈阻素心。遁去不同秦客逐，", "從道趣時身計拙，如非所好肯開襟。"]'),
('yuding-44','雪','李鹹用','唐','御定全唐诗','yuding','','[]','上帝無私意甚微，欲教霖雨更光輝。也知出處花相似，',40,'御定全唐詩/json/646.json','["上帝無私意甚微，欲教霖雨更光輝。也知出處花相似，", "高樓四望吟魂斂，卻憶明皇月殿歸。"]'),
('yuding-45','緋桃花','李鹹用','唐','御定全唐诗','yuding','','[]','茫茫天意為誰留，深染夭桃備勝遊。未醉已知醒後憶，',40,'御定全唐詩/json/646.json','["茫茫天意為誰留，深染夭桃備勝遊。未醉已知醒後憶，", "何事梨花空似雪，也稱春色是悠悠。"]'),
('yuding-46','同友人秋日登庾樓','李咸用','唐','御定全唐诗','yuding','','[]','蘭摧菊暗不勝秋，倚著高樓思莫收。六代風光無問處，',40,'御定全唐詩/json/646.json','["蘭摧菊暗不勝秋，倚著高樓思莫收。六代風光無問處，", "欲學仲宣知是否，臂弓腰劍逐時流。"]'),
('yuding-47','和人詠雪','李鹹用','唐','御定全唐诗','yuding','','[]','輕輕玉疊向風加，襟袖誰能認六葩。高岫人迷千尺布，',40,'御定全唐詩/json/646.json','["輕輕玉疊向風加，襟袖誰能認六葩。高岫人迷千尺布，", "公子樽前流遠思，不知何處客程賒。"]'),
('yuding-48','和友人喜相遇十首','李鹹用','唐','御定全唐诗','yuding','','[]','為儒自愧已多年，文賦歌詩路不專。肯信披沙難見寶，',400,'御定全唐詩/json/646.json','["為儒自愧已多年，文賦歌詩路不專。肯信披沙難見寶，", "且固初心希一試，箭穿正鵠豈無緣。", "揣情摩意已無功，只把篇章助國風。宋玉謾誇雲雨會，", "難世好居郊野地，出門常喜與人同。", "惠子休驚學五車，沛公方起斬長蛇。六雄互欲吞諸國，", "人生心口宜相副，莫使堯階草勢斜。", "不傍江煙訪所思，更應無處展愁眉。數杯竹閣花殘酒，", "非窮非達非高尚，冷笑行藏只獨知。", "閑吟閑坐道相應，遠想南華亦自矜。拋擲家鄉輕似夢，", "唯仗十篇金玉韻，此中高旨莫階升。", "已向丘門老此軀，可堪空作小人儒。吟中景象千般有，", "短衣甯倦重修謁，誰識高陽舊酒徒。", "松桂寒多眾木分，輕浮如葉自紛紜。韶咸古曲教誰愛，", "相逢莫厭杯中酒，同醉同醒只有君。", "還淳反樸已難期，依德依仁敢暫違。寡欲自應剛正立，", "年紀少他蘧伯玉，幸因多難早知非。", "麻衣未識帝城塵，四十為儒是病身。有恨不關銜國恥，", "一種愛閑閑不得，混時行止卻應真。", "任說天長海影沈，友朋情比未為深。唯應樂處無虛日，", "他年有要玄珠者，赤水縈紆試一尋。"]'),
('yuding-49','依韻修睦上人山居十首','李鹹用','唐','御定全唐诗','yuding','','[]','生身便在亂離間，遇柳尋花作麼看。老去轉諳無是事，',400,'御定全唐詩/json/646.json','["生身便在亂離間，遇柳尋花作麼看。老去轉諳無是事，", "覆載我徒爭會得，大鵬飛尚未知寬。", "雲泉日日長松寺，絲管年年細柳營。靜躁殊途知自識，", "若見淨名居士語，逍遙全不讓莊生。", "莫言天道終難定，須信人心儘自輕。宣室三千雖有恨，", "不是不同明主意，懶將唇舌與齊烹。", "不論軒冕及漁樵，性與情違漸漸遙。季子禍從憐富貴，", "好學堯民偎舜日，短裁孤竹理雲韶。", "春風春雨一何頻，望極空江覺損神。鶯有來由重入谷，", "賴是水鄉樗櫟賤，滿爐紅焰且相親。", "三十年來要自觀，履春冰恐未為難。自于南國同埋劍，", "多慚幸住匡山下，偷得穠嵐坐臥看。", "畹蘭未必因香折，湖象多應為齒焚。兼濟直饒同巨楫，", "閑憑竹軒遊子過，替他愁見日西曛。", "何事深山嘯複歌，短弓長劍不如他。且圖青史垂名穩，", "人生若得逢堯舜，便是巢由亦易過。", "太玄太易小窗明，古義尋來醉複醒。西伯縱逢頭已白，", "此景得閒閑去得，人間無事不曾經。", "壯氣雖同德不同，項王何似王江東。鄉歌寂寂荒丘月，", "吟君十首山中作，方覺多端總是空。"]'),
('yuding-50','同友生春夜聞雨','李咸用','唐','御定全唐诗','yuding','','[]','春雨三更洗物華，亂和絲竹響豪家。滴繁知在長條柳，',40,'御定全唐詩/json/646.json','["春雨三更洗物華，亂和絲竹響豪家。滴繁知在長條柳，", "此時童叟渾無夢，為喜流膏潤穀芽。"]'),
('yuding-51','同友生題僧院杜鵑花','李鹹用','唐','御定全唐诗','yuding','','[]','若比眾芳應有在，難同上品是中春。牡丹為性疏南國，',40,'御定全唐詩/json/646.json','["若比眾芳應有在，難同上品是中春。牡丹為性疏南國，", "鶴林太盛今空地，莫放枝條出四鄰。"]'),
('yuding-52','春日題陳正字林亭','李咸用','唐','御定全唐诗','yuding','','[]','周回勝異似仙鄉，稍減愁人日月長。幕繞虛簷高岫色，',40,'御定全唐詩/json/646.json','["周回勝異似仙鄉，稍減愁人日月長。幕繞虛簷高岫色，", "南北近來多少事，數聲橫笛怨斜陽。"]'),
('yuding-53','送河南韋主簿歸京','李鹹用','唐','御定全唐诗','yuding','','[]','岩風愛日淚闌幹，去住情途各萬端。世亂敢言離別易，',40,'御定全唐詩/json/646.json','["岩風愛日淚闌幹，去住情途各萬端。世亂敢言離別易，", "見說滿朝親友在，肯教憔悴出長安。"]'),
('yuding-54','喻道','李鹹用','唐','御定全唐诗','yuding','','[]','漢武秦皇漫苦辛，那思俗骨本含真。不知流水潛催老，',40,'御定全唐詩/json/646.json','["漢武秦皇漫苦辛，那思俗骨本含真。不知流水潛催老，", "長生客待仙桃餌，月裏嬋娟笑煞人。"]'),
('yuding-55','山中','李鹹用','唐','御定全唐诗','yuding','','[]','一簇煙霞榮辱外，秋山留得傍簷楹。朝鐘暮鼓不到耳，',40,'御定全唐詩/json/646.json','["一簇煙霞榮辱外，秋山留得傍簷楹。朝鐘暮鼓不到耳，", "尋思阮籍當時意，豈是途窮泣利名。"]'),
('yuding-56','同玄昶上人觀山榴','李鹹用','唐','御定全唐诗','yuding','','[]','病隨支遁偶行行，正見榴花獨滿庭。',32,'御定全唐詩/json/646.json','["病隨支遁偶行行，正見榴花獨滿庭。", "瘦竹成林人不看，卻應著得強青青。"]'),
('yuding-57','別李將軍','李咸用','唐','御定全唐诗','yuding','','[]','一拜虯髭便受恩，宮門細柳五搖春。',32,'御定全唐詩/json/646.json','["一拜虯髭便受恩，宮門細柳五搖春。", "男兒自古多離別，懶對英雄淚滿巾。"]'),
('yuding-58','早雞','李鹹用','唐','御定全唐诗','yuding','','[]','錦翅朱冠驚四鄰，稻粱恩重職司晨。',32,'御定全唐詩/json/646.json','["錦翅朱冠驚四鄰，稻粱恩重職司晨。", "不知下土兵難戢，但報明時向國人。"]'),
('yuding-59','別友','李咸用','唐','御定全唐诗','yuding','','[]','北吹微微動旅情，不堪分手在平明。',32,'御定全唐詩/json/646.json','["北吹微微動旅情，不堪分手在平明。", "寒雞不待東方曙，喚起征人蹋月行。"]'),
('yuding-0','草檄答南蠻有詠','胡曾','唐','御定全唐诗','yuding','','[]','辭天出塞陣雲空，霧卷霞開萬里通。親受虎符安宇宙，',40,'御定全唐詩/json/647.json','["辭天出塞陣雲空，霧卷霞開萬里通。親受虎符安宇宙，", "為報南蠻須屏跡，不同蜀將武侯功。"]'),
('yuding-1','寒食都門作','胡曾','唐','御定全唐诗','yuding','','[]','二年寒食住京華，寓目春風萬萬家。金絡馬銜原上草，',40,'御定全唐詩/json/647.json','["二年寒食住京華，寓目春風萬萬家。金絡馬銜原上草，", "誰念都門兩行淚，故園寥落在長沙。"]'),
('yuding-2','薄命妾','胡曾','唐','御定全唐诗','yuding','','[]','阿嬌初失漢皇恩，舊賜羅衣亦罷熏。倚枕夜悲金屋雨，',40,'御定全唐詩/json/647.json','["阿嬌初失漢皇恩，舊賜羅衣亦罷熏。倚枕夜悲金屋雨，", "龍騎不巡時漸久，長門空掩綠苔紋。"]'),
('yuding-3','獨不見','胡曾','唐','御定全唐诗','yuding','','[]','玉關一自有氛埃，年少從軍竟未回。門外塵凝張樂榭，',40,'御定全唐詩/json/647.json','["玉關一自有氛埃，年少從軍竟未回。門外塵凝張樂榭，", "萬里寂寥音信絕，寸心爭忍不成灰。"]'),
('yuding-4','交河塞下曲','胡曾','唐','御定全唐诗','yuding','','[]','交河冰薄日遲遲，漢將思家感別離。塞北草生蘇武泣，',40,'御定全唐詩/json/647.json','["交河冰薄日遲遲，漢將思家感別離。塞北草生蘇武泣，", "何處疲兵心最苦，夕陽樓上笛聲時。"]'),
('yuding-5','車遙遙','胡曾','唐','御定全唐诗','yuding','','[]','自從車馬出門朝，便入空房守寂寥。玉枕夜殘魚信絕，',40,'御定全唐詩/json/647.json','["自從車馬出門朝，便入空房守寂寥。玉枕夜殘魚信絕，", "芳草又衰還不至，碧天霜冷轉無憀。"]'),
('yuding-6','早發潛水驛謁郎中員外','胡曾','唐','御定全唐诗','yuding','','[]','半床秋月一聲雞，萬里行人費馬蹄。青野霧銷凝晉洞，',40,'御定全唐詩/json/647.json','["半床秋月一聲雞，萬里行人費馬蹄。青野霧銷凝晉洞，", "已是大仙憐後進，不應來向武陵迷。"]'),
('yuding-7','贈漁者','胡曾','唐','御定全唐诗','yuding','','[]','不愧人間萬戶侯，子孫相繼老扁舟。往來南越諳鮫室，',40,'御定全唐詩/json/647.json','["不愧人間萬戶侯，子孫相繼老扁舟。往來南越諳鮫室，", "羨君獨得逃名趣，身外無機任白頭。"]'),
('yuding-8','自嶺下泛鷁到清遠峽作','胡曾','唐','御定全唐诗','yuding','','[]','乘船浮鷁下韶水，絕境方知在嶺南。薜荔雨餘山自黛，',40,'御定全唐詩/json/647.json','["乘船浮鷁下韶水，絕境方知在嶺南。薜荔雨餘山自黛，", "不為篋中書未獻，便來茲地結茅庵。"]'),
('yuding-9','題周瑜將軍廟','胡曾','唐','御定全唐诗','yuding','','[]','共說生前國步難，山川龍戰血漫漫。交鋒魏帝旌旗退，',40,'御定全唐詩/json/647.json','["共說生前國步難，山川龍戰血漫漫。交鋒魏帝旌旗退，", "功勳碑碣今何在，不得當時一字看。"]'),
('yuding-10','詠史詩：烏江','胡曾','唐','御定全唐诗','yuding','','[]','爭帝圖王勢已傾，八千兵散楚歌聲。',32,'御定全唐詩/json/647.json','["爭帝圖王勢已傾，八千兵散楚歌聲。", "烏江不是無船渡，恥向東吳再起兵。"]'),
('yuding-11','詠史詩：章華台','胡曾','唐','御定全唐诗','yuding','','[]','茫茫衰草沒章華，因笑靈王昔好奢。',32,'御定全唐詩/json/647.json','["茫茫衰草沒章華，因笑靈王昔好奢。", "台土未幹簫管絕，可憐身死野人家。"]'),
('yuding-12','詠史詩：細腰宮','胡曾','唐','御定全唐诗','yuding','','[]','楚王辛苦戰無功，國破城荒霸業空。',32,'御定全唐詩/json/647.json','["楚王辛苦戰無功，國破城荒霸業空。", "唯有青春花上露，至今猶泣細腰宮。"]'),
('yuding-13','詠史詩：沙苑','胡曾','唐','御定全唐诗','yuding','','[]','馮翊南邊宿霧開，行人一步一裴回。',32,'御定全唐詩/json/647.json','["馮翊南邊宿霧開，行人一步一裴回。", "誰知此地凋殘柳，儘是高歡敗後栽。"]'),
('yuding-14','詠史詩：石城','胡曾','唐','御定全唐诗','yuding','','[]','古郢雲開白雪樓，漢江還繞石城流。',32,'御定全唐詩/json/647.json','["古郢雲開白雪樓，漢江還繞石城流。", "何人知道寥天月，曾向朱門送莫愁。"]'),
('yuding-15','詠史詩：荊山','胡曾','唐','御定全唐诗','yuding','','[]','抱玉岩前桂葉稠，碧溪寒水至今流。',32,'御定全唐詩/json/647.json','["抱玉岩前桂葉稠，碧溪寒水至今流。", "空山落日猿聲叫，疑是荊人哭未休。"]'),
('yuding-16','詠史詩：陽臺','胡曾','唐','御定全唐诗','yuding','','[]','楚國城池颯已空，陽臺雲雨過無蹤。',32,'御定全唐詩/json/647.json','["楚國城池颯已空，陽臺雲雨過無蹤。", "何人更有襄王夢，寂寂巫山十二重。"]'),
('yuding-17','詠史詩：居延','胡曾','唐','御定全唐诗','yuding','','[]','漠漠平沙際碧天，問人雲此是居延。',32,'御定全唐詩/json/647.json','["漠漠平沙際碧天，問人雲此是居延。", "停驂一顧猶魂斷，蘇武爭禁十九年。"]'),
('yuding-18','詠史詩：沛宮','胡曾','唐','御定全唐诗','yuding','','[]','漢高辛苦事干戈，帝業興隆俊傑多。',32,'御定全唐詩/json/647.json','["漢高辛苦事干戈，帝業興隆俊傑多。", "猶恨四方無壯士，還鄉悲唱大風歌。"]'),
('yuding-19','詠史詩：金谷園','胡曾','唐','御定全唐诗','yuding','','[]','一自佳人墜玉樓，繁華東逐洛河流。',32,'御定全唐詩/json/647.json','["一自佳人墜玉樓，繁華東逐洛河流。", "唯餘金穀園中樹，殘日蟬聲送客愁。"]'),
('yuding-20','詠史詩：湘川','胡曾','唐','御定全唐诗','yuding','','[]','虞舜南捐萬乘君，靈妃揮涕竹成紋。',32,'御定全唐詩/json/647.json','["虞舜南捐萬乘君，靈妃揮涕竹成紋。", "不知精魄遊何處，落日瀟湘空白雲。"]'),
('yuding-21','詠史詩：夷門','胡曾','唐','御定全唐诗','yuding','','[]','六龍冉冉驟朝昏，魏國賢才杳不存。',32,'御定全唐詩/json/647.json','["六龍冉冉驟朝昏，魏國賢才杳不存。", "唯有侯嬴在時月，夜來空自照夷門。"]'),
('yuding-22','詠史詩：黃金台','胡曾','唐','御定全唐诗','yuding','','[]','北乘羸馬到燕然，此地何人複禮賢。',32,'御定全唐詩/json/647.json','["北乘羸馬到燕然，此地何人複禮賢。", "若問昭王無處所，黃金臺上草連天。"]'),
('yuding-23','詠史詩：夷陵','胡曾','唐','御定全唐诗','yuding','','[]','夷陵城闕倚朝雲，戰敗秦師縱火焚。',32,'御定全唐詩/json/647.json','["夷陵城闕倚朝雲，戰敗秦師縱火焚。", "何事三千珠履客，不能西禦武安君。"]'),
('yuding-24','詠史詩：漢江','胡曾','唐','御定全唐诗','yuding','','[]','漢江一帶碧流長，兩岸春風起綠楊。',32,'御定全唐詩/json/647.json','["漢江一帶碧流長，兩岸春風起綠楊。", "借問膠船何處沒，欲停蘭棹祀昭王。"]'),
('yuding-25','詠史詩：蒼梧','胡曾','唐','御定全唐诗','yuding','','[]','有虞龍駕不西還，空委簫韶洞壑間。',32,'御定全唐詩/json/647.json','["有虞龍駕不西還，空委簫韶洞壑間。", "無計得知陵寢處，愁雲長滿九疑山。"]'),
('yuding-26','詠史詩：陳宮','胡曾','唐','御定全唐诗','yuding','','[]','陳國機權未可涯，如何後主恣嬌奢。',32,'御定全唐詩/json/647.json','["陳國機權未可涯，如何後主恣嬌奢。", "不知即入宮中井，猶自聽吹玉樹花。"]'),
('yuding-27','詠史詩：南陽','胡曾','唐','御定全唐诗','yuding','','[]','世亂英雄百戰餘，孔明方此樂耕鋤。',32,'御定全唐詩/json/647.json','["世亂英雄百戰餘，孔明方此樂耕鋤。", "蜀王不自垂三顧，爭得先生出舊廬。"]'),
('yuding-28','詠史詩：即墨','胡曾','唐','御定全唐诗','yuding','','[]','即墨門開縱火牛，燕師營裏血波流。',32,'御定全唐詩/json/647.json','["即墨門開縱火牛，燕師營裏血波流。", "固存不得田單術，齊國尋成一土丘。"]'),
('yuding-29','詠史詩：渭濱','胡曾','唐','御定全唐诗','yuding','','[]','岸草青青渭水流，子牙曾此獨垂釣。',32,'御定全唐詩/json/647.json','["岸草青青渭水流，子牙曾此獨垂釣。", "當時未入非熊兆，幾向斜陽歎白頭。"]'),
('yuding-30','詠史詩：五湖','胡曾','唐','御定全唐诗','yuding','','[]','東上高山望五湖，雪濤煙浪起天隅。',32,'御定全唐詩/json/647.json','["東上高山望五湖，雪濤煙浪起天隅。", "不知範蠡乘舟後，更有功臣繼踵無。"]'),
('yuding-31','詠史詩：易水','胡曾','唐','御定全唐诗','yuding','','[]','一旦秦皇馬角生，燕丹歸北送荊卿。',32,'御定全唐詩/json/647.json','["一旦秦皇馬角生，燕丹歸北送荊卿。", "行人欲識無窮恨，聽取東流易水聲。"]'),
('yuding-32','詠史詩：長平','胡曾','唐','御定全唐诗','yuding','','[]','長平瓦震武安初，趙卒俄成戲鼎魚。',32,'御定全唐詩/json/647.json','["長平瓦震武安初，趙卒俄成戲鼎魚。", "四十萬人俱下世，元戎何用讀兵書。"]'),
('yuding-33','詠史詩：西園','胡曾','唐','御定全唐诗','yuding','','[]','月滿西園夜未央，金風不動鄴天涼。',32,'御定全唐詩/json/647.json','["月滿西園夜未央，金風不動鄴天涼。", "高情公子多秋興，更領詩人入醉鄉。"]'),
('yuding-34','詠史詩：長沙','胡曾','唐','御定全唐诗','yuding','','[]','江上南風起白蘋，長沙城郭異咸秦。',32,'御定全唐詩/json/647.json','["江上南風起白蘋，長沙城郭異咸秦。", "故鄉猶自嫌卑濕，何況當時賦鵩人。"]'),
('yuding-35','詠史詩：圯橋','胡曾','唐','御定全唐诗','yuding','','[]','廟算張良獨有餘，少年逃難下邳初。',32,'御定全唐詩/json/647.json','["廟算張良獨有餘，少年逃難下邳初。", "逡巡不進泥中履，爭得先生一卷書。"]'),
('yuding-36','詠史詩：銅雀台','胡曾','唐','御定全唐诗','yuding','','[]','魏武龍輿逐逝波，高臺空按望陵歌。',32,'御定全唐詩/json/647.json','["魏武龍輿逐逝波，高臺空按望陵歌。", "遏雲聲絕悲風起，翻向樽前泣翠娥。"]'),
('yuding-37','詠史詩：東晉','胡曾','唐','御定全唐诗','yuding','','[]','石頭城下浪崔嵬，風起聲疑出地雷。',32,'御定全唐詩/json/647.json','["石頭城下浪崔嵬，風起聲疑出地雷。", "何事苻堅太相小，欲投鞭策過江來。"]'),
('yuding-38','詠史詩：吳江','胡曾','唐','御定全唐诗','yuding','','[]','子胥今日委東流，吳國明朝亦古丘。',32,'御定全唐詩/json/647.json','["子胥今日委東流，吳國明朝亦古丘。", "大笑夫差諸將相，更無人解守蘇州。"]'),
('yuding-39','詠史詩：函谷關','胡曾','唐','御定全唐诗','yuding','','[]','寂寂函關鎖未開，田文車馬出秦來。',32,'御定全唐詩/json/647.json','["寂寂函關鎖未開，田文車馬出秦來。", "朱門不養三千客，誰為雞鳴得放回。"]'),
('yuding-40','詠史詩：武關','胡曾','唐','御定全唐诗','yuding','','[]','戰國相持竟不休，武關才掩楚王憂。',32,'御定全唐詩/json/647.json','["戰國相持竟不休，武關才掩楚王憂。", "出門若取靈均語，豈作咸陽一死囚。"]'),
('yuding-41','詠史詩：垓下','胡曾','唐','御定全唐诗','yuding','','[]','拔山力盡霸圖隳，倚劍空歌不逝騅。',32,'御定全唐詩/json/647.json','["拔山力盡霸圖隳，倚劍空歌不逝騅。", "明月滿營天似水，那堪回首別虞姬。"]'),
('yuding-42','詠史詩：郴縣','胡曾','唐','御定全唐诗','yuding','','[]','義帝南遷路入郴，國亡身死亂山深。',32,'御定全唐詩/json/647.json','["義帝南遷路入郴，國亡身死亂山深。", "不知埋恨窮泉後，幾度西陵片月沉。"]'),
('yuding-43','詠史詩：東海','胡曾','唐','御定全唐诗','yuding','','[]','東巡玉輦委泉台，徐福樓船尚未回。',32,'御定全唐詩/json/647.json','["東巡玉輦委泉台，徐福樓船尚未回。", "自是祖龍先下世，不關無路到蓬萊。"]'),
('yuding-44','詠史詩：故宜城','胡曾','唐','御定全唐诗','yuding','','[]','武安南伐勒秦兵，疏鑿功將夏禹並。',32,'御定全唐詩/json/647.json','["武安南伐勒秦兵，疏鑿功將夏禹並。", "誰謂長渠千載後，水流猶入故宜城。"]'),
('yuding-45','詠史詩：成都','胡曾','唐','御定全唐诗','yuding','','[]','杜宇曾為蜀帝王，化禽飛去舊城荒。',32,'御定全唐詩/json/647.json','["杜宇曾為蜀帝王，化禽飛去舊城荒。", "年年來叫桃花月，似向春風訴國亡。"]'),
('yuding-46','詠史詩：檀溪','胡曾','唐','御定全唐诗','yuding','','[]','三月襄陽綠草齊，王孫相引到檀溪。',32,'御定全唐詩/json/647.json','["三月襄陽綠草齊，王孫相引到檀溪。", "的盧何處埋龍骨，流水依前繞大堤。"]'),
('yuding-47','詠史詩：青塚','胡曾','唐','御定全唐诗','yuding','','[]','玉貌元期漢帝招，誰知西嫁怨天驕。',32,'御定全唐詩/json/647.json','["玉貌元期漢帝招，誰知西嫁怨天驕。", "至今青塚愁雲起，疑是佳人恨未銷。"]'),
('yuding-48','詠史詩：李陵台','胡曾','唐','御定全唐诗','yuding','','[]','北入單于萬里疆，五千兵敗滯窮荒。',32,'御定全唐詩/json/647.json','["北入單于萬里疆，五千兵敗滯窮荒。", "英雄不伏蠻夷死，更築高臺望故鄉。"]'),
('yuding-49','詠史詩：河梁','胡曾','唐','御定全唐诗','yuding','','[]','漢家英傑出皇都，攜手河梁話入胡。',32,'御定全唐詩/json/647.json','["漢家英傑出皇都，攜手河梁話入胡。", "不是子卿全大節，也應低首拜單于。"]'),
('yuding-50','詠史詩：軹道','胡曾','唐','御定全唐诗','yuding','','[]','漢祖西來秉白旄，子嬰宗廟委波濤。',32,'御定全唐詩/json/647.json','["漢祖西來秉白旄，子嬰宗廟委波濤。", "誰憐君有翻身術，解向秦宮殺趙高。"]'),
('yuding-51','詠史詩：漢宮','胡曾','唐','御定全唐诗','yuding','','[]','明妃遠嫁泣西風，玉箸雙垂出漢宮。',32,'御定全唐詩/json/647.json','["明妃遠嫁泣西風，玉箸雙垂出漢宮。", "何事將軍封萬戶，卻令紅粉為和戎。"]'),
('yuding-52','詠史詩：豫讓橋','胡曾','唐','御定全唐诗','yuding','','[]','豫讓酬恩歲已深，高名不朽到如今。',32,'御定全唐詩/json/647.json','["豫讓酬恩歲已深，高名不朽到如今。", "年年橋上行人過，誰有當時國士心。"]'),
