('yuding-153','詠史詩：潁川','胡曾','唐','御定全唐诗','yuding','','[]','古賢高尚不爭名，行止由來動杳冥。',32,'御定全唐詩/json/647.json','["古賢高尚不爭名，行止由來動杳冥。", "今日浪為千里客，看花慚上德星亭。"]'),
('yuding-154','詠史詩：江夏','胡曾','唐','御定全唐诗','yuding','','[]','黃祖才非長者儔，禰衡珠碎此江頭。',32,'御定全唐詩/json/647.json','["黃祖才非長者儔，禰衡珠碎此江頭。", "今來鸚鵡洲邊過，惟有無情碧水流。"]'),
('yuding-155','詠史詩：官渡','胡曾','唐','御定全唐诗','yuding','','[]','本初屈指定中華，官渡相持勒虎牙。',32,'御定全唐詩/json/647.json','["本初屈指定中華，官渡相持勒虎牙。", "若使許攸財用足，山河爭得屬曹家。"]'),
('yuding-156','詠史詩：灞岸','胡曾','唐','御定全唐诗','yuding','','[]','長安城外白雲秋，蕭索悲風灞水流。',32,'御定全唐詩/json/647.json','["長安城外白雲秋，蕭索悲風灞水流。", "因想漢朝離亂日，仲宣從此向荊州。"]'),
('yuding-157','詠史詩：濡須橋','胡曾','唐','御定全唐诗','yuding','','[]','徒向濡須欲受降，英雄才略獨無雙。',32,'御定全唐詩/json/647.json','["徒向濡須欲受降，英雄才略獨無雙。", "天心不與金陵便，高步何由得渡江。"]'),
('yuding-158','詠史詩：豫州','胡曾','唐','御定全唐诗','yuding','','[]','策馬行行到豫州，祖生寂寞水空流。',32,'御定全唐詩/json/647.json','["策馬行行到豫州，祖生寂寞水空流。", "當時更有三年壽，石勒尋為關下囚。"]'),
('yuding-159','詠史詩：八公山','胡曾','唐','御定全唐诗','yuding','','[]','苻堅舉國出西秦，東晉危如累卵晨。',32,'御定全唐詩/json/647.json','["苻堅舉國出西秦，東晉危如累卵晨。", "誰料此山諸草木，盡能排難化為人。"]'),
('yuding-160','詠史詩：下第','胡曾','唐','御定全唐诗','yuding','','[]','翰苑何時休嫁女，文昌早晚罷生兒。',32,'御定全唐詩/json/647.json','["翰苑何時休嫁女，文昌早晚罷生兒。", "上林新桂年年發，不許平人折一枝。"]'),
('yuding-161','詠史詩：贈薛濤','胡曾','唐','御定全唐诗','yuding','','[]','萬里橋邊女校書，枇杷花下閉門居。',32,'御定全唐詩/json/647.json','["萬里橋邊女校書，枇杷花下閉門居。", "掃眉才子知多少，管領春風總不如。"]'),
('yuding-0','採蓮','方幹','唐','御定全唐诗','yuding','','[]','採蓮女兒避殘熱，隔夜相期侵早發。指剝春蔥腕似雪，',40,'御定全唐詩/json/648.json','["採蓮女兒避殘熱，隔夜相期侵早發。指剝春蔥腕似雪，", "才到河灣分首去，散在花間不知處。"]'),
('yuding-1','寄李頻','方幹','唐','御定全唐诗','yuding','','[]','眾木又搖落，望群還不還。軒車在何處，雨雪滿前山。',48,'御定全唐詩/json/648.json','["眾木又搖落，望群還不還。軒車在何處，雨雪滿前山。", "思苦文星動，鄉遙釣渚閑。明年見名姓，唯我獨何顏。"]'),
('yuding-2','東溪別業寄吉州段郎中','方幹','唐','御定全唐诗','yuding','','[]','前山含遠翠，羅列在窗中。盡日人不到，一尊誰與同。',48,'御定全唐詩/json/648.json','["前山含遠翠，羅列在窗中。盡日人不到，一尊誰與同。", "涼隨蓮葉雨，暑避柳條風。豈分長岑寂，明時有至公。"]'),
('yuding-3','懷州客舍','方幹','唐','御定全唐诗','yuding','','[]','誤飲覃懷酒，誰知滯去程。朝昏太行色，坐臥沁河聲。',48,'御定全唐詩/json/648.json','["誤飲覃懷酒，誰知滯去程。朝昏太行色，坐臥沁河聲。", "白道穿秦甸，嚴鼙似戍城。鄰雞莫相促，遊子自晨征。"]'),
('yuding-4','中路寄喻鳧先輩','方幹','唐','御定全唐诗','yuding','','[]','求名如未遂，白首亦難歸。送我尊前酒，典君身上衣。',48,'御定全唐詩/json/648.json','["求名如未遂，白首亦難歸。送我尊前酒，典君身上衣。", "寒蕪隨楚盡，落葉渡淮稀。莫歎幹時晚，前心豈便非。"]'),
('yuding-5','送趙明府還北','方幹','唐','御定全唐诗','yuding','','[]','故園終不住，劍鶴在扁舟。盡室無餘俸，還家得白頭。',48,'御定全唐詩/json/648.json','["故園終不住，劍鶴在扁舟。盡室無餘俸，還家得白頭。", "鐘催吳岫曉，月繞渭河流。曾是棲安邑，恩期異日酬。"]'),
('yuding-6','過朱協律故山','方幹','唐','御定全唐诗','yuding','','[]','地下無餘恨，人間得盛名。殘篇續大雅，稚子托諸生。',48,'御定全唐詩/json/648.json','["地下無餘恨，人間得盛名。殘篇續大雅，稚子托諸生。", "度日山空暮，緣溪鶴自鳴。難收故交意，寒笛一聲聲。"]'),
('yuding-7','途中寄劉沆','方幹','唐','御定全唐诗','yuding','','[]','登車誤相遠，談笑亦何因。路入瀟湘樹，書隨巴蜀人。',48,'御定全唐詩/json/648.json','["登車誤相遠，談笑亦何因。路入瀟湘樹，書隨巴蜀人。", "斂衣寒犯雪，傾篋病看春。莫負髫年志，清朝作獻臣。"]'),
('yuding-8','送班主簿入謁荊南韋常侍','方幹','唐','御定全唐诗','yuding','','[]','束書成遠去，還計莫經春。倒篋唯求醉，登舟自笑貧。',48,'御定全唐詩/json/648.json','["束書成遠去，還計莫經春。倒篋唯求醉，登舟自笑貧。", "波移彭蠡月，樹沒漢陵人。試吏曾趨府，旌幢自可親。"]'),
('yuding-9','夏日登靈隱寺後峰','方幹','唐','御定全唐诗','yuding','','[]','絕頂無煩暑，登臨三伏中。深蘿難透日，喬木更含風。',48,'御定全唐詩/json/648.json','["絕頂無煩暑，登臨三伏中。深蘿難透日，喬木更含風。", "山疊雲霞際，川傾世界東。那知茲夕興，不與古人同。"]'),
('yuding-10','聽新蟬寄張晝','方幹','唐','御定全唐诗','yuding','','[]','細聲頻斷續，審聽亦難分。仿佛應移處，從容卻不聞。',48,'御定全唐詩/json/648.json','["細聲頻斷續，審聽亦難分。仿佛應移處，從容卻不聞。", "蘭棲朝咽露，樹隱暝吟雲。莫遣鄉愁起，吾懷只是君。"]'),
('yuding-11','送喻坦之下第還江東','方幹','唐','御定全唐诗','yuding','','[]','文戰偶未勝，無令移壯心。風塵辭帝裏，舟楫到家林。',48,'御定全唐詩/json/648.json','["文戰偶未勝，無令移壯心。風塵辭帝裏，舟楫到家林。", "過楚寒方盡，浮淮月正沈。持杯話來日，不聽洞庭砧。"]'),
('yuding-12','送姚舒下第游蜀','方幹','唐','御定全唐诗','yuding','','[]','蜀路何迢遞，憐君獨去遊。風煙連北虜，山水似東甌。',48,'御定全唐詩/json/648.json','["蜀路何迢遞，憐君獨去遊。風煙連北虜，山水似東甌。", "九折盤荒阪，重江繞漢州。臨邛一壺酒，能遣長卿愁。"]'),
('yuding-13','旅次錢塘','方幹','唐','御定全唐诗','yuding','','[]','此地似鄉國，堪為朝夕吟。雲藏吳相廟，樹引越山禽。',48,'御定全唐詩/json/648.json','["此地似鄉國，堪為朝夕吟。雲藏吳相廟，樹引越山禽。", "潮落海人散，鐘遲秋寺深。我來無舊識，誰見寂寥心。"]'),
('yuding-14','別喻鳧','方幹','唐','御定全唐诗','yuding','','[]','知心似古人，歲久分彌親。離別波濤闊，留連槐柳新。',48,'御定全唐詩/json/648.json','["知心似古人，歲久分彌親。離別波濤闊，留連槐柳新。", "蟆陵寒貰酒，漁浦夜垂綸。自此星居後，音書豈厭頻。"]'),
('yuding-15','送相裏燭','方幹','唐','御定全唐诗','yuding','','[]','相逢未作期，相送定何之。不得長年少，那堪遠別離。',48,'御定全唐詩/json/648.json','["相逢未作期，相送定何之。不得長年少，那堪遠別離。", "泛湖乘月早，踐雪過山遲。永望多時立，翻如在夢思。"]'),
('yuding-16','君不來','方幹','唐','御定全唐诗','yuding','','[]','閑花未零落，心緒已紛紛。久客無人見，新禽何處聞。',48,'御定全唐詩/json/648.json','["閑花未零落，心緒已紛紛。久客無人見，新禽何處聞。", "舟隨一水遠，路出萬山分。夜月生愁望，孤光必照君。"]'),
('yuding-17','將謁商州呂郎中，道出楚州，留獻章中丞','方幹','唐','御定全唐诗','yuding','','[]','江流盤複直，浮棹出家林。商洛路猶遠，山陽春已深。',48,'御定全唐詩/json/648.json','["江流盤複直，浮棹出家林。商洛路猶遠，山陽春已深。", "青雲應有望，白髮未相侵。才小知難薦，終勞許郭心。"]'),
('yuding-18','金州客舍','方幹','唐','御定全唐诗','yuding','','[]','卷箔群峰暮，蕭條未掩關。江流嶓塚雨，路入漢家山。',48,'御定全唐詩/json/648.json','["卷箔群峰暮，蕭條未掩關。江流嶓塚雨，路入漢家山。", "落葉欹眠後，孤砧倚望間。此情偏耐醉，難遣酒罍閑。"]'),
('yuding-19','途中逢孫輅因得李頻消息','方幹','唐','御定全唐诗','yuding','','[]','灞上寒仍在，柔條亦自新。山河雖度臘，雨雪未知春。',48,'御定全唐詩/json/648.json','["灞上寒仍在，柔條亦自新。山河雖度臘，雨雪未知春。", "正憶同袍者，堪逢共國人。銜杯益無語，與爾轉相親。"]'),
('yuding-20','送從兄郜','方幹','唐','御定全唐诗','yuding','','[]','道路本無限，又應何處逢。流年莫虛擲，華髮不相容。',48,'御定全唐詩/json/648.json','["道路本無限，又應何處逢。流年莫虛擲，華髮不相容。", "野渡波搖月，空城雨翳鐘。此心隨去馬，迢遞過千峰。"]'),
('yuding-21','送許溫','方幹','唐','御定全唐诗','yuding','','[]','壯歲分罙切，少年心正同。當聞千里去，難遣一尊空。',48,'御定全唐詩/json/648.json','["壯歲分罙切，少年心正同。當聞千里去，難遣一尊空。", "翳燭蒹葭雨，吹帆橘柚風。明年見親族，盡集在懷中。"]'),
('yuding-22','鏡中別業二首','方幹','唐','御定全唐诗','yuding','','[]','寒山壓鏡心，此處是家林。梁燕窺春醉，岩猿學夜吟。',96,'御定全唐詩/json/648.json','["寒山壓鏡心，此處是家林。梁燕窺春醉，岩猿學夜吟。", "雲連平地起，月向白波沈。猶自聞鐘角，棲身可在深。", "世人如不容，吾自縱天慵。落葉憑風掃，香粳倩水舂。", "花期連郭霧，雪夜隔湖鐘。身外無能事，頭宜白此峰。"]'),
('yuding-23','經周處士故居','方幹','唐','御定全唐诗','yuding','','[]','愁吟與獨行，何事不傷情。久立釣魚處，唯聞啼鳥聲。',48,'御定全唐詩/json/648.json','["愁吟與獨行，何事不傷情。久立釣魚處，唯聞啼鳥聲。", "山蔬和草嫩，海樹入籬生。吾在茲溪上，懷君恨不平。"]'),
('yuding-24','贈喻鳧','方幹','唐','御定全唐诗','yuding','','[]','所得非眾語，眾人那得知。才吟五字句，又白幾莖髭。',48,'御定全唐詩/json/648.json','["所得非眾語，眾人那得知。才吟五字句，又白幾莖髭。", "月閣欹眠夜，霜軒正坐時。沈思心更苦，恐作滿頭絲。"]'),
('yuding-25','早發洞庭','方幹','唐','御定全唐诗','yuding','','[]','長天接廣澤，二氣共含秋。舉目無平地，何心戀直鉤。',48,'御定全唐詩/json/648.json','["長天接廣澤，二氣共含秋。舉目無平地，何心戀直鉤。", "孤鐘鳴大岸，片月落中流。卻憶鴟夷子，當時此泛舟。"]'),
('yuding-26','貽錢塘縣路明府','方幹','唐','御定全唐诗','yuding','','[]','志業不得力，到今猶苦吟。吟成五字句，用破一生心。',48,'御定全唐詩/json/648.json','["志業不得力，到今猶苦吟。吟成五字句，用破一生心。", "世路屈聲遠，寒溪怨氣深。前賢多晚達，莫怕鬢霜侵。"]'),
('yuding-27','湖上言事寄長城喻明府','方幹','唐','御定全唐诗','yuding','','[]','吟霜與臥雲，此興亦甘貧。吹箭落翠羽，垂絲牽錦鱗。',48,'御定全唐詩/json/648.json','["吟霜與臥雲，此興亦甘貧。吹箭落翠羽，垂絲牽錦鱗。", "滿湖風撼月，半日雨藏春。卻笑縈簪組，勞心字遠人。"]'),
('yuding-28','涵碧亭','方幹','唐','御定全唐诗','yuding','','[]','高低竹雜松，積翠複留風。路極陰溪裏，寒生暑氣中。',48,'御定全唐詩/json/648.json','["高低竹雜松，積翠複留風。路極陰溪裏，寒生暑氣中。", "閑雲低覆草，片水靜涵空。方見洋源牧，心侔造化功。"]'),
('yuding-29','除夜','方幹','唐','御定全唐诗','yuding','','[]','永懷難自問，此夕眾愁興。曉韻侵春角，寒光隔歲燈。',48,'御定全唐詩/json/648.json','["永懷難自問，此夕眾愁興。曉韻侵春角，寒光隔歲燈。", "心燃一寸火，淚結兩行冰。煦育誠非遠，陽和又欲升。"]'),
('yuding-30','贈許牘山人','方幹','唐','御定全唐诗','yuding','','[]','才子醉更逸，一吟傾一觴。支頤忍有得，搖筆便成章。',48,'御定全唐詩/json/648.json','["才子醉更逸，一吟傾一觴。支頤忍有得，搖筆便成章。", "王粲實可重，禰衡爭不狂。何時應會面，夢裏是瀟湘。"]'),
('yuding-31','贈功成將','方幹','唐','御定全唐诗','yuding','','[]','定難在明略，何曾勞戰爭。飛書諭強寇，計日下重城。',48,'御定全唐詩/json/648.json','["定難在明略，何曾勞戰爭。飛書諭強寇，計日下重城。", "深雪移軍夜，寒笳出塞情。苦心殊易老，新發早年生。"]'),
('yuding-32','白艾原客','方幹','唐','御定全唐诗','yuding','','[]','原上桑柘瘦，再來還見貧。滄州幾年隱，白髮一莖新。',48,'御定全唐詩/json/648.json','["原上桑柘瘦，再來還見貧。滄州幾年隱，白髮一莖新。", "敗葉平空塹，殘陽滿近鄰。閑言說知己，半是學禪人。"]'),
('yuding-33','朔管','方幹','唐','御定全唐诗','yuding','','[]','寥寥落何處，一夜過胡天。送苦秋風外，吹愁白髮邊。',48,'御定全唐詩/json/648.json','["寥寥落何處，一夜過胡天。送苦秋風外，吹愁白髮邊。", "望鄉皆下淚，久戍盡休眠。寂寞空沙曉，開眸片月懸。"]'),
('yuding-34','憶故山','方幹','唐','御定全唐诗','yuding','','[]','舊山長繫念，終日臥邊亭。道路知已遠，夢魂空再經。',48,'御定全唐詩/json/648.json','["舊山長繫念，終日臥邊亭。道路知已遠，夢魂空再經。", "秋泉涼好引，乳鶴靜宜聽。獨上高樓望，蓬身且未寧。"]'),
('yuding-35','冬夜泊僧舍','方幹','唐','御定全唐诗','yuding','','[]','江東寒近臘，野寺水天昏。無酒能宵夜，隨僧早閉門。',48,'御定全唐詩/json/648.json','["江東寒近臘，野寺水天昏。無酒能宵夜，隨僧早閉門。", "照牆燈焰細，著瓦雨聲繁。漂泊仍千里，清吟欲斷魂。"]'),
('yuding-36','新秋獨夜寄戴叔倫','方幹','唐','御定全唐诗','yuding','','[]','遙夜獨不臥，寂寥庭戶中。河明五陵上，月滿九門東。',48,'御定全唐詩/json/648.json','["遙夜獨不臥，寂寥庭戶中。河明五陵上，月滿九門東。", "萬里親朋散，故園滄海空。歸懷正南望，此夕起秋風。"]'),
('yuding-37','送沛縣司馬丞之任','方幹','唐','御定全唐诗','yuding','','[]','舉酒一相勸，逢春聊盡歡。羈游故交少，遠別後期難。',48,'御定全唐詩/json/648.json','["舉酒一相勸，逢春聊盡歡。羈游故交少，遠別後期難。", "路上野花發，雨中青草寒。悠悠兩都夢，小沛與長安。"]'),
('yuding-38','送盧評事東歸','方幹','唐','御定全唐诗','yuding','','[]','萬里楊柳色，出關隨故人。輕煙覆流水，落日照行塵。',48,'御定全唐詩/json/648.json','["萬里楊柳色，出關隨故人。輕煙覆流水，落日照行塵。", "積夢江湖闊，憶家兄弟貧。裴回灞亭上，不語共傷春。"]'),
('yuding-39','清明日送鄧芮還鄉','方幹','唐','御定全唐诗','yuding','','[]','鐘鼓喧離室，車徒促夜裝。曉榆新變火，輕柳暗飛霜。',48,'御定全唐詩/json/648.json','["鐘鼓喧離室，車徒促夜裝。曉榆新變火，輕柳暗飛霜。", "轉鏡看華髮，傳杯話故鄉。每嫌兒女淚，今日自沾裳。"]'),
('yuding-0','送崔拾遺出使江東','方幹','唐','御定全唐诗','yuding','','[]','九門思諫諍，萬里采風謠。關外逢秋月，天涯過晚潮。',48,'御定全唐詩/json/649.json','["九門思諫諍，萬里采風謠。關外逢秋月，天涯過晚潮。", "雁飛雲杳杳，木落浦蕭蕭。空怨他鄉別，回舟暮寂寥。"]'),
('yuding-1','重陽日送洛陽李丞之任','方幹','唐','御定全唐诗','yuding','','[]','為文通絕境，從宦及良辰。洛下知名早，腰邊結綬新。',48,'御定全唐詩/json/649.json','["為文通絕境，從宦及良辰。洛下知名早，腰邊結綬新。", "且傾浮菊酒，聊拂染衣塵。獨恨滄州侶，愁來別故人。"]'),
('yuding-2','江州送李侍禦歸東洛','方幹','唐','御定全唐诗','yuding','','[]','獨乘驄馬去，不並旅人還。中外名卿貴，田園高步閑。',48,'御定全唐詩/json/649.json','["獨乘驄馬去，不並旅人還。中外名卿貴，田園高步閑。", "暮春經楚縣，新月上淮山。道路空瞻望，軒車不敢攀。"]'),
('yuding-3','送郭太祝歸江東','方幹','唐','御定全唐诗','yuding','','[]','鄉人去欲盡，北雁又南飛。京洛風塵久，江淮音信稀。',48,'御定全唐詩/json/649.json','["鄉人去欲盡，北雁又南飛。京洛風塵久，江淮音信稀。", "舊山知獨往，一醉莫相違。未得解羈旅，無勞問是非。"]'),
('yuding-4','送李恬及第後還貝州','方幹','唐','御定全唐诗','yuding','','[]','成名年少日，就業聖人書。擢桂誰相比，籝金已不如。',48,'御定全唐詩/json/649.json','["成名年少日，就業聖人書。擢桂誰相比，籝金已不如。", "東城送歸客，秋日待征車。若到清潭畔，儒風變裏閭。"]'),
('yuding-5','收兩京後還上都兼訪一二親故','方幹','唐','御定全唐诗','yuding','','[]','離堂千里客，歸騎五陵人。路轉函關晚，煙開上苑新。',48,'御定全唐詩/json/649.json','["離堂千里客，歸騎五陵人。路轉函關晚，煙開上苑新。", "天涯將野服，闕下見鄉親。問得存亡事，裁詩寄海濱。"]'),
('yuding-6','送汶上王明府之任','方幹','唐','御定全唐诗','yuding','','[]','何時到故鄉，歸去佩銅章。親友移家盡，閭閻百戰傷。',48,'御定全唐詩/json/649.json','["何時到故鄉，歸去佩銅章。親友移家盡，閭閻百戰傷。", "背關餘草木，出塞足風霜。遺老應相賀，知君不下堂。"]'),
('yuding-7','湖南使院遣情送江夏賀侍郎','方幹','唐','御定全唐诗','yuding','','[]','雲雨一消散，悠悠關複河。俱從泛舟役，遂隔洞庭波。',48,'御定全唐詩/json/649.json','["雲雨一消散，悠悠關複河。俱從泛舟役，遂隔洞庭波。", "楚水去不盡，秋風今更過。無由得相見，卻恨寄書多。"]'),
('yuding-8','過申州作','方幹','唐','御定全唐诗','yuding','','[]','萬人曾死戰，幾戶免刀兵。井邑初安堵，兒童未長成。',48,'御定全唐詩/json/649.json','["萬人曾死戰，幾戶免刀兵。井邑初安堵，兒童未長成。", "涼風吹古木，野火燒殘營。寥落千餘裏，山高水複清。"]'),
('yuding-9','汝南過訪田評事','方幹','唐','御定全唐诗','yuding','','[]','移家近漢陰，不復問華簪。買酒宜城遠，燒田夢澤深。',48,'御定全唐詩/json/649.json','["移家近漢陰，不復問華簪。買酒宜城遠，燒田夢澤深。", "暮山逢鳥入，寒水見魚沈。與物皆無累，終年愜本心。"]'),
('yuding-10','送道上人游方','方幹','唐','御定全唐诗','yuding','','[]','律儀通外學，詩思入玄關。煙景隨人別，風姿與物閑。',48,'御定全唐詩/json/649.json','["律儀通外學，詩思入玄關。煙景隨人別，風姿與物閑。", "貫花留靜室，咒水度空山。誰識浮雲意，悠悠天地間。"]'),
('yuding-11','送饒州王司法之任兼寄朱處士','方幹','唐','御定全唐诗','yuding','','[]','莫辭還作吏，且喜速回車。留醉悲殘歲，含情寄遠書。',48,'御定全唐詩/json/649.json','["莫辭還作吏，且喜速回車。留醉悲殘歲，含情寄遠書。", "共看衰老近，轉覺宦名虛。遙想清溪畔，幽人得自如。"]'),
('yuding-12','詹碏山居','方幹','唐','御定全唐诗','yuding','','[]','愛此棲心靜，風塵路已賒。十餘莖野竹，一兩樹山花。',48,'御定全唐詩/json/649.json','["愛此棲心靜，風塵路已賒。十餘莖野竹，一兩樹山花。", "繞石開泉細，穿羅引徑斜。無人會幽意，來往在煙霞。"]'),
('yuding-13','曉角','方幹','唐','御定全唐诗','yuding','','[]','畫角吹殘月，寒聲發戍樓。立霜嘶馬怨，攢磧泣兵愁。',48,'御定全唐詩/json/649.json','["畫角吹殘月，寒聲發戍樓。立霜嘶馬怨，攢磧泣兵愁。", "燕雁鳴雲畔，胡風冷草頭。罷聞三會後，天迥曉星流。"]'),
('yuding-14','冬日','方幹','唐','御定全唐诗','yuding','','[]','燒火掩關坐，窮居客訪稀。凍雲愁暮色，寒日淡斜暉。',48,'御定全唐詩/json/649.json','["燒火掩關坐，窮居客訪稀。凍雲愁暮色，寒日淡斜暉。", "穿牖竹風滿，繞庭雲葉飛。已嗟週一歲，羈寓尚何依。"]'),
('yuding-15','殘秋送友','方幹','唐','御定全唐诗','yuding','','[]','早為千里別，況複是秋殘。木葉怨先老，江雲愁暮寒。',48,'御定全唐詩/json/649.json','["早為千里別，況複是秋殘。木葉怨先老，江雲愁暮寒。", "交情如水淡，離酒泛杯寬。料想還家後，休吟行路難。"]'),
('yuding-16','客行','方幹','唐','御定全唐诗','yuding','','[]','藕葉綴為衣，東西泣路岐。鄉心日落後，身計酒醒時。',48,'御定全唐詩/json/649.json','["藕葉綴為衣，東西泣路岐。鄉心日落後，身計酒醒時。", "觸目多添感，凝情足所思。羈愁難盡遣，行坐一低眉。"]'),
('yuding-17','秋夜','方幹','唐','御定全唐诗','yuding','','[]','度鴻驚睡醒，欹枕已三更。夢破寂寥思，燈殘零落明。',48,'御定全唐詩/json/649.json','["度鴻驚睡醒，欹枕已三更。夢破寂寥思，燈殘零落明。", "空窗閑月色，幽壁靜蟲聲。況是離鄉久，依然無限情。"]'),
('yuding-18','新月','方幹','唐','御定全唐诗','yuding','','[]','入夜天西見，蛾眉冷素光。潭魚驚釣落，雲雁怯弓張。',48,'御定全唐詩/json/649.json','["入夜天西見，蛾眉冷素光。潭魚驚釣落，雲雁怯弓張。", "隱隱臨珠箔，微微上粉牆。更憐三五夕，仙桂滿輪芳。"]'),
('yuding-19','滁上懷周賀','方幹','唐','御定全唐诗','yuding','','[]','就枕忽不寐，孤懷興歎初。南譙收舊曆，上苑絕來書。',48,'御定全唐詩/json/649.json','["就枕忽不寐，孤懷興歎初。南譙收舊曆，上苑絕來書。", "暝雪細聲積，晨鐘寒韻疏。侯門昔彈鋏，曾共食江魚。"]'),
('yuding-20','寄石湓清越上人','方幹','唐','御定全唐诗','yuding','','[]','寺處唯高僻，雲生石枕前。靜吟因得句，獨夜不妨禪。',48,'御定全唐詩/json/649.json','["寺處唯高僻，雲生石枕前。靜吟因得句，獨夜不妨禪。", "窗接停猿樹，岩飛浴鶴泉。相思有書劄，俱倩獵人傳。"]'),
('yuding-21','陳式水墨山水','方幹','唐','御定全唐诗','yuding','','[]','造化有功力，平分歸筆端。溪如冰後聽，山似燒來看。',48,'御定全唐詩/json/649.json','["造化有功力，平分歸筆端。溪如冰後聽，山似燒來看。", "立意雪髯出，支頤煙汗幹。世間從爾後，應覺致名難。"]'),
('yuding-22','陳秀才亭際木蘭','方幹','唐','御定全唐诗','yuding','','[]','昔見初栽日，今逢成樹時。存思心更感，繞看步還遲。',48,'御定全唐詩/json/649.json','["昔見初栽日，今逢成樹時。存思心更感，繞看步還遲。", "蝶舞搖風蕊，鶯啼含露枝。裴回不忍去，應與醉相宜。"]'),
('yuding-23','贈鏡公','方幹','唐','御定全唐诗','yuding','','[]','幽獨度遙夜，夜清神更閑。高風吹越樹，細露濕湖山。',48,'御定全唐詩/json/649.json','["幽獨度遙夜，夜清神更閑。高風吹越樹，細露濕湖山。", "月皎微吟後，鐘鳴不寐間。如教累簪組，此興豈相關。"]'),
('yuding-24','登雪竇僧家','方幹','唐','御定全唐诗','yuding','','[]','登寺尋盤道，人煙遠更微。石窗秋見海，山靄暮侵衣。',48,'御定全唐詩/json/649.json','["登寺尋盤道，人煙遠更微。石窗秋見海，山靄暮侵衣。", "眾木隨僧老，高泉盡日飛。誰能厭軒冕，來此便忘機。"]'),
('yuding-25','途中逢進士許巢','方幹','唐','御定全唐诗','yuding','','[]','聲望去已遠，門人無不知。義行相識處，貧過少年時。',48,'御定全唐詩/json/649.json','["聲望去已遠，門人無不知。義行相識處，貧過少年時。", "妨寐夜吟苦，愛閑身達遲。難求似君者，我去更逢誰。"]'),
('yuding-26','贈瑪瑙山禪者','方幹','唐','御定全唐诗','yuding','','[]','芿草不停獸，因師山更靈。村林朝乞食，風雨夜開扃。',48,'御定全唐詩/json/649.json','["芿草不停獸，因師山更靈。村林朝乞食，風雨夜開扃。", "井味兼松粉，雲根著淨瓶。塵勞如醉夢，對此暫能醒。"]'),
('yuding-27','酬故人陳乂都','方幹','唐','御定全唐诗','yuding','','[]','遠別那無夢，重遊自有期。半年鄉信到，兩地赤心知。',48,'御定全唐詩/json/649.json','["遠別那無夢，重遊自有期。半年鄉信到，兩地赤心知。", "坐久吟移調，更長硯結凘。文人才力薄，終怕阿戎欺。"]'),
('yuding-28','閏春','方幹','唐','御定全唐诗','yuding','','[]','冪冪複蒼蒼，微和傍早陽。前春寒已盡，待閏日猶長。',48,'御定全唐詩/json/649.json','["冪冪複蒼蒼，微和傍早陽。前春寒已盡，待閏日猶長。", "柳變雖因雨，花遲豈為霜。自茲延聖曆，誰不駐年光。"]'),
('yuding-29','方著作畫竹','方幹','唐','御定全唐诗','yuding','','[]','疊葉與高節，俱從毫末生。流傳千古譽，研煉十年情。',48,'御定全唐詩/json/649.json','["疊葉與高節，俱從毫末生。流傳千古譽，研煉十年情。", "向月本無影，臨風疑有聲。吾家釣台畔，似此兩三莖。"]'),
('yuding-30','題友人山花','方幹','唐','御定全唐诗','yuding','','[]','平明方發盡，為待好風吹。不見移來日，先愁落去時。',48,'御定全唐詩/json/649.json','["平明方發盡，為待好風吹。不見移來日，先愁落去時。", "濃香熏疊葉，繁朵壓卑枝。坐看皆終夕，遊蜂似有期。"]'),
('yuding-31','贈詩僧懷靜','方幹','唐','御定全唐诗','yuding','','[]','幾生餘習在，時複作微吟。坐夏莓苔合，行禪檜柏深。',48,'御定全唐詩/json/649.json','["幾生餘習在，時複作微吟。坐夏莓苔合，行禪檜柏深。", "入山成白首，學道是初心。心地不移變，徒雲寒暑侵。"]'),
('yuding-32','贈許牘秀才','方幹','唐','御定全唐诗','yuding','','[]','理論與妙用，皆從人外來。山河澄正氣，雪月助宏才。',48,'御定全唐詩/json/649.json','["理論與妙用，皆從人外來。山河澄正氣，雪月助宏才。", "傲世寄漁艇，藏名歸酒杯。升沈在方寸，即恐起風雷。"]'),
('yuding-33','送于丹','方幹','唐','御定全唐诗','yuding','','[]','至業是至寶，莫過心自知。時情如甚暢，天道即無私。',48,'御定全唐詩/json/649.json','["至業是至寶，莫過心自知。時情如甚暢，天道即無私。", "入洛霜霰苦，離家蘭菊衰。焚舟不回顧，薄暮又何之。"]'),
('yuding-34','送人游日本國','方幹','唐','御定全唐诗','yuding','','[]','蒼茫大荒外，風教即難知。連夜揚帆去，經年到岸遲。',48,'御定全唐詩/json/649.json','["蒼茫大荒外，風教即難知。連夜揚帆去，經年到岸遲。", "波濤含左界，星斗定東維。或有歸風便，當為相見期。"]'),
('yuding-35','東溪言事寄于丹','方幹','唐','御定全唐诗','yuding','','[]','日月晝夜轉，年光難駐留。軒窗才過雨，枕簟即知秋。',48,'御定全唐詩/json/649.json','["日月晝夜轉，年光難駐留。軒窗才過雨，枕簟即知秋。", "草際鳥行出，溪中虹影收。唯君壯心在，應笑臥滄洲。"]'),
('yuding-36','暮發七裏灘夜泊嚴光台下','方幹','唐','御定全唐诗','yuding','','[]','一瞬即七裏，箭馳猶是難。檣邊走嵐翠，枕底失風湍。',48,'御定全唐詩/json/649.json','["一瞬即七裏，箭馳猶是難。檣邊走嵐翠，枕底失風湍。", "但訝猿鳥定，不知霜月寒。前賢竟何益，此地誤垂竿。"]'),
('yuding-37','處州洞溪','方幹','唐','御定全唐诗','yuding','','[]','氣象四時清，無人畫得成。眾山寒疊翠，兩派綠分聲。',48,'御定全唐詩/json/649.json','["氣象四時清，無人畫得成。眾山寒疊翠，兩派綠分聲。", "坐月何曾夜，聽松不似晴。混元融結後，便有此溪名。"]'),
('yuding-38','稱心寺中島','方幹','唐','御定全唐诗','yuding','','[]','水木深不極，似將星漢連。中州唯此地，上界別無天。',48,'御定全唐詩/json/649.json','["水木深不極，似將星漢連。中州唯此地，上界別無天。", "雪折停猿樹，花藏浴鶴泉。師為終老意，日日複年年。"]'),
('yuding-39','歲晚苦寒','方幹','唐','御定全唐诗','yuding','','[]','地氣寒不暢，嚴風無定時。挑燈青燼少，呵筆尺書遲。',48,'御定全唐詩/json/649.json','["地氣寒不暢，嚴風無定時。挑燈青燼少，呵筆尺書遲。", "白兔沒已久，晨雞僵未知。佇看開聖曆，喧煦立為期。"]'),
('yuding-40','杜鵑花','方幹','唐','御定全唐诗','yuding','','[]','未問移栽日，先愁落地時。疏中從間葉，密處莫燒枝。',48,'御定全唐詩/json/649.json','["未問移栽日，先愁落地時。疏中從間葉，密處莫燒枝。", "郢客教誰探，胡蜂是自知。周回兩三步，常有醉鄉期。"]'),
('yuding-41','山中','方幹','唐','御定全唐诗','yuding','','[]','散拙亦自遂，粗將猿鳥同。飛泉高瀉月，獨樹迥含風。',48,'御定全唐詩/json/649.json','["散拙亦自遂，粗將猿鳥同。飛泉高瀉月，獨樹迥含風。", "果落盤盂上，雲生篋笥中。未甘明聖日，終作釣漁翁。"]'),
('yuding-42','路支使小池','方幹','唐','御定全唐诗','yuding','','[]','兒童戲穿鑿，咫尺見津涯。蘚岸和纖草，松泉濺淺沙。',48,'御定全唐詩/json/649.json','["兒童戲穿鑿，咫尺見津涯。蘚岸和纖草，松泉濺淺沙。", "光含半床月，影入一枝花。到此無醒日，當時有習家。"]'),
('yuding-43','清源標公','方幹','唐','御定全唐诗','yuding','','[]','師為眾人重，始得眾人師。年到白頭日，行如新戒時。',48,'御定全唐詩/json/649.json','["師為眾人重，始得眾人師。年到白頭日，行如新戒時。", "瓶添放魚澗，窗迥嫋猿枝。此地堪終老，迷癡自不知。"]'),
('yuding-44','題雪竇禪師壁','方幹','唐','御定全唐诗','yuding','','[]','飛泉濺禪石，瓶注亦生苔。海上山不淺，天邊人自來。',48,'御定全唐詩/json/649.json','["飛泉濺禪石，瓶注亦生苔。海上山不淺，天邊人自來。", "長年隨檜柏，獨夜任風雷。獵者聞疏磬，知師入定回。"]'),
('yuding-45','重寄金山寺僧','方幹','唐','御定全唐诗','yuding','','[]','風濤匝山寺，磬韻達漁船。此處別師久，遠懷無信傳。',48,'御定全唐詩/json/649.json','["風濤匝山寺，磬韻達漁船。此處別師久，遠懷無信傳。", "月華妨靜燭，鳥語答幽禪。已見如如理，灰心應不然。"]'),
('yuding-46','哭胡珪','方幹','唐','御定全唐诗','yuding','','[]','才高登上第，孝極歿廬塋。一命何無定，片言徒有聲。',48,'御定全唐詩/json/649.json','["才高登上第，孝極歿廬塋。一命何無定，片言徒有聲。", "故園花自發，新塚月初明。寂寞重泉裏，豈知春物榮。"]'),
('yuding-47','與清溪趙明府','方幹','唐','御定全唐诗','yuding','','[]','清規暫趨府，獨立與誰親。遂性無非酒，求閑卻愛貧。',48,'御定全唐詩/json/649.json','["清規暫趨府，獨立與誰親。遂性無非酒，求閑卻愛貧。", "林泉應入夢，印綬莫留人。王事聞多暇，吟來幾首新。"]'),
('yuding-48','送剡縣陳永秩滿歸越','方幹','唐','御定全唐诗','yuding','','[]','俸祿三年後，程途一月間。舟中非客路，鏡裏是家山。',48,'御定全唐詩/json/649.json','["俸祿三年後，程途一月間。舟中非客路，鏡裏是家山。", "密雪沾行袂，離杯變別顏。古人唯賀滿，今挈解由還。"]'),
('yuding-49','示鄉叟','方幹','唐','御定全唐诗','yuding','','[]','暮齒甘衰謝，逢人惜別離。青山前代業，老樹此身移。',48,'御定全唐詩/json/649.json','["暮齒甘衰謝，逢人惜別離。青山前代業，老樹此身移。", "買藥將衣盡，尋方見字遲。如何鑷殘鬢，覽鏡變成絲。"]'),
('yuding-50','游竹林寺','方幹','唐','御定全唐诗','yuding','','[]','得路到深寺，幽虛曾識名。蘚濃陰砌古，煙起暮香生。',48,'御定全唐詩/json/649.json','["得路到深寺，幽虛曾識名。蘚濃陰砌古，煙起暮香生。", "曙月落松翠，石泉流梵聲。聞僧說真理，煩惱自然輕。"]'),
('yuding-51','陸處士別業','方幹','唐','御定全唐诗','yuding','','[]','問道遠相訪，無人覺路長。夜深回釣楫，月影出書床。',48,'御定全唐詩/json/649.json','["問道遠相訪，無人覺路長。夜深回釣楫，月影出書床。", "蟬噪蓼花發，禽來山果香。多時欲歸去，西望又斜陽。"]'),
('yuding-52','贈中嶽僧','方幹','唐','御定全唐诗','yuding','','[]','坐來叢木大，誰見入岩年。多病長留藥，無憂亦是禪。',48,'御定全唐詩/json/649.json','["坐來叢木大，誰見入岩年。多病長留藥，無憂亦是禪。", "支床移片石，舂粟引高泉。盡願求心法，逢誰即擬傳。"]'),
('yuding-53','寄普州賈司倉島','方幹','唐','御定全唐诗','yuding','','[]','亂山重複疊，何路訪先生。豈料多才者，空垂不世名。',48,'御定全唐詩/json/649.json','["亂山重複疊，何路訪先生。豈料多才者，空垂不世名。", "閑曹猶得醉，薄俸亦勝耕。莫問吟詩石，年年芳草平。"]'),
('yuding-54','送鏡空上人游江南','方幹','唐','御定全唐诗','yuding','','[]','去住如雲鶴，飄然不可留。何山逢後夏，一食在孤舟。',48,'御定全唐詩/json/649.json','["去住如雲鶴，飄然不可留。何山逢後夏，一食在孤舟。", "細雨蓮塘晚，疏蟬橘岸秋。應懷舊溪月，夜過石窗流。"]'),
('yuding-55','新正','方幹','唐','御定全唐诗','yuding','','[]','蓽門惆悵內，時節暗來頻。每見新正雪，長思故國春。',48,'御定全唐詩/json/649.json','["蓽門惆悵內，時節暗來頻。每見新正雪，長思故國春。", "雲西斜去雁，江上未歸人。又一年為客，何媒得到秦。"]'),
('yuding-56','夜聽步虛','方幹','唐','御定全唐诗','yuding','','[]','寂寂永宮裏，天師朝禮聲。步虛聞一曲，渾欲到三清。',48,'御定全唐詩/json/649.json','["寂寂永宮裏，天師朝禮聲。步虛聞一曲，渾欲到三清。", "瑞草秋風起，仙階夜月明。多年遠塵意，此地欲鋪平。"]'),
('yuding-57','題碧溪山禪老','方幹','唐','御定全唐诗','yuding','','[]','師步有雲隨，師情唯鶴知。蘿迷收朮路，雪隔出溪時。',48,'御定全唐詩/json/649.json','["師步有雲隨，師情唯鶴知。蘿迷收朮路，雪隔出溪時。", "竹狖窺沙井，岩禽停檜枝。由來傲卿相，臥穩答書遲。"]'),
('yuding-58','寒食宿先天寺無可上人房','方幹','唐','御定全唐诗','yuding','','[]','雙扉檜下開，寄宿石房苔。幡北燈花動，城西雪霰來。',48,'御定全唐詩/json/649.json','["雙扉檜下開，寄宿石房苔。幡北燈花動，城西雪霰來。", "收棋想雲夢，罷茗議天臺。同憶前年臘，師初白閣回。"]'),
('yuding-59','中秋月','方幹','唐','御定全唐诗','yuding','','[]','涼霄煙靄外，三五玉蟾秋。列野星辰正，當空鬼魅愁。',48,'御定全唐詩/json/649.json','["涼霄煙靄外，三五玉蟾秋。列野星辰正，當空鬼魅愁。", "泉澄寒魄瑩，露滴冷光浮。未折青青桂，吟看不忍休。"]'),
('yuding-60','暮冬書懷呈友人','方幹','唐','御定全唐诗','yuding','','[]','空為梁甫吟，誰竟是知音。風雪生寒夜，鄉園來舊心。',48,'御定全唐詩/json/649.json','["空為梁甫吟，誰竟是知音。風雪生寒夜，鄉園來舊心。", "滄江孤棹迥，白閣一鐘深。君子久忘我，此懷甘自沈。"]'),
('yuding-61','贈江南僧','方幹','唐','御定全唐诗','yuding','','[]','忘機室亦空，禪與沃州同。唯有半庭竹，能生竟日風。',48,'御定全唐詩/json/649.json','["忘機室亦空，禪與沃州同。唯有半庭竹，能生竟日風。", "思山海月上，出定印香終。繼後傳衣者，還須立雪中。"]'),
('yuding-62','柳','方幹','唐','御定全唐诗','yuding','','[]','搖曳惹風吹，臨堤軟勝絲。態濃誰為識，力弱自難持。',48,'御定全唐詩/json/649.json','["搖曳惹風吹，臨堤軟勝絲。態濃誰為識，力弱自難持。", "學舞枝翻袖，呈妝葉展眉。如何一攀折，懷友又題詩。"]'),
('yuding-63','送姚合員外赴金州','方幹','唐','御定全唐诗','yuding','','[]','受詔從華省，開旗發帝州。野煙新驛曙，殘照古山秋。',48,'御定全唐詩/json/649.json','["受詔從華省，開旗發帝州。野煙新驛曙，殘照古山秋。", "樹勢連巴沒，江聲入楚流。唯應化行後，吟句上閑樓。"]'),
('yuding-64','送江陰霍明府之任','方幹','唐','御定全唐诗','yuding','','[]','遙遙去舸新，浸郭葦兼蘋。樹列巢灘鶴，鄉多釣浦人。',48,'御定全唐詩/json/649.json','["遙遙去舸新，浸郭葦兼蘋。樹列巢灘鶴，鄉多釣浦人。", "虹分陽羨雨，浪隔廣陵春。知竟三年秩，琴書外是貧。"]'),
('yuding-65','送友及第歸浙東','方幹','唐','御定全唐诗','yuding','','[]','南行無俗侶，秋雁與寒雲。野趣自多愜，鄉名人共聞。',48,'御定全唐詩/json/649.json','["南行無俗侶，秋雁與寒雲。野趣自多愜，鄉名人共聞。", "吳山中路斷，浙水半江分。此地登臨慣，攄情一送君。"]'),
('yuding-66','山中即事','方幹','唐','御定全唐诗','yuding','','[]','趨世非身事，山中適性情。野花多異色，幽鳥少凡聲。',48,'御定全唐詩/json/649.json','["趨世非身事，山中適性情。野花多異色，幽鳥少凡聲。", "樹影搜涼臥，苔光破碧行。閑尋采藥處，仙路漸分明。"]'),
('yuding-67','過黃州作','方幹','唐','御定全唐诗','yuding','','[]','弭節齊安郡，孤城百戰殘。傍村林有虎，帶郭縣無官。',48,'御定全唐詩/json/649.json','["弭節齊安郡，孤城百戰殘。傍村林有虎，帶郭縣無官。", "暮角梅花怨，清江桂影寒。黍離緣底事，撩我起長歎。"]'),
('yuding-0','元日','方幹','唐','御定全唐诗','yuding','','[]','晨雞兩遍報更闌，刁鬥無聲曉漏幹。暖日映山調正氣，',40,'御定全唐詩/json/650.json','["晨雞兩遍報更闌，刁鬥無聲曉漏幹。暖日映山調正氣，", "才酌屠蘇定年齒，坐中惟笑鬢毛斑。"]'),
('yuding-1','別從兄郜','方幹','唐','御定全唐诗','yuding','','[]','展翅開帆只待風，吹噓成事古今同。已呼斷雁歸行裏，',40,'御定全唐詩/json/650.json','["展翅開帆只待風，吹噓成事古今同。已呼斷雁歸行裏，", "臨岐再拜無餘事，願取文章達聖聰。"]'),
('yuding-2','寄江陵王少府','方幹','唐','御定全唐诗','yuding','','[]','分手頻曾變寒暑，迢迢遠意各何如。波濤一阻兩鄉夢，',40,'御定全唐詩/json/650.json','["分手頻曾變寒暑，迢迢遠意各何如。波濤一阻兩鄉夢，", "此來俗輩皆疏我，唯有故人心不疏。"]'),
('yuding-3','題睦州烏龍山禪居','方幹','唐','御定全唐诗','yuding','','[]','曙後月華猶冷濕，自知坐臥逼天宮。晨雞未暇鳴山底，',40,'御定全唐詩/json/650.json','["曙後月華猶冷濕，自知坐臥逼天宮。晨雞未暇鳴山底，", "伴師長住應難住，歸去仍須入俗籠。"]'),
('yuding-4','寄杭州于郎中','方幹','唐','御定全唐诗','yuding','','[]','雖雲聖代識賢明，自是山河應數生。大雅篇章無弟子，',40,'御定全唐詩/json/650.json','["雖雲聖代識賢明，自是山河應數生。大雅篇章無弟子，", "白屋青雲至懸闊，愚儒肝膽若為傾。"]'),
('yuding-5','寄靈武胡常侍','方幹','唐','御定全唐诗','yuding','','[]','青雲直上路初通，已在明君倚注中。欲遣為霖安九有，',40,'御定全唐詩/json/650.json','["青雲直上路初通，已在明君倚注中。欲遣為霖安九有，", "最是何人感恩德，謝敷星下釣漁翁。"]'),
('yuding-6','上張舍人','方幹','唐','御定全唐诗','yuding','','[]','海內芳聲誰可並，承家三代相門深。剖符已副東人望，',40,'御定全唐詩/json/650.json','["海內芳聲誰可並，承家三代相門深。剖符已副東人望，", "他年莫學鴟夷子，遠泛扁舟用鑄金。"]'),
('yuding-7','題慈溪張丞壁','方幹','唐','御定全唐诗','yuding','','[]','因君貳邑藍溪上，遣我維舟紅葉時。共向鄉中非半面，',40,'御定全唐詩/json/650.json','["因君貳邑藍溪上，遣我維舟紅葉時。共向鄉中非半面，", "貌似故人心尚喜，相逢況是舊相知。"]'),
('yuding-8','贈鄰居袁明府','方幹','唐','御定全唐诗','yuding','','[]','隔竹每呼皆得應，二心親熟更如何。文章鍛煉猶相似，',40,'御定全唐詩/json/650.json','["隔竹每呼皆得應，二心親熟更如何。文章鍛煉猶相似，", "朝昏幸得同醒醉，遮莫光陰自下坡。"]'),
('yuding-9','孫氏林亭','方幹','唐','御定全唐诗','yuding','','[]','池亭才有二三畝，風景勝於千萬家。瑟瑟林排全巷竹，',40,'御定全唐詩/json/650.json','["池亭才有二三畝，風景勝於千萬家。瑟瑟林排全巷竹，", "丱角相知成白首，而今歡笑莫咨嗟。"]'),
('yuding-10','漳州陽亭言事寄於使君','方幹','唐','御定全唐诗','yuding','','[]','謝守登城對遠峰，金英泛泛滿金鐘。樓頭風景八九月，',40,'御定全唐詩/json/650.json','["謝守登城對遠峰，金英泛泛滿金鐘。樓頭風景八九月，", "鯉魚縱是凡鱗鬣，得在膺門合作龍。"]'),
('yuding-11','別胡中丞','方幹','唐','御定全唐诗','yuding','','[]','二年朝夜見雙旌，心魄知恩夢亦驚。幽賤粗能分菽麥，',40,'御定全唐詩/json/650.json','["二年朝夜見雙旌，心魄知恩夢亦驚。幽賤粗能分菽麥，", "卻恨此身唯一死，空將一死報猶輕。"]'),
('yuding-12','游張公洞寄陶校書','方幹','唐','御定全唐诗','yuding','','[]','步步勢穿江底去，此中危滑轉身難。下蒸陰氣松蘿濕，',40,'御定全唐詩/json/650.json','["步步勢穿江底去，此中危滑轉身難。下蒸陰氣松蘿濕，", "由來委曲尋仙路，不似先生換骨丹。"]'),
('yuding-13','題睦州郡中千峰榭','方幹','唐','御定全唐诗','yuding','','[]','豈知平地似天臺，朱戶深沈別徑開。曳響露蟬穿樹去，',40,'御定全唐詩/json/650.json','["豈知平地似天臺，朱戶深沈別徑開。曳響露蟬穿樹去，", "何事此中如世外，應緣羊祜是仙才。"]'),
('yuding-14','登新城縣樓贈蔡明府','方幹','唐','御定全唐诗','yuding','','[]','楊震東來是宦游，政成登此自消憂。草中白道穿村去，',40,'御定全唐詩/json/650.json','["楊震東來是宦游，政成登此自消憂。草中白道穿村去，", "不知縣籍添新戶，但見川原桑柘稠。"]'),
('yuding-15','和於中丞登扶風亭','方幹','唐','御定全唐诗','yuding','','[]','避石攀蘿去不迷，行時舉步似丹梯。東軒海日已先照，',40,'御定全唐詩/json/650.json','["避石攀蘿去不迷，行時舉步似丹梯。東軒海日已先照，", "謝公吟望多來此，此地應將峴首齊。"]'),
('yuding-16','贈信州高員外','方幹','唐','御定全唐诗','yuding','','[]','溪勢盤回繞郡流，饒陽春色滿溪樓。豈唯啼鳥催人醉，',40,'御定全唐詩/json/650.json','["溪勢盤回繞郡流，饒陽春色滿溪樓。豈唯啼鳥催人醉，", "膺門若感深恩去，終殺微軀未足酬。"]'),
('yuding-17','漳州于使君罷郡如之任漳南去上國二十四州使君無非親故','方幹','唐','御定全唐诗','yuding','','[]','漳南罷郡如之任，二十四州相次迎。泊岸旗幡郵吏拜，',40,'御定全唐詩/json/650.json','["漳南罷郡如之任，二十四州相次迎。泊岸旗幡郵吏拜，", "聖主此時思共理，又應何處救蒼生。"]'),
('yuding-18','送弟子伍秀才赴舉','方幹','唐','御定全唐诗','yuding','','[]','天遣相門延積慶，今同太廟薦嘉賓。柳條此日同誰折，',40,'御定全唐詩/json/650.json','["天遣相門延積慶，今同太廟薦嘉賓。柳條此日同誰折，", "由來不要文章得，要且文章出眾人。"]'),
('yuding-19','貽高讜','方幹','唐','御定全唐诗','yuding','','[]','都緣相府有宗兄，卻恐妨君正路行。石上長松自森秀，',40,'御定全唐詩/json/650.json','["都緣相府有宗兄，卻恐妨君正路行。石上長松自森秀，", "幸有清才與洪筆，何愁高節不公卿。"]'),
('yuding-20','題長洲陳明府小亭','方幹','唐','御定全唐诗','yuding','','[]','坐看孤峭卻勞神，還是微吟到日曛。松鶴認名呼得下，',40,'御定全唐詩/json/650.json','["坐看孤峭卻勞神，還是微吟到日曛。松鶴認名呼得下，", "便此消遙應不易，朱衣紅旆未容君。"]'),
('yuding-21','送朱二十赴漣水','方幹','唐','御定全唐诗','yuding','','[]','到縣卻應嫌水闊，離家終是見山疏。笙歌不駐難辭酒，',40,'御定全唐詩/json/650.json','["到縣卻應嫌水闊，離家終是見山疏。笙歌不駐難辭酒，", "鸞凰取便多如此，掠地斜飛上太虛。"]'),
('yuding-22','德政上睦州胡中丞','方幹','唐','御定全唐诗','yuding','','[]','上德由來合動天，旌旗到日是豐年。群書已熟無人似，',40,'御定全唐詩/json/650.json','["上德由來合動天，旌旗到日是豐年。群書已熟無人似，", "豈唯裏巷皆蘇息，猶有恩波及釣船。"]'),
('yuding-23','袁明府以家醞寄余余以山梅答贈非唯四韻兼亦雙關','方幹','唐','御定全唐诗','yuding','','[]','封匏寄酒提攜遠，織籠盛梅答贈遲。九度攪和誰用法，',40,'御定全唐詩/json/650.json','["封匏寄酒提攜遠，織籠盛梅答贈遲。九度攪和誰用法，", "畢卓醉狂潘氏少，傾來擲去恰相宜。"]'),
('yuding-24','上杭州姚郎中','方幹','唐','御定全唐诗','yuding','','[]','能除疾瘼似良醫，一郡鄉風當日移。身貴久離行藥伴，',40,'御定全唐詩/json/650.json','["能除疾瘼似良醫，一郡鄉風當日移。身貴久離行藥伴，", "借問公方與文道，而今中夏更傳誰。"]'),
('yuding-25','送葉秀才赴舉兼呈呂少監','方幹','唐','御定全唐诗','yuding','','[]','君辭舊裏一年期，藝至心身亦自知。尊盡離人看北斗，',40,'御定全唐詩/json/650.json','["君辭舊裏一年期，藝至心身亦自知。尊盡離人看北斗，", "與爾相逢終不遠，昨聞秘監在台墀。"]'),
('yuding-26','自縉雲赴郡溪流百里輕棹一發曾不崇朝敘事四韻寄獻段郎中','方幹','唐','御定全唐诗','yuding','','[]','激箭溪湍勢莫憑，飄然一葉若為乘。仰瞻青壁開天罅，',40,'御定全唐詩/json/650.json','["激箭溪湍勢莫憑，飄然一葉若為乘。仰瞻青壁開天罅，", "此中明日尋知己，恐似龍門不易登。"]'),
('yuding-27','胡中丞早梅','方幹','唐','御定全唐诗','yuding','','[]','不獨閑花不共時，一株寒豔尚參差。淩晨未噴含霜朵，',40,'御定全唐詩/json/650.json','["不獨閑花不共時，一株寒豔尚參差。淩晨未噴含霜朵，", "謝公吟賞愁飄落，可得更拈長笛吹。"]'),
('yuding-28','牡丹','方幹','唐','御定全唐诗','yuding','','[]','借問庭芳早晚栽，座中疑展畫屏開。花分淺淺胭脂臉，',40,'御定全唐詩/json/650.json','["借問庭芳早晚栽，座中疑展畫屏開。花分淺淺胭脂臉，", "殷勤為報看花客，莫學遊蜂日日來。"]'),
('yuding-29','觀項信水墨','方幹','唐','御定全唐诗','yuding','','[]','險峭雖從筆下成，精能皆自意中生。倚雲孤檜知無朽，',40,'御定全唐詩/json/650.json','["險峭雖從筆下成，精能皆自意中生。倚雲孤檜知無朽，", "小年師祖過今祖，異域應傳項信名。"]'),
('yuding-30','書桃花塢周處士壁','方幹','唐','御定全唐诗','yuding','','[]','醉吟雪月思深苦，思苦神勞華發生。自學古賢修靜節，',40,'御定全唐詩/json/650.json','["醉吟雪月思深苦，思苦神勞華發生。自學古賢修靜節，", "何事懶于嵇叔夜，更無書劄答公卿。"]'),
('yuding-31','題桐廬謝逸人江居','方幹','唐','御定全唐诗','yuding','','[]','少小高眠無一事，五侯勳盛欲如何。湖邊倚杖寒吟苦，',40,'御定全唐詩/json/650.json','["少小高眠無一事，五侯勳盛欲如何。湖邊倚杖寒吟苦，", "由來朝市為真隱，可要棲身向薜蘿。"]'),
('yuding-32','敘雪寄喻鳧','方幹','唐','御定全唐诗','yuding','','[]','密片無聲急複遲，紛紛猶勝落花時。從容不覺藏苔徑，',40,'御定全唐詩/json/650.json','["密片無聲急複遲，紛紛猶勝落花時。從容不覺藏苔徑，", "高人坐臥才方逸，援筆應成六出詞。"]'),
('yuding-33','敘雪寄喻鳧','方幹','唐','御定全唐诗','yuding','','[]','密片繁聲旋不銷，縈風雜霰轉飄颻。澄江莫蔽長流色，',40,'御定全唐詩/json/650.json','["密片繁聲旋不銷，縈風雜霰轉飄颻。澄江莫蔽長流色，", "此時明徑無行跡，唯望徽之問寂寥。"]'),
('yuding-34','哭秘書姚少監','方幹','唐','御定全唐诗','yuding','','[]','寒空此夜落文星，星落文留萬古名。入室幾人成弟子，',40,'御定全唐詩/json/650.json','["寒空此夜落文星，星落文留萬古名。入室幾人成弟子，", "曉向平原陳葬禮，悲風吹雨濕銘旌。"]'),
('yuding-35','送人宰永泰','方幹','唐','御定全唐诗','yuding','','[]','北人雖泛南流水，稱意南行莫恨賒。道路先經毛竹嶺，',40,'御定全唐詩/json/650.json','["北人雖泛南流水，稱意南行莫恨賒。道路先經毛竹嶺，", "下馬政聲王事少，應容閑吏日高衙。"]'),
('yuding-36','旅次洋州寓居郝氏林亭','方幹','唐','御定全唐诗','yuding','','[]','舉目縱然非我有，思量似在故山時。鶴盤遠勢投孤嶼，',40,'御定全唐詩/json/650.json','["舉目縱然非我有，思量似在故山時。鶴盤遠勢投孤嶼，", "青雲未得平行去，夢到江南身旅羈。"]'),
('yuding-37','茅山贈洪拾遺','方幹','唐','御定全唐诗','yuding','','[]','聖代諫臣停諫舌，求歸故里傲雲霞。溪頭講樹纜漁艇，',40,'御定全唐詩/json/650.json','["聖代諫臣停諫舌，求歸故里傲雲霞。溪頭講樹纜漁艇，", "我來幸與諸生異，問答時容近絳紗。"]'),
('yuding-38','睦州呂郎中郡中環溪亭','方幹','唐','御定全唐诗','yuding','','[]','為是仙才登望處，風光便似武陵春。閑花半落猶迷蝶，',40,'御定全唐詩/json/650.json','["為是仙才登望處，風光便似武陵春。閑花半落猶迷蝶，", "暫來此地非多日，明主那容借寇恂。"]'),
('yuding-39','贈華陰隱者','方幹','唐','御定全唐诗','yuding','','[]','少微夜夜當仙掌，更有何人在此居。花月舊應看浴鶴，',40,'御定全唐詩/json/650.json','["少微夜夜當仙掌，更有何人在此居。花月舊應看浴鶴，", "故國多年歸未遂，因逢此地憶吾廬。"]'),
('yuding-40','上杭州杜中丞','方幹','唐','御定全唐诗','yuding','','[]','昔用雄才登上第，今將重德合明君。苦心多為安民術，',40,'御定全唐詩/json/650.json','["昔用雄才登上第，今將重德合明君。苦心多為安民術，", "掠天逸勢應非久，一鶚那棲眾鳥群。"]'),
('yuding-41','贈處州段郎中','方幹','唐','御定全唐诗','yuding','','[]','幸見仙才領郡初，郡城孤峭似仙居。杉蘿色裏遊亭榭，',40,'御定全唐詩/json/650.json','["幸見仙才領郡初，郡城孤峭似仙居。杉蘿色裏遊亭榭，", "寒潭是處清連底，賓席何心望食魚。"]'),
('yuding-42','書法華寺上方禪壁','方幹','唐','御定全唐诗','yuding','','[]','砌下松巔有鶴棲，孤猿亦在鶴邊啼。臥聞雷雨歸岩早，',40,'御定全唐詩/json/650.json','["砌下松巔有鶴棲，孤猿亦在鶴邊啼。臥聞雷雨歸岩早，", "是非生死多憂惱，此日蒙師為破迷。"]'),
('yuding-43','書吳道隱林亭','方幹','唐','御定全唐诗','yuding','','[]','蘚榭莎亭蘿筱陰，依稀氣象似山林。橘枝亞路黃苞重，',40,'御定全唐詩/json/650.json','["蘚榭莎亭蘿筱陰，依稀氣象似山林。橘枝亞路黃苞重，", "四鄰不見孤高處，翻笑騰騰只醉吟。"]'),
('yuding-44','陪王大夫泛湖','方幹','唐','御定全唐诗','yuding','','[]','去去淩晨回見星，木蘭舟穩畫橈輕。白波潭上魚龍氣，',40,'御定全唐詩/json/650.json','["去去淩晨回見星，木蘭舟穩畫橈輕。白波潭上魚龍氣，", "此時檢點諸名士，卻是漁翁無姓名。"]'),
('yuding-45','贈會稽張少府','方幹','唐','御定全唐诗','yuding','','[]','高節何曾似任官，藥苗香潔備常餐。一分酒戶添猶得，',40,'御定全唐詩/json/650.json','["高節何曾似任官，藥苗香潔備常餐。一分酒戶添猶得，", "明年莫便還家去，鏡裏雲山且共看。"]'),
('yuding-46','送鄭台處士歸絳岩','方幹','唐','御定全唐诗','yuding','','[]','榮啟先生挾琴去，厭尋靈勝憶岩棲。白猿垂樹窗邊月，',40,'御定全唐詩/json/650.json','["榮啟先生挾琴去，厭尋靈勝憶岩棲。白猿垂樹窗邊月，", "古賢猶愴河梁別，未可匆匆便解攜。"]'),
('yuding-47','因話天臺勝異仍送羅道士','方幹','唐','御定全唐诗','yuding','','[]','積翠千層一徑開，遙盤山腹到瓊台。藕花飄落前岩去，',40,'御定全唐詩/json/650.json','["積翠千層一徑開，遙盤山腹到瓊台。藕花飄落前岩去，", "縱雲孤鶴無留滯，定恐煙蘿不放回。"]'),
('yuding-48','哭喻鳧先輩','方幹','唐','御定全唐诗','yuding','','[]','日夜役神多損壽，先生下世未中年。撰碑縱托登龍伴，',40,'御定全唐詩/json/650.json','["日夜役神多損壽，先生下世未中年。撰碑縱托登龍伴，", "人間別更無冤事，到此誰能與問天。"]'),
('yuding-49','湖北有茅齋湖西有松島輕棹往返頗諧素心因成四韻','方幹','唐','御定全唐诗','yuding','','[]','湖北湖西往復還，朝昏只處自由間。暑天移榻就深竹，',40,'御定全唐詩/json/650.json','["湖北湖西往復還，朝昏只處自由間。暑天移榻就深竹，", "古賢暮齒方如此，多笑愚儒鬢未斑。"]'),
('yuding-50','鑒湖西島言事','方幹','唐','御定全唐诗','yuding','','[]','慵拙幸便荒僻地，縱聽猿鳥亦何愁。偶斟藥酒欺梅雨，',40,'御定全唐詩/json/650.json','["慵拙幸便荒僻地，縱聽猿鳥亦何愁。偶斟藥酒欺梅雨，", "世人若便無知己，應向此溪成白頭。"]'),
('yuding-51','山中言事','方幹','唐','御定全唐诗','yuding','','[]','欹枕亦吟行亦醉，臥吟行醉更何營。貧來猶有故琴在，',40,'御定全唐詩/json/650.json','["欹枕亦吟行亦醉，臥吟行醉更何營。貧來猶有故琴在，", "潛夫自有孤雲侶，可要王侯知姓名。"]'),
('yuding-52','贈蕭山彭少府','方幹','唐','御定全唐诗','yuding','','[]','作尉孜孜更寒苦，操心至癖不為清。雖將劍鶴支殘債，',40,'御定全唐詩/json/650.json','["作尉孜孜更寒苦，操心至癖不為清。雖將劍鶴支殘債，", "與君相識因儒術，歲月彌多別有情。"]'),
('yuding-53','贈式上人','方幹','唐','御定全唐诗','yuding','','[]','縱居鼙角喧闐處，亦共雲溪邃僻同。萬慮全離方寸內，',40,'御定全唐詩/json/650.json','["縱居鼙角喧闐處，亦共雲溪邃僻同。萬慮全離方寸內，", "莫笑旅人終日醉，吾將大醉與禪通。"]'),
('yuding-54','贈錢塘湖上唐處士','方幹','唐','御定全唐诗','yuding','','[]','我愛君家似洞庭，沖灣潑岸夜波聲。蟾蜍影裏清吟苦，',40,'御定全唐詩/json/650.json','["我愛君家似洞庭，沖灣潑岸夜波聲。蟾蜍影裏清吟苦，", "莫言舉世無知己，自有孤雲識此情。"]'),
('yuding-0','山中言事','方幹','唐','御定全唐诗','yuding','','[]','日與村家事漸同，燒松啜茗學鄰翁。池塘月撼芙蕖浪，',40,'御定全唐詩/json/651.json','["日與村家事漸同，燒松啜茗學鄰翁。池塘月撼芙蕖浪，", "山陰釣叟無知己，窺鏡撏多鬢欲空。"]'),
('yuding-1','題陶詳校書陽羨隱居','方幹','唐','御定全唐诗','yuding','','[]','芸香署裏從容步，陽羨山中嘯傲情。竿底紫鱗輸釣伴，',40,'御定全唐詩/json/651.json','["芸香署裏從容步，陽羨山中嘯傲情。竿底紫鱗輸釣伴，", "便泛扁舟應未得，鴟夷棄相始垂名。"]'),
('yuding-2','秋晚林中寄賓幕','方幹','唐','御定全唐诗','yuding','','[]','八月蕭條九月時，沙蟬海燕各分飛。杯盂未稱嘗生酒，',40,'御定全唐詩/json/651.json','["八月蕭條九月時，沙蟬海燕各分飛。杯盂未稱嘗生酒，", "無過縱有家山思，印綬留連爭得歸。"]'),
('yuding-3','與鄉人鑒休上人別','方幹','唐','御定全唐诗','yuding','','[]','此日因師話鄉里，故鄉風土我偏諳。一枝竹葉如溪北，',40,'御定全唐詩/json/651.json','["此日因師話鄉里，故鄉風土我偏諳。一枝竹葉如溪北，", "如今休作還家意，兩須垂絲已不堪。"]'),
('yuding-4','送王霖赴舉','方幹','唐','御定全唐诗','yuding','','[]','自古主司看薦士，明年應是不參差。須憑吉夢為先兆，',40,'御定全唐詩/json/651.json','["自古主司看薦士，明年應是不參差。須憑吉夢為先兆，", "郤詵可要真消息，只向春前便得知。"]'),
('yuding-5','思越中舊游寄友','方幹','唐','御定全唐诗','yuding','','[]','甸外山川無越國，依稀只似劍門西。鏡中疊浪搖星斗，',40,'御定全唐詩/json/651.json','["甸外山川無越國，依稀只似劍門西。鏡中疊浪搖星斗，", "此中曾是同遊處，迢遞尋君夢不迷。"]'),
('yuding-6','陪胡中丞泛湖','方幹','唐','御定全唐诗','yuding','','[]','仙舟仙樂醉行春，上界稀逢下界人。綺繡峰前聞野鶴，',40,'御定全唐詩/json/651.json','["仙舟仙樂醉行春，上界稀逢下界人。綺繡峰前聞野鶴，", "凡許從容誰不幸，就中光顯是州民。"]'),
('yuding-7','敘雪獻員外','方幹','唐','御定全唐诗','yuding','','[]','紛紜宛轉更堪看，壓竹摧巢井徑漫。風柳細條黏不得，',40,'御定全唐詩/json/651.json','["紛紜宛轉更堪看，壓竹摧巢井徑漫。風柳細條黏不得，", "謝守來吟才更逸，郢詞先至彩毫端。"]'),
('yuding-8','王將軍','方幹','唐','御定全唐诗','yuding','','[]','大志無心守章句，終懷上略致殊功。保寧帝業青萍在，',40,'御定全唐詩/json/651.json','["大志無心守章句，終懷上略致殊功。保寧帝業青萍在，", "將星依舊當文座，應念愚儒命未通。"]'),
('yuding-9','陽亭言事獻漳州於使君','方幹','唐','御定全唐诗','yuding','','[]','重疊山前對酒樽，騰騰兀兀度朝昏。平明疏磬白雲寺，',40,'御定全唐詩/json/651.json','["重疊山前對酒樽，騰騰兀兀度朝昏。平明疏磬白雲寺，", "旅人寄食逢黃菊，每見故人思故園。"]'),
('yuding-10','海石榴','方幹','唐','御定全唐诗','yuding','','[]','亭際夭妍日日看，每朝顏色一般般。滿枝猶待春風力，',40,'御定全唐詩/json/651.json','["亭際夭妍日日看，每朝顏色一般般。滿枝猶待春風力，", "久長年少應難得，忍不叢邊到夜觀。"]'),
('yuding-11','嘉興許明府','方幹','唐','御定全唐诗','yuding','','[]','檇李轉聞風教好，重門夜不上重關。腰懸墨綬三年外，',40,'御定全唐詩/json/651.json','["檇李轉聞風教好，重門夜不上重關。腰懸墨綬三年外，", "升沈路別情猶在，不忘鄉中舊往還。"]'),
('yuding-12','再題路支使南亭','方幹','唐','御定全唐诗','yuding','','[]','行處避松兼礙石，即須門徑落斜開。愛邀舊友看漁釣，',40,'御定全唐詩/json/651.json','["行處避松兼礙石，即須門徑落斜開。愛邀舊友看漁釣，", "睡時分得江淹夢，五色毫端弄逸才。"]'),
('yuding-13','路支使小池','方幹','唐','御定全唐诗','yuding','','[]','廣狹偶然非制定，猶將方寸像滄溟。一泓春水無多浪，',40,'御定全唐詩/json/651.json','["廣狹偶然非制定，猶將方寸像滄溟。一泓春水無多浪，", "主人垂釣常來此，雖把魚竿醉未醒。"]'),
('yuding-14','哭江西處士陳陶','方幹','唐','御定全唐诗','yuding','','[]','壽盡天年命不通，釣溪吟月便成翁。雖雲掛劍來墳上，',40,'御定全唐詩/json/651.json','["壽盡天年命不通，釣溪吟月便成翁。雖雲掛劍來墳上，", "南華至理須齊物，生死即應無異同。"]'),
('yuding-15','越中言事二首','方幹','唐','御定全唐诗','yuding','','[]','異術閑和合聖明，湖光浩氣共澄清。郭中雲吐啼猿寺，',80,'御定全唐詩/json/651.json','["異術閑和合聖明，湖光浩氣共澄清。郭中雲吐啼猿寺，", "遊人今日又明日，不覺鏡中新發生。", "雲霞水木共蒼蒼，元化分功秀一方。百里湖波輕撼月，", "終歲逍遙仁術內，無名甘老買臣鄉。"]'),
('yuding-16','題龍瑞觀兼呈徐尊師','方幹','唐','御定全唐诗','yuding','','[]','或雨或雲常不定，地靈雲雨自無時。世人莫識神方字，',40,'御定全唐詩/json/651.json','["或雨或雲常不定，地靈雲雨自無時。世人莫識神方字，", "此中唯有師知我，未得尋師即夢師。"]'),
('yuding-17','送陳秀才將游霅上便議北歸','方幹','唐','御定全唐诗','yuding','','[]','婆娑戀酒山花盡，繞繚還家水路通。轉楫擬從青草岸，',40,'御定全唐詩/json/651.json','["婆娑戀酒山花盡，繞繚還家水路通。轉楫擬從青草岸，", "詩句因餘更孤峭，書題不合忘江東。"]'),
('yuding-18','送吳彥融赴舉','方幹','唐','御定全唐诗','yuding','','[]','用心精至自無疑，千萬人中似汝稀。上國才將五字去，',40,'御定全唐詩/json/651.json','["用心精至自無疑，千萬人中似汝稀。上國才將五字去，", "想見明年榜前事，當時分散著來衣。"]'),
('yuding-19','同蕭山陳長官縣樓登望','方幹','唐','御定全唐诗','yuding','','[]','坐看南北與西東，遠近無非禮義中。一縣繁花香送雨，',40,'御定全唐詩/json/651.json','["坐看南北與西東，遠近無非禮義中。一縣繁花香送雨，", "仲叔受恩多感戀，裴回卻怕酒壺空。"]'),
('yuding-20','送何道者','方幹','唐','御定全唐诗','yuding','','[]','何事忽來還忽去，孤雲不定鶴情高。真經與術添年壽，',40,'御定全唐詩/json/651.json','["何事忽來還忽去，孤雲不定鶴情高。真經與術添年壽，", "遍尋岩洞求仙者，即恐無人似爾曹。"]'),
('yuding-21','酬將作於少監','方幹','唐','御定全唐诗','yuding','','[]','由來至寶出毫端，五色炎光照室寒。仰望孤峰知聳峻，',40,'御定全唐詩/json/651.json','["由來至寶出毫端，五色炎光照室寒。仰望孤峰知聳峻，", "不是散齋兼拭目，尋常未便借人看。"]'),
('yuding-22','雪中寄殷道士','方幹','唐','御定全唐诗','yuding','','[]','大片紛紛小片輕，雨和風擊更縱橫。園林入夜寒光動，',40,'御定全唐詩/json/651.json','["大片紛紛小片輕，雨和風擊更縱橫。園林入夜寒光動，", "山陰道士吟多興，六出花邊五字成。"]'),
('yuding-23','宋從事','方幹','唐','御定全唐诗','yuding','','[]','出眾仙才是謫仙，裁霞曳繡一篇篇。雖將潔白酬知己，',40,'御定全唐詩/json/651.json','["出眾仙才是謫仙，裁霞曳繡一篇篇。雖將潔白酬知己，", "冥搜太苦神應乏，心在虛無更那邊。"]'),
('yuding-24','出山寄蘇從事','方幹','唐','御定全唐诗','yuding','','[]','寸心似火頻求薦，兩鬢如霜始息機。隔岸雞鳴春耨去，',40,'御定全唐詩/json/651.json','["寸心似火頻求薦，兩鬢如霜始息機。隔岸雞鳴春耨去，", "多謝元瑜憐野賤，時回車馬發光輝。"]'),
('yuding-25','送杭州李員外','方幹','唐','御定全唐诗','yuding','','[]','政成何用滿三年，上界群仙待謫仙。便赴新恩歸紫禁，',40,'御定全唐詩/json/651.json','["政成何用滿三年，上界群仙待謫仙。便赴新恩歸紫禁，", "必恐駐班留立位，前程一步是爐煙。"]'),
('yuding-26','贈李支使','方幹','唐','御定全唐诗','yuding','','[]','藥成平地是寥天，三十人中最少年。白雪振聲來輦下，',40,'御定全唐詩/json/651.json','["藥成平地是寥天，三十人中最少年。白雪振聲來輦下，", "一等孔門為弟子，愚儒獨自賦歸田。"]'),
('yuding-27','盧卓山人畫水','方幹','唐','御定全唐诗','yuding','','[]','常聞畫石不畫水，畫水至難君得名。海色未將藍汁染，',40,'御定全唐詩/json/651.json','["常聞畫石不畫水，畫水至難君得名。海色未將藍汁染，", "坐久神迷不能決，卻疑身在小蓬瀛。"]'),
('yuding-28','廢宅','方幹','唐','御定全唐诗','yuding','','[]','主人何處獨裴回，流水自流花自開。若見故交皆散去，',40,'御定全唐詩/json/651.json','["主人何處獨裴回，流水自流花自開。若見故交皆散去，", "應是曾經惡風雨，修桐半折損琴材。"]'),
('yuding-29','題寶林山禪院','方幹','唐','御定全唐诗','yuding','','[]','山捧亭台郭繞山，遙盤蒼翠到山巔。岩中古井雖通海，',40,'御定全唐詩/json/651.json','["山捧亭台郭繞山，遙盤蒼翠到山巔。岩中古井雖通海，", "我來可要歸禪老，一寸寒灰已達玄。"]'),
('yuding-30','題越州袁秀才林亭','方幹','唐','御定全唐诗','yuding','','[]','清邃林亭指畫開，幽岩別派像天臺。坐牽蕉葉題詩句，',40,'御定全唐詩/json/651.json','["清邃林亭指畫開，幽岩別派像天臺。坐牽蕉葉題詩句，", "終年此地為吟伴，早起尋君薄暮回。"]'),
('yuding-31','題龜山穆上人院','方幹','唐','御定全唐诗','yuding','','[]','修持百法過半百，日往月來心更堅。床上水雲隨坐夏，',40,'御定全唐詩/json/651.json','["修持百法過半百，日往月來心更堅。床上水雲隨坐夏，", "我愛尋師師訪我，只應尋訪是因緣。"]'),
('yuding-32','贈美人四首','方幹','唐','御定全唐诗','yuding','','[]','直緣多藝用心勞，心路玲瓏格調高。舞袖低徊真蛺蝶，',160,'御定全唐詩/json/651.json','["直緣多藝用心勞，心路玲瓏格調高。舞袖低徊真蛺蝶，", "才會雨雲須別去，語慚不及琵琶槽。", "嚴冬忽作看花日，盛暑翻為見雪時。坐上弄嬌聲不轉，", "年幾未多猶怯在，些些私語怕人疑。", "酒蘊天然自性靈，人間有藝總關情。剝蔥十指轉籌疾，", "若教梅尉無仙骨，爭得仙娥駐玉京。", "昔日仙人今玉人，深冬相見亦如春。倍酬金價微含笑，", "百年別後知誰在，須遣丹青畫取真。"]'),
('yuding-33','聽段處士彈琴','方幹','唐','御定全唐诗','yuding','','[]','幾年調弄七條絲，元化分功十指知。泉迸幽音離石底，',40,'御定全唐詩/json/651.json','["幾年調弄七條絲，元化分功十指知。泉迸幽音離石底，", "唯有此時心更靜，聲聲可作後人師。"]'),
('yuding-34','初歸鏡中寄陳端公','方幹','唐','御定全唐诗','yuding','','[]','去歲離家今歲歸，孤帆夢向鳥前飛。必知蘆筍侵沙井，',40,'御定全唐詩/json/651.json','["去歲離家今歲歸，孤帆夢向鳥前飛。必知蘆筍侵沙井，", "故交若問逍遙事，玄冕何曾勝葦衣。"]'),
('yuding-35','再題龍泉寺上方','方幹','唐','御定全唐诗','yuding','','[]','牛鬥正齊群木末，鳥行橫截眾山腰。路盤砌下兼穿竹，',40,'御定全唐詩/json/651.json','["牛鬥正齊群木末，鳥行橫截眾山腰。路盤砌下兼穿竹，", "未能割得繁華去，難向此中甘寂寞。"]'),
('yuding-36','于秀才小池','方幹','唐','御定全唐诗','yuding','','[]','一泓瀲灩複澄明，半日功夫劚小庭。占地未過四五尺，',40,'御定全唐詩/json/651.json','["一泓瀲灩複澄明，半日功夫劚小庭。占地未過四五尺，", "才見規模識方寸，知君立意象滄溟。"]'),
('yuding-37','敘錢塘異勝','方幹','唐','御定全唐诗','yuding','','[]','暖景融融寒景清，越颱風送曉鐘聲。四郊遠火燒煙月，',40,'御定全唐詩/json/651.json','["暖景融融寒景清，越颱風送曉鐘聲。四郊遠火燒煙月，", "謝公吟處依稀在，千古無人繼盛名。"]'),
('yuding-38','贈中岩王處士','方幹','唐','御定全唐诗','yuding','','[]','垂楊嫋嫋草芊芊，氣象清深似洞天。援筆便成鸚鵡賦，',40,'御定全唐詩/json/651.json','["垂楊嫋嫋草芊芊，氣象清深似洞天。援筆便成鸚鵡賦，", "直恐剛腸閑未得，醉吟爭奈被才牽。"]'),
('yuding-39','初歸故里獻侯郎中','方幹','唐','御定全唐诗','yuding','','[]','常思舊裏欲歸難，已作歸心即自寬。此日早知無爵位，',40,'御定全唐詩/json/651.json','["常思舊裏欲歸難，已作歸心即自寬。此日早知無爵位，", "不是幽愚望榮忝，君侯異禮亦何安。"]'),
('yuding-40','歸睦州中路寄侯郎中','方幹','唐','御定全唐诗','yuding','','[]','顏巷蕭條知命後，膺門感激受恩初。卻容鶴發還蝸舍，',40,'御定全唐詩/json/651.json','["顏巷蕭條知命後，膺門感激受恩初。卻容鶴發還蝸舍，", "鄉中自古為儒者，誰得公侯降尺書。"]'),
('yuding-41','題報恩寺上方','方幹','唐','御定全唐诗','yuding','','[]','來來先上上方看，眼界無窮世界寬。岩溜噴空晴似雨，',40,'御定全唐詩/json/651.json','["來來先上上方看，眼界無窮世界寬。岩溜噴空晴似雨，", "清峭關心惜歸去，他時夢到亦難判。"]'),
('yuding-42','送永嘉王令之任二首','方幹','唐','御定全唐诗','yuding','','[]','定擬孜孜化海邊，須判素發侮流年。波濤不應雙溪水，',80,'御定全唐詩/json/651.json','["定擬孜孜化海邊，須判素發侮流年。波濤不應雙溪水，", "前賢未必全堪學，莫讀當時歸去篇。", "雖展縣圖如到縣，五程猶入縉雲東。山間閣道盤岩底，", "字人若用非常術，唯要旬時便立功。"]'),
('yuding-43','鹽官王長官新創瑞隱亭','方幹','唐','御定全唐诗','yuding','','[]','指畫便分元化力，周回秀絕自清機。孤雲戀石尋常住，',40,'御定全唐詩/json/651.json','["指畫便分元化力，周回秀絕自清機。孤雲戀石尋常住，", "明年秩滿難將去，何似先教畫取歸。"]'),
('yuding-44','李戶曹小妓天得善擊越器以成曲章','方幹','唐','御定全唐诗','yuding','','[]','越器敲來曲調成，腕頭勻滑自輕清。隨風搖曳有餘韻，',40,'御定全唐詩/json/651.json','["越器敲來曲調成，腕頭勻滑自輕清。隨風搖曳有餘韻，", "若教進上梨園去，眾樂無由更擅名。"]'),
('yuding-45','歲晚言事寄鄉中親友','方幹','唐','御定全唐诗','yuding','','[]','急景蒼茫晝若昏，夜風乾峭觸前軒。寒威半入龍蛇窟，',40,'御定全唐詩/json/651.json','["急景蒼茫晝若昏，夜風乾峭觸前軒。寒威半入龍蛇窟，", "尺書未達年應老，先被新春入故園。"]'),
('yuding-46','贈孫百篇','方幹','唐','御定全唐诗','yuding','','[]','禦題百首思縱橫，半日功夫舉世名。羽翼便從吟處出，',40,'御定全唐詩/json/651.json','["禦題百首思縱橫，半日功夫舉世名。羽翼便從吟處出，", "才子風流複年少，無愁高臥不公卿。"]'),
('yuding-47','贈夏侯評事','方幹','唐','御定全唐诗','yuding','','[]','傍窺盛德與高節，緬想應無前後人。講論參同深到骨，',40,'御定全唐詩/json/651.json','["傍窺盛德與高節，緬想應無前後人。講論參同深到骨，", "朱紫侯門猶不見，可知岐路有風塵。"]'),
('yuding-48','送鄭端公','方幹','唐','御定全唐诗','yuding','','[]','聖主佇知宣室事，豈容才子滯長沙。隨珠此去方酬德，',40,'御定全唐詩/json/651.json','["聖主佇知宣室事，豈容才子滯長沙。隨珠此去方酬德，", "應憐寂寞滄洲客，煙漢塵泥相去賒。"]'),
('yuding-49','題故人廢宅二首','方幹','唐','御定全唐诗','yuding','','[]','舉目淒涼入破門，鮫人一飯尚知恩。閑花舊識猶含笑，',80,'御定全唐詩/json/651.json','["舉目淒涼入破門，鮫人一飯尚知恩。閑花舊識猶含笑，", "壺觴笑詠隨風去，唯有聲聲蜀帝魂。", "寒莎野樹入荒庭，風雨蕭蕭不掩扃。舊徑已知無孟竹，", "薄暮停車更悽愴，山陽鄰笛若為聽。"]'),
('yuding-50','寄於少監','方幹','唐','御定全唐诗','yuding','','[]','修持清苦振佳聲，眾鳥那知一鶚情。躡履三千皆後學，',40,'御定全唐詩/json/651.json','["修持清苦振佳聲，眾鳥那知一鶚情。躡履三千皆後學，", "從此雲泥更懸闊，漁翁不合見公卿。"]'),
('yuding-51','和剡縣陳明府登縣樓','方幹','唐','御定全唐诗','yuding','','[]','郭裏人家如掌上，簷前樹木映窗櫺。煙霞若接天臺地，',40,'御定全唐詩/json/651.json','["郭裏人家如掌上，簷前樹木映窗櫺。煙霞若接天臺地，", "彩衣才子多吟嘯，公退時時見畫屏。"]'),
('yuding-52','項洙處士畫水墨釣台','方幹','唐','御定全唐诗','yuding','','[]','畫石畫松無兩般，猶嫌瀑布畫聲難。雖雲智惠生靈府，',40,'御定全唐詩/json/651.json','["畫石畫松無兩般，猶嫌瀑布畫聲難。雖雲智惠生靈府，", "我家曾寄雙台下，往往開圖盡日看。"]'),
('yuding-0','贈天臺葉尊師','方幹','唐','御定全唐诗','yuding','','[]','莫見平明離少室，須知薄暮入天臺。常時愛縮山川去，',40,'御定全唐詩/json/652.json','["莫見平明離少室，須知薄暮入天臺。常時愛縮山川去，", "先生暗笑看棋者，半局棋邊白髮催。"]'),
('yuding-1','寄台州孫從事百篇','方幹','唐','御定全唐诗','yuding','','[]','聖世科名酬志業，仙州秀色助神機。梅真入仕提雄筆，',40,'御定全唐詩/json/652.json','["聖世科名酬志業，仙州秀色助神機。梅真入仕提雄筆，", "相思莫訝音書晚，鳥去猶須疊日飛。"]'),
('yuding-2','送睦州侯郎中赴闕','方幹','唐','御定全唐诗','yuding','','[]','昔著政聲聞國外，今留儒術化江東。青雲舊路歸仙掖，',40,'御定全唐詩/json/652.json','["昔著政聲聞國外，今留儒術化江東。青雲舊路歸仙掖，", "郡人難議酬恩德，遍在三年禮遇中。"]'),
('yuding-3','朱秀才庭際薔薇','方幹','唐','御定全唐诗','yuding','','[]','繡難相似畫難真，明媚鮮妍絕比倫。露壓盤條方到地，',40,'御定全唐詩/json/652.json','["繡難相似畫難真，明媚鮮妍絕比倫。露壓盤條方到地，", "看取後時歸故里，庭花應讓錦衣新。"]'),
('yuding-4','登龍瑞觀北岩','方幹','唐','御定全唐诗','yuding','','[]','縱目下看浮世事，方知峭崿與天通。湖邊風力歸帆上，',40,'御定全唐詩/json/652.json','["縱目下看浮世事，方知峭崿與天通。湖邊風力歸帆上，", "前人去後後人至，今古異時登眺同。"]'),
('yuding-5','送婺州許錄事','方幹','唐','御定全唐诗','yuding','','[]','之官便是還鄉路，白日堂堂著錦衣。八詠遺風資逸興，',40,'御定全唐詩/json/652.json','["之官便是還鄉路，白日堂堂著錦衣。八詠遺風資逸興，", "笑我中年更愚僻，醉醒多在釣漁磯。"]'),
('yuding-6','題龍泉寺絕頂','方幹','唐','御定全唐诗','yuding','','[]','未明先見海底日，良久遠雞方報晨。古樹含風長帶雨，',40,'御定全唐詩/json/652.json','["未明先見海底日，良久遠雞方報晨。古樹含風長帶雨，", "前後登臨思無盡，年年改換去來人。"]'),
('yuding-7','贈上虞胡少府百篇','方幹','唐','御定全唐诗','yuding','','[]','求仙不在煉金丹，輕舉由來別有門。日晷未移三十刻，',40,'御定全唐詩/json/652.json','["求仙不在煉金丹，輕舉由來別有門。日晷未移三十刻，", "斂板塵中無恨色，應緣利祿副晨昏。"]'),
('yuding-8','上鄭員外','方幹','唐','御定全唐诗','yuding','','[]','為郡至公兼至察，古今能有幾多人。憂民一似清吟苦，',40,'御定全唐詩/json/652.json','["為郡至公兼至察，古今能有幾多人。憂民一似清吟苦，", "潛夫豈合幹旌旆，甘棹漁舟下釣綸。"]'),
('yuding-9','桐廬江閣','方幹','唐','御定全唐诗','yuding','','[]','風煙百變無定態，緬想畫人虛損心。卷箔檻前沙鳥散，',40,'御定全唐詩/json/652.json','["風煙百變無定態，緬想畫人虛損心。卷箔檻前沙鳥散，", "此地四時拋不得，非唯盛暑事開襟。"]'),
('yuding-10','題澄聖塔院上方','方幹','唐','御定全唐诗','yuding','','[]','地靈直是饒風雨，杉檜老于雲雨間。只訝窗中常見海，',40,'御定全唐詩/json/652.json','["地靈直是饒風雨，杉檜老于雲雨間。只訝窗中常見海，", "若把重門諭玄寂，何妨善閉卻無關。"]'),
('yuding-11','僧院小泉井','方幹','唐','御定全唐诗','yuding','','[]','亦恐淺深同禹穴，兼雲制度象汙樽。窺尋未見泉來路，',40,'御定全唐詩/json/652.json','["亦恐淺深同禹穴，兼雲制度象汙樽。窺尋未見泉來路，", "欲知到底無塵染，堪與吾師比性源。"]'),
('yuding-12','過姚監故居','方幹','唐','御定全唐诗','yuding','','[]','不敢要君征亦起，致君全得似唐虞。讜言昨歎離天聽，',40,'御定全唐詩/json/652.json','["不敢要君征亦起，致君全得似唐虞。讜言昨歎離天聽，", "學書弟子何人在，檢點猶逢諫草無。"]'),
('yuding-13','陪李郎中夜宴','方幹','唐','御定全唐诗','yuding','','[]','間世星郎夜宴時，丁丁寒漏滴聲稀。琵琶弦促千般語，',40,'御定全唐詩/json/652.json','["間世星郎夜宴時，丁丁寒漏滴聲稀。琵琶弦促千般語，", "人間有此榮華事，爭遣漁翁戀釣磯。"]'),
('yuding-14','狂寇後上劉尚書','方幹','唐','御定全唐诗','yuding','','[]','孫武傾心與萬夫，削平妖孽在斯須。才施偃月行軍令，',40,'御定全唐詩/json/652.json','["孫武傾心與萬夫，削平妖孽在斯須。才施偃月行軍令，", "聖君爭不酬功業，仗下高懸破賊圖。"]'),
('yuding-15','尚書新創敵樓二首','方幹','唐','御定全唐诗','yuding','','[]','下馬政成無一事，應須勝地過朝昏。笙歌引出桃花洞，',80,'御定全唐詩/json/652.json','["下馬政成無一事，應須勝地過朝昏。笙歌引出桃花洞，", "常聞大廈堪棲息，燕雀心知不敢言。", "異境永為歡樂地，歌鐘夜夜複年年。平明旭日生床底，", "直須分付丹青手，畫出旌幢繞謫仙。"]'),
('yuding-16','贈李郢端公','方幹','唐','御定全唐诗','yuding','','[]','非唯孤峭與世絕，吟處斯須能變通。物外搜羅歸大雅，',40,'御定全唐詩/json/652.json','["非唯孤峭與世絕，吟處斯須能變通。物外搜羅歸大雅，", "別得人間上升術，丹霄路在五言中。"]'),
('yuding-17','送孫百篇游天臺','方幹','唐','御定全唐诗','yuding','','[]','東南雲路落斜行，入樹穿村見赤城。遠近常時皆藥氣，',40,'御定全唐詩/json/652.json','["東南雲路落斜行，入樹穿村見赤城。遠近常時皆藥氣，", "更有仙花與靈鳥，恐君多半未知名。"]'),
('yuding-18','陸山人畫水','方幹','唐','御定全唐诗','yuding','','[]','毫末用功成一水，水源山脈固難尋。逡巡便可見波浪，',40,'御定全唐詩/json/652.json','["毫末用功成一水，水源山脈固難尋。逡巡便可見波浪，", "我來擬學磻溪叟，白首釣璜非陸沈。"]'),
('yuding-19','郭中山居','方幹','唐','御定全唐诗','yuding','','[]','莫見一瓢離樹上，猶須四壁在林間。沈吟不寐先聞角，',40,'御定全唐詩/json/652.json','["莫見一瓢離樹上，猶須四壁在林間。沈吟不寐先聞角，", "公卿若便遺名姓，卻與禽魚作往還。"]'),
('yuding-20','雪中寄李知誨判官','方幹','唐','御定全唐诗','yuding','','[]','聚散聯翩急複遲，解將華髮兩相欺。雖雲竹重先藏路，',40,'御定全唐詩/json/652.json','["聚散聯翩急複遲，解將華髮兩相欺。雖雲竹重先藏路，", "此時門巷無行跡，塵滿尊罍誰得知。"]'),
('yuding-21','途中言事寄居遠上人','方幹','唐','御定全唐诗','yuding','','[]','舉目時時似故園，鄉心自動向誰言。白雲曉濕寒山寺，',40,'御定全唐詩/json/652.json','["舉目時時似故園，鄉心自動向誰言。白雲曉濕寒山寺，", "羨師了達無牽束，竹徑生苔掩竹門。"]'),
('yuding-22','雪中寄薛郎中','方幹','唐','御定全唐诗','yuding','','[]','野禽未覺巢枝仄，稚子先憂徑竹摧。半夜忽明非月午，',40,'御定全唐詩/json/652.json','["野禽未覺巢枝仄，稚子先憂徑竹摧。半夜忽明非月午，", "深擁紅爐聽仙樂，忍教愁坐畫寒灰。"]'),
('yuding-23','題盛令新亭','方幹','唐','御定全唐诗','yuding','','[]','舉目豈知新智慧，存思便是小天臺。偶嘗嘉果求枝去，',40,'御定全唐詩/json/652.json','["舉目豈知新智慧，存思便是小天臺。偶嘗嘉果求枝去，", "此中難遇逍遙事，計日應為印綬催。"]'),
('yuding-24','贈鄭仁規','方幹','唐','御定全唐诗','yuding','','[]','一石雄才獨佔難，應分二鬥借人寰。澄心不出風騷外，',40,'御定全唐詩/json/652.json','["一石雄才獨佔難，應分二鬥借人寰。澄心不出風騷外，", "可憐麗句能飛動，荀宋精靈亦厚顏。"]'),
('yuding-25','送縉陵王少府赴舉','方幹','唐','御定全唐诗','yuding','','[]','相看不忍盡離觴，五兩牽風速去檣。遠驛新砧應弄月，',40,'御定全唐詩/json/652.json','["相看不忍盡離觴，五兩牽風速去檣。遠驛新砧應弄月，", "珍重郤家好兄弟，明年祿位在何方。"]'),
('yuding-26','路入剡中作','方幹','唐','御定全唐诗','yuding','','[]','截灣沖瀨片帆通，高枕微吟到剡中。掠草並飛憐燕子，',40,'御定全唐詩/json/652.json','["截灣沖瀨片帆通，高枕微吟到剡中。掠草並飛憐燕子，", "便擬乘槎應去得，仙源直恐接星東。"]'),
('yuding-27','東山瀑布','方幹','唐','御定全唐诗','yuding','','[]','遙夜看來疑月照，平明失去被雲迷。掛岩遠勢穿松島，',40,'御定全唐詩/json/652.json','["遙夜看來疑月照，平明失去被雲迷。掛岩遠勢穿松島，", "不緣真宰能開決，應向前山雜淤泥。"]'),
('yuding-28','水墨松石','方幹','唐','御定全唐诗','yuding','','[]','三世精能舉世無，筆端狼藉見功夫。添來勢逸陰崖黑，',40,'御定全唐詩/json/652.json','["三世精能舉世無，筆端狼藉見功夫。添來勢逸陰崖黑，", "蘭堂坐久心彌惑，不道山川是畫圖。"]'),
('yuding-29','獻浙東王大夫二首','方幹','唐','御定全唐诗','yuding','','[]','出鎮當時移越俗，致君何日不堯年。到來唯飲長溪水，',80,'御定全唐詩/json/652.json','["出鎮當時移越俗，致君何日不堯年。到來唯飲長溪水，", "四方皆是分憂寄，獨有東南戴二天。", "王臣夷夏仰清名，領鎮猶為失意行。已見玉璜曾上釣，", "泥滓雲霄至懸闊，漁翁不合見公卿。"]'),
('yuding-30','越州使院竹','方幹','唐','御定全唐诗','yuding','','[]','莫見淩風飄粉籜，須知礙石作盤根。細看枝上蟬吟處，',40,'御定全唐詩/json/652.json','["莫見淩風飄粉籜，須知礙石作盤根。細看枝上蟬吟處，", "列仙終日逍遙地，鳥雀潛來不敢喧。"]'),
('yuding-31','題贈李校書','方幹','唐','御定全唐诗','yuding','','[]','名場失手一年年，月桂嘗聞到手邊。誰道高情偏似鶴，',40,'御定全唐詩/json/652.json','["名場失手一年年，月桂嘗聞到手邊。誰道高情偏似鶴，", "卻是偶然行未到，元來有路上寥天。"]'),
('yuding-32','送王侍郎浙東入朝','方幹','唐','御定全唐诗','yuding','','[]','自將苦節酬清秩，肯要龐眉一個錢。恩愛已蘇句踐國，',40,'御定全唐詩/json/652.json','["自將苦節酬清秩，肯要龐眉一個錢。恩愛已蘇句踐國，", "密奏無非經濟術，從容幾刻在爐煙。"]'),
('yuding-33','贈黃處士','方幹','唐','御定全唐诗','yuding','','[]','閉戶先生無是非，竹灣松樹藕苗衣。愁吟密雪思難盡，',40,'御定全唐詩/json/652.json','["閉戶先生無是非，竹灣松樹藕苗衣。愁吟密雪思難盡，", "到頭苦節終何益，空改文星作少微。"]'),
('yuding-34','獻王大夫二首','方幹','唐','御定全唐诗','yuding','','[]','都緣聲價振皇州，高臥中條不自由。早副急征來鳳沼，',80,'御定全唐詩/json/652.json','["都緣聲價振皇州，高臥中條不自由。早副急征來鳳沼，", "必恐借留終不遂，越人相顧已先愁。", "功成猶自更行春，塞路旌旗十裏塵。只用篇章為教化，", "歷任聖朝清峻地，至今依是少年身。"]'),
('yuding-35','贈五牙山人洗修白','方幹','唐','御定全唐诗','yuding','','[]','變通唯在片時間，此事全由一粒丹。若取壽長延至易，',40,'御定全唐詩/json/652.json','["變通唯在片時間，此事全由一粒丹。若取壽長延至易，", "篋裏生塵是閑藥，外沾猶可救衰殘。"]'),
('yuding-36','處州獻盧員外','方幹','唐','御定全唐诗','yuding','','[]','才下軺車即歲豐，方知盛德與天通。清聲漸出寰瀛外，',40,'御定全唐詩/json/652.json','["才下軺車即歲豐，方知盛德與天通。清聲漸出寰瀛外，", "直緣後學無功業，不慮文翁不至公。"]'),
('yuding-37','石門瀑布','方幹','唐','御定全唐诗','yuding','','[]','奔傾漱石亦噴苔，此是便隨元化來。長片掛岩輕似練，',40,'御定全唐詩/json/652.json','["奔傾漱石亦噴苔，此是便隨元化來。長片掛岩輕似練，", "直是銀河分派落，兼聞碎滴濺天臺。"]'),
('yuding-38','題仙岩瀑布呈陳明府','方幹','唐','御定全唐诗','yuding','','[]','方知激蹙與噴飛，直恐古今同一時。遠壑流來多石脈，',40,'御定全唐詩/json/652.json','["方知激蹙與噴飛，直恐古今同一時。遠壑流來多石脈，", "聚向山前更誰測，深沉見底是澄漪。"]'),
('yuding-39','贈山陰崔明府','方幹','唐','御定全唐诗','yuding','','[]','用心何況兩衙間，退食孜孜亦不閑。壓酒曬書猶檢點，',40,'御定全唐詩/json/652.json','["用心何況兩衙間，退食孜孜亦不閑。壓酒曬書猶檢點，", "平叔正堪湯餅試，風流不合問年顏。"]'),
('yuding-40','山井','方幹','唐','御定全唐诗','yuding','','[]','灩灩濕光淩竹樹，寥寥清氣襲衣襟。不知測穴通潮信，',40,'御定全唐詩/json/652.json','["灩灩濕光淩竹樹，寥寥清氣襲衣襟。不知測穴通潮信，", "轆轤用智終何益，抱甕遺名亦至今。"]'),
('yuding-41','偶作','方幹','唐','御定全唐诗','yuding','','[]','直為篇章非動眾，遂令軒蓋不經過。未妨溪上泛漁艇，',40,'御定全唐詩/json/652.json','["直為篇章非動眾，遂令軒蓋不經過。未妨溪上泛漁艇，", "若於岩洞求倫類，今古疏愚似我多。"]'),
('yuding-42','賊退後贈劉將軍','方幹','唐','御定全唐诗','yuding','','[]','非唯吳起與穰苴，今古推排盡不如。白馬知無髀上肉，',40,'御定全唐詩/json/652.json','["非唯吳起與穰苴，今古推排盡不如。白馬知無髀上肉，", "功業更多身轉貴，佇看幢節引戎車。"]'),
('yuding-43','感時三首','方幹','唐','御定全唐诗','yuding','','[]','不覺年華似箭流，朝看春色暮逢秋。正嗟新塚垂青草，',120,'御定全唐詩/json/652.json','["不覺年華似箭流，朝看春色暮逢秋。正嗟新塚垂青草，", "破除生死須齊物，誰向穹蒼問事由。", "日烏往返無休息，朝出扶桑暮卻回。夜雨旋驅殘熱去，", "莫恃少年欺白首，須臾還被老相催。", "世途擾擾複憧憧，真恐華夷事亦同。歲月自消寒暑內，", "堪笑愚夫足紛競，不知流水去無窮。"]'),
('yuding-44','牡丹','方幹','唐','御定全唐诗','yuding','','[]','不逢盛暑不沖寒，種子成叢用法難。醉眼若為拋去得，',40,'御定全唐詩/json/652.json','["不逢盛暑不沖寒，種子成叢用法難。醉眼若為拋去得，", "莫道嬌紅怕風雨，經時猶自未凋殘。"]'),
('yuding-45','贈進士章碣','方幹','唐','御定全唐诗','yuding','','[]','織錦雖雲用舊機，抽梭起樣更新奇。何如且破望中葉，',40,'御定全唐詩/json/652.json','["織錦雖雲用舊機，抽梭起樣更新奇。何如且破望中葉，", "此時才子吟應苦，吟苦鬼神知不知。"]'),
('yuding-46','與桐廬鄭明府','方幹','唐','御定全唐诗','yuding','','[]','字人心苦達神明，何止重門夜不扃。莫道耕田全種秫，',40,'御定全唐詩/json/652.json','["字人心苦達神明，何止重門夜不扃。莫道耕田全種秫，", "卻恐南山盡無石，南山有石合為銘。"]'),
('yuding-47','謝王大夫奏表','方幹','唐','御定全唐诗','yuding','','[]','非唯言下變榮衰，大海可傾山可移。如剖夜光歸暗室，',40,'御定全唐詩/json/652.json','["非唯言下變榮衰，大海可傾山可移。如剖夜光歸暗室，", "便殺微躬複何益，生成恩重報無期。"]'),
('yuding-48','送道人歸舊岩','方幹','唐','御定全唐诗','yuding','','[]','舊岩終副卻歸期，岩下有人應識師。目睹嬰孩成老叟，',40,'御定全唐詩/json/652.json','["舊岩終副卻歸期，岩下有人應識師。目睹嬰孩成老叟，", "若把古今相比類，姓丁仙鶴亦如斯。"]'),
('yuding-49','送錢特卿赴職天臺','方幹','唐','御定全唐诗','yuding','','[]','路入仙溪氣象清，垂鞭樹石罅中行。霧昏不見西陵岸，',40,'御定全唐詩/json/652.json','["路入仙溪氣象清，垂鞭樹石罅中行。霧昏不見西陵岸，", "詩家弟子無多少，唯只于餘別有情。"]'),
('yuding-50','題新竹','方幹','唐','御定全唐诗','yuding','','[]','青苔劚破植貞堅，細碧竿排鬱眼鮮。小鳳凰聲吹嫩葉，',40,'御定全唐詩/json/652.json','["青苔劚破植貞堅，細碧竿排鬱眼鮮。小鳳凰聲吹嫩葉，", "怪得入門肌骨冷，綴風黏月滿庭前。"]'),
('yuding-51','哭王大夫','方幹','唐','御定全唐诗','yuding','','[]','俗人皆嫉謝臨川，果中常情□□□。為政舊規方利國，',40,'御定全唐詩/json/652.json','["俗人皆嫉謝臨川，果中常情□□□。為政舊規方利國，", "從此心喪應畢世，忍看墳草讀殘篇。"]'),
('yuding-52','贈幹素上人','方幹','唐','御定全唐诗','yuding','','[]','苦用貞心傳弟子，即應低眼看公卿。水中明月無蹤跡，',40,'御定全唐詩/json/652.json','["苦用貞心傳弟子，即應低眼看公卿。水中明月無蹤跡，", "料師多劫長如此，豈算前生與後生。"]'),
('yuding-53','題應天寺上方兼呈謙上人','方幹','唐','御定全唐诗','yuding','','[]','中天坐臥見人寰，峭石垂藤不易攀。晴卷風雷歸故壑，',40,'御定全唐詩/json/652.json','["中天坐臥見人寰，峭石垂藤不易攀。晴卷風雷歸故壑，", "師在西岩最高處，路尋之字見禪關。"]'),
('yuding-54','題法華寺絕頂禪家壁','方幹','唐','御定全唐诗','yuding','','[]','蒼翠岧嶢逼窅冥，下方雷雨上方晴。飛流便向砌邊掛，',40,'御定全唐詩/json/652.json','["蒼翠岧嶢逼窅冥，下方雷雨上方晴。飛流便向砌邊掛，", "只應禪者無來去，坐看千山白髮生。"]'),
('yuding-55','春日','方幹','唐','御定全唐诗','yuding','','[]','春去春來似有期，日高添睡是歸時。雖將細雨催蘆筍，',40,'御定全唐詩/json/652.json','["春去春來似有期，日高添睡是歸時。雖將細雨催蘆筍，", "此時野客因花醉，醉臥花間應不知。"]'),
('yuding-56','上越州楊嚴中丞','方幹','唐','御定全唐诗','yuding','','[]','連枝棣萼世無雙，未秉鴻鈞擁大邦。折桂早聞推獨步，',40,'御定全唐詩/json/652.json','["連枝棣萼世無雙，未秉鴻鈞擁大邦。折桂早聞推獨步，", "試把十年辛苦志，問津求拜碧油幢。"]'),
('yuding-57','月','方幹','唐','御定全唐诗','yuding','','[]','桂輪秋半出東方，巢鵲驚飛夜未央。海上風雲搖皓影，',40,'御定全唐詩/json/652.json','["桂輪秋半出東方，巢鵲驚飛夜未央。海上風雲搖皓影，", "庾亮恃才高更逸，方聞墨翰已成章。"]'),
('yuding-58','早春','方幹','唐','御定全唐诗','yuding','','[]','運行元化不參差，四極中華共一時。正氣才隨灰律變，',40,'御定全唐詩/json/652.json','["運行元化不參差，四極中華共一時。正氣才隨灰律變，", "不信風光疾於箭，年來年去變霜髭。"]'),
('yuding-59','對花','方幹','唐','御定全唐诗','yuding','','[]','清曉入花如步障，戀花行步步遲遲。含風欲綻中心朵，',40,'御定全唐詩/json/652.json','["清曉入花如步障，戀花行步步遲遲。含風欲綻中心朵，", "使君坐處笙歌合，便是列仙身不知。"]'),
('yuding-60','除夜','方幹','唐','御定全唐诗','yuding','','[]','玉漏斯須即達晨，四時吹轉任風輪。寒燈短燼方燒臘，',40,'御定全唐詩/json/652.json','["玉漏斯須即達晨，四時吹轉任風輪。寒燈短燼方燒臘，", "新正定數隨年減，浮世惟應百遍新。"]'),
('yuding-61','題松江驛','方幹','唐','御定全唐诗','yuding','','[]','便向中流出太陽，兼疑大岸逼浮桑。門前白道通丹闕，',40,'御定全唐詩/json/652.json','["便向中流出太陽，兼疑大岸逼浮桑。門前白道通丹闕，", "古今悉不知天意，偏把雲霞媚一方。"]'),
('yuding-62','思桐廬舊居便送鑒上人','方幹','唐','御定全唐诗','yuding','','[]','莫道東南路不賒，思歸一步是天涯。林中夜半雙台月，',40,'御定全唐詩/json/652.json','["莫道東南路不賒，思歸一步是天涯。林中夜半雙台月，", "聞師卻到鄉中去，為我殷勤謝酒家。"]'),
('yuding-63','送僧歸日本','方幹','唐','御定全唐诗','yuding','','[]','四極雖雲共二儀，晦明前後即難知。西方尚在星辰下，',40,'御定全唐詩/json/652.json','["四極雖雲共二儀，晦明前後即難知。西方尚在星辰下，", "滿帆若有歸風便，到岸猶須隔歲期。"]'),
('yuding-64','甯國寺','方幹','唐','御定全唐诗','yuding','','[]','深僻孤高無四鄰，白雲明月自相親。海中日出山先曉，',40,'御定全唐詩/json/652.json','["深僻孤高無四鄰，白雲明月自相親。海中日出山先曉，", "此時惟有雷居士，不厭籃輿去住頻。"]'),
('yuding-0','山中寄吳磻十韻','方幹','唐','御定全唐诗','yuding','','[]','莫問終休否，林中事已成。盤餐憐火種，歲計付刀耕。',120,'御定全唐詩/json/653.json','["莫問終休否，林中事已成。盤餐憐火種，歲計付刀耕。", "掬水皆花氣，聽松似雨聲。書空翹足臥，避險側身行。", "果傍閑軒落，蒲連濕岸生。禪生知見理，妻子笑無名。", "更擬教詩苦，何曾待酒清。石溪魚不大，月樹鵲多驚。", "砌下通樵路，窗間見縣城。雲山任重疊，難隔故交情。"]'),
('yuding-1','嘉興縣內池閣','方幹','唐','御定全唐诗','yuding','','[]','指畫應心成，周回氣象清。床前沙鳥語，案下錦鱗驚。',72,'御定全唐詩/json/653.json','["指畫應心成，周回氣象清。床前沙鳥語，案下錦鱗驚。", "細柳風吹旋，新荷露壓傾。微芳緣岸落，迸筍入波生。", "舴艋舟中醉，莓苔徑上行。高人莫歸去，此處勝蓬瀛。"]'),
('yuding-2','鏡湖西島言事寄陶校書','方幹','唐','御定全唐诗','yuding','','[]','樵獵兩三戶，凋疏是近鄰。風雷前壑雨，花木後岩春。',72,'御定全唐詩/json/653.json','["樵獵兩三戶，凋疏是近鄰。風雷前壑雨，花木後岩春。", "文字不得力，桑麻難救貧。山禽欺稚子，夜犬吠漁人。", "未必聖明代，長將雲水親。知音不延薦，何路出泥塵。"]'),
('yuding-3','贈趙崇侍禦','方幹','唐','御定全唐诗','yuding','','[]','貴達合逢明聖日，風流又及少年時。才因出眾人皆嫉，',48,'御定全唐詩/json/653.json','["貴達合逢明聖日，風流又及少年時。才因出眾人皆嫉，", "卻教鸚鵡呼桃葉，便遣嬋娟唱竹枝。閒話篇章停燭久，"]'),
('yuding-4','敘龍瑞觀勝異寄于尊師','方幹','唐','御定全唐诗','yuding','','[]','混元融結致功難，山下平湖湖上山。萬傾涵虛寒瀲灩，',48,'御定全唐詩/json/653.json','["混元融結致功難，山下平湖湖上山。萬傾涵虛寒瀲灩，", "但有五雲依鶴嶺，曾無陸路向人寰。夜溪漱玉常堪聽，"]'),
('yuding-5','侯郎中新置西湖','方幹','唐','御定全唐诗','yuding','','[]','遠近利民因智力，周回潤物像心源。菰蒲縱感生成惠，',88,'御定全唐詩/json/653.json','["遠近利民因智力，周回潤物像心源。菰蒲縱感生成惠，", "砂泉繞石通山脈，岸木黏萍是浪痕。已見澄來連鏡底，", "煙霧未應藏島嶼，鳧鷖亦解避旌幡。雖雲桃葉歌還醉，", "能將盛事添元化，一夕機謨萬古存。"]'),
('yuding-6','許員外新陽別業','方幹','唐','御定全唐诗','yuding','','[]','蘭汀橘島映亭台，不是經心即手栽。滿閣白雲隨雨去，',72,'御定全唐詩/json/653.json','["蘭汀橘島映亭台，不是經心即手栽。滿閣白雲隨雨去，", "柳絮風前欹枕臥，荷花香裏棹舟回。園中認葉封林草，", "若因螢火終殘卷，便把漁歌送幾杯。多謝郢中賢太守，"]'),
('yuding-7','李侍禦上虞別業','方幹','唐','御定全唐诗','yuding','','[]','滿目亭台嘉木繁，燕蟬吟語不為喧。晝潮勢急吞諸島，',48,'御定全唐詩/json/653.json','["滿目亭台嘉木繁，燕蟬吟語不為喧。晝潮勢急吞諸島，", "若將明月為儔侶，應把清風遺子孫。繡羽驚弓離果上，"]'),
('yuding-8','題懸溜岩隱者居','方幹','唐','御定全唐诗','yuding','','[]','世人如要問生涯，滿架堆床是五車。穀鳥暮蟬聲四散，',72,'御定全唐詩/json/653.json','["世人如要問生涯，滿架堆床是五車。穀鳥暮蟬聲四散，", "卻用水荷苞綠李，兼將寒井浸甘瓜。慣緣嶮峭收松粉，", "坐雲獨酌杯盤濕，穿竹微吟路徑斜。見說公卿訪遺逸，"]'),
('yuding-9','山中言事八韻寄李支使','方幹','唐','御定全唐诗','yuding','','[]','豈知經史深相誤，兩鬢垂絲百事休。受業幾多為弟子，',72,'御定全唐詩/json/653.json','["豈知經史深相誤，兩鬢垂絲百事休。受業幾多為弟子，", "竹裏斷雲來枕上，岩邊片月在床頭。過庭急雨和花落，", "舊詩改處空留韻，新醞嘗來不滿篘。阮瑀如能問寒餒，"]'),
('yuding-10','山中言事寄贈蘇判官','方幹','唐','御定全唐诗','yuding','','[]','寸心似火頻求薦，兩鬢如霜始息機。隔岸雞鳴春耨去，',48,'御定全唐詩/json/653.json','["寸心似火頻求薦，兩鬢如霜始息機。隔岸雞鳴春耨去，", "執爨縱曾炊橡實，紉針曾解補荷衣。常憑早月來張燭，"]'),
('yuding-11','獻王大夫','方幹','唐','御定全唐诗','yuding','','[]','高情不與俗人知，恥學諸生取桂枝。荀宋五言行世早，',72,'御定全唐詩/json/653.json','["高情不與俗人知，恥學諸生取桂枝。荀宋五言行世早，", "一鶚難成燕雀伍，非熊本是帝王師。賢臣雖蘊經邦術，", "直緣材力頭頭贍，專被文星步步隨。不信重言通造化，"]'),
('yuding-12','淺井','方幹','唐','御定全唐诗','yuding','','[]','夜入明河星似少，曙搖澄碧扇風翻。',32,'御定全唐詩/json/653.json','["夜入明河星似少，曙搖澄碧扇風翻。", "細泉細脈難來到，應覺添瓶耗舊痕。"]'),
('yuding-13','與徐溫話別','方幹','唐','御定全唐诗','yuding','','[]','去去何時卻見君，悠悠煙水似天津。',32,'御定全唐詩/json/653.json','["去去何時卻見君，悠悠煙水似天津。", "明年今夜有明月，不是今年看月人。"]'),
('yuding-14','出東陽道中作','方幹','唐','御定全唐诗','yuding','','[]','馬首寒山黛色濃，一重重盡一重重。',32,'御定全唐詩/json/653.json','["馬首寒山黛色濃，一重重盡一重重。", "醉醒已在他人界，猶憶東陽昨夜鐘。"]'),
('yuding-15','酬孫發','方幹','唐','御定全唐诗','yuding','','[]','錦價轉高花更巧，能將舊手弄新梭。',32,'御定全唐詩/json/653.json','["錦價轉高花更巧，能將舊手弄新梭。", "從來一字為褒貶，二十八言猶太多。"]'),
('yuding-16','送鄉中故人','方幹','唐','御定全唐诗','yuding','','[]','少小與君情不疏，聽君細話勝家書。',32,'御定全唐詩/json/653.json','["少小與君情不疏，聽君細話勝家書。", "如今若到鄉中去，道我垂鉤不釣魚。"]'),
('yuding-17','思江南','方幹','唐','御定全唐诗','yuding','','[]','昨日草枯今日青，羈人又動望鄉情。',32,'御定全唐詩/json/653.json','["昨日草枯今日青，羈人又動望鄉情。", "夜來有夢登歸路，不到桐廬已及明。"]'),
('yuding-18','題寶林寺禪者壁','方幹','唐','御定全唐诗','yuding','','[]','邃岩喬木夏藏寒，床下雲溪枕上看。',32,'御定全唐詩/json/653.json','["邃岩喬木夏藏寒，床下雲溪枕上看。", "台殿漸多山更重，卻令飛去即應難。"]'),
('yuding-19','過李群玉故居','方幹','唐','御定全唐诗','yuding','','[]','訐直上書難遇主，銜冤下世未成翁。',32,'御定全唐詩/json/653.json','["訐直上書難遇主，銜冤下世未成翁。", "琴尊劍鶴誰將去，惟鎖山齋一樹風。"]'),
('yuding-20','題玉笥山強處士','方幹','唐','御定全唐诗','yuding','','[]','酒裏藏身岩裏居，刪繁自是一家書。',32,'御定全唐詩/json/653.json','["酒裏藏身岩裏居，刪繁自是一家書。", "世人呼爾為漁叟，爾學釣璜非釣魚。"]'),
('yuding-21','君不來','方幹','唐','御定全唐诗','yuding','','[]','遠路東西欲問誰，寒來無處寄寒衣。',32,'御定全唐詩/json/653.json','["遠路東西欲問誰，寒來無處寄寒衣。", "去時初種庭前樹，樹已勝巢人未歸。"]'),
('yuding-22','經曠禪師舊院','方幹','唐','御定全唐诗','yuding','','[]','穀鳥散啼如有恨，庭花含笑似無情。',32,'御定全唐詩/json/653.json','["穀鳥散啼如有恨，庭花含笑似無情。", "更名變貌難休息，去去來來第幾生。"]'),
('yuding-23','江南聞新曲','方幹','唐','御定全唐诗','yuding','','[]','席上新聲花下杯，一聲聲被拍聲摧。',32,'御定全唐詩/json/653.json','["席上新聲花下杯，一聲聲被拍聲摧。", "樂工不識長安道，儘是書中寄曲來。"]'),
('yuding-24','經故侯郎中舊居','方幹','唐','御定全唐诗','yuding','','[]','一朝寂寂與冥冥，壟樹未長墳草青。',32,'御定全唐詩/json/653.json','["一朝寂寂與冥冥，壟樹未長墳草青。", "高節雄才向何處，夜闌空鎖滿池星。"]'),
('yuding-25','越中逢孫百篇','方幹','唐','御定全唐诗','yuding','','[]','上才乘酒到山陰，日日成篇字字金。',32,'御定全唐詩/json/653.json','["上才乘酒到山陰，日日成篇字字金。", "鏡水周回千萬頃，波瀾倒瀉入君心。"]'),
('yuding-26','寄謝麟','方幹','唐','御定全唐诗','yuding','','[]','越國雲溪秀髮時，蔣京詞賦謝麟詩。',32,'御定全唐詩/json/653.json','["越國雲溪秀髮時，蔣京詞賦謝麟詩。", "後來若要知優劣，學圃無過老圃知。"]'),
('yuding-27','與長洲陳子美長官','方幹','唐','御定全唐诗','yuding','','[]','枕上愁多百緒牽，常時睡覺在溪前。',32,'御定全唐詩/json/653.json','["枕上愁多百緒牽，常時睡覺在溪前。", "人前儘是交親力，莫道升沈總信天。"]'),
('yuding-28','新安殷明府家樂方響','方幹','唐','御定全唐诗','yuding','','[]','葛溪鐵片梨園調，耳底丁東十六聲。',32,'御定全唐詩/json/653.json','["葛溪鐵片梨園調，耳底丁東十六聲。", "彭澤主人憐妙樂，玉杯春暖許同傾。"]'),
('yuding-29','別殷明府','方幹','唐','御定全唐诗','yuding','','[]','許教門館久踟躕，仲叔懷恩對玉壺。',32,'御定全唐詩/json/653.json','["許教門館久踟躕，仲叔懷恩對玉壺。", "唯有離心欲銷客，空垂雙淚不成珠。"]'),
('yuding-30','送水墨項處士歸天臺','方幹','唐','御定全唐诗','yuding','','[]','仙嶠倍分元化功，揉藍翠色一重重。',32,'御定全唐詩/json/653.json','["仙嶠倍分元化功，揉藍翠色一重重。", "還家莫更尋山水，自有雲山在筆峰。"]'),
('yuding-31','贈會稽楊長官','方幹','唐','御定全唐诗','yuding','','[]','直鉤終日竟無魚，鐘鼓聲中與世疏。',32,'御定全唐詩/json/653.json','["直鉤終日竟無魚，鐘鼓聲中與世疏。", "若向湖邊訪幽拙，蕭條四壁是閒居。"]'),
('yuding-32','贈申長官','方幹','唐','御定全唐诗','yuding','','[]','言下隨機見物情，看看獄路草還生。',32,'御定全唐詩/json/653.json','["言下隨機見物情，看看獄路草還生。", "旅人莫怪無魚食，直為寒江水至清。"]'),
('yuding-33','將歸湖上留別陳宰','方幹','唐','御定全唐诗','yuding','','[]','歸去春山逗晚晴，縈回樹石罅中行。',32,'御定全唐詩/json/653.json','["歸去春山逗晚晴，縈回樹石罅中行。", "明時不是無知己，自憶湖邊釣與耕。"]'),
('yuding-34','貽亮上人','方幹','唐','御定全唐诗','yuding','','[]','秋水一泓常見底，澗松千尺不生枝。',32,'御定全唐詩/json/653.json','["秋水一泓常見底，澗松千尺不生枝。", "人間學佛知多少，淨盡心花只有師。"]'),
('yuding-35','貽曦上人','方幹','唐','御定全唐诗','yuding','','[]','四十年來多少人，一分零落九成塵。',32,'御定全唐詩/json/653.json','["四十年來多少人，一分零落九成塵。", "與師猶得重相見，亦是枯株勉強春。"]'),
('yuding-36','書原上鮑處士屋壁','方幹','唐','御定全唐诗','yuding','','[]','水闊坐看千萬里，青蕪蓋地接天津。',32,'御定全唐詩/json/653.json','["水闊坐看千萬里，青蕪蓋地接天津。", "禰衡莫愛山中靜，繞舍山多卻礙人。"]'),
('yuding-37','別孫蜀','方幹','唐','御定全唐诗','yuding','','[]','吳越思君意易傷，別君添我鬢邊霜。',32,'御定全唐詩/json/653.json','["吳越思君意易傷，別君添我鬢邊霜。", "由來浙水偏堪恨，截斷千山作兩鄉。"]'),
('yuding-38','贈江上老人','方幹','唐','御定全唐诗','yuding','','[]','潭底錦鱗多識釣，未投香餌即先知。',32,'御定全唐詩/json/653.json','["潭底錦鱗多識釣，未投香餌即先知。", "欲教魚目無分別，須學揉藍染釣絲。"]'),
('yuding-39','贈東溪貧道','方幹','唐','御定全唐诗','yuding','','[]','非唯劍鶴獨難留，觸事皆聞被債收。',32,'御定全唐詩/json/653.json','["非唯劍鶴獨難留，觸事皆聞被債收。", "賴是豪家念寒餒，卻還漁島與漁舟。"]'),
('yuding-40','詠花','方幹','唐','御定全唐诗','yuding','','[]','狂心醉眼共裴回，一半先開笑未開。',32,'御定全唐詩/json/653.json','["狂心醉眼共裴回，一半先開笑未開。", "此日不能偷折去，胡蜂直恐趁人來。"]'),
('yuding-41','路入金州江中作','方幹','唐','御定全唐诗','yuding','','[]','棹尋椒岸縈回去，數裏時逢一兩家。',32,'御定全唐詩/json/653.json','["棹尋椒岸縈回去，數裏時逢一兩家。", "知是從來貢金處，江邊牧豎亦披沙。"]'),
('yuding-42','夜會鄭氏昆季林亭','方幹','唐','御定全唐诗','yuding','','[]','捲簾圓月照方塘，坐久尊空竹有霜。',32,'御定全唐詩/json/653.json','["捲簾圓月照方塘，坐久尊空竹有霜。", "白犬吠風驚雁起，猶能一一旋成行。"]'),
('yuding-43','題黃山人庭前孤桂','方幹','唐','御定全唐诗','yuding','','[]','映窗孤桂非手植，子落月中聞落時。',32,'御定全唐詩/json/653.json','["映窗孤桂非手植，子落月中聞落時。", "仙客此時頭不白，看來看去有枯枝。"]'),
('yuding-44','送僧南游','方幹','唐','御定全唐诗','yuding','','[]','三秋萬里五溪行，風裏孤雲不計程。',32,'御定全唐詩/json/653.json','["三秋萬里五溪行，風裏孤雲不計程。", "若念猩猩解言語，放生先合放猩猩。"]'),
('yuding-45','惜花','方幹','唐','御定全唐诗','yuding','','[]','可憐妍豔正當時，剛被狂風一夜吹。',32,'御定全唐詩/json/653.json','["可憐妍豔正當時，剛被狂風一夜吹。", "今日流鶯來舊處，百般言語殢空枝。"]'),
('yuding-46','題天柱觀魚尊師舊院','方幹','唐','御定全唐诗','yuding','','[]','早識吾師頻到此，芝童藥犬亦相迎。',32,'御定全唐詩/json/653.json','["早識吾師頻到此，芝童藥犬亦相迎。", "今師一去無來日，花洞石壇空月明。"]'),
('yuding-47','東陽道中作','方幹','唐','御定全唐诗','yuding','','[]','百花香氣傍行人，花底垂鞭日易醺。',32,'御定全唐詩/json/653.json','["百花香氣傍行人，花底垂鞭日易醺。", "野父不知寒食節，穿林轉壑自燒雲。"]'),
('yuding-48','題畫建溪圖','方幹','唐','御定全唐诗','yuding','','[]','六幅輕綃畫建溪，刺桐花下路高低。',32,'御定全唐詩/json/653.json','["六幅輕綃畫建溪，刺桐花下路高低。", "分明記得曾行處，只欠猿聲與鳥啼。"]'),
('yuding-49','蜀中','方幹','唐','御定全唐诗','yuding','','[]','遊子去游多不歸，春風酒味勝餘時。',32,'御定全唐詩/json/653.json','["遊子去游多不歸，春風酒味勝餘時。", "閑來卻伴巴兒醉，豆蔻花邊唱竹枝。"]'),
('yuding-50','衢州別李秀才','方幹','唐','御定全唐诗','yuding','','[]','千山紅樹萬山雲，把酒相看日又曛。',32,'御定全唐詩/json/653.json','["千山紅樹萬山雲，把酒相看日又曛。", "一曲驪歌兩行淚，更知何處再逢君。"]'),
('yuding-51','題君山','方幹','唐','御定全唐诗','yuding','','[]','曾于方外見麻姑，聞說君山自古無。',32,'御定全唐詩/json/653.json','["曾于方外見麻姑，聞說君山自古無。", "元是昆侖山頂石，海風吹落洞庭湖。"]'),
('yuding-52','題嚴子陵祠二首','方幹','唐','御定全唐诗','yuding','','[]','物色旁求至漢庭，一宵同寢見交情。',64,'御定全唐詩/json/653.json','["物色旁求至漢庭，一宵同寢見交情。", "先生不入雲台像，贏得桐江萬古名。", "蒼翠雲峰開俗眼，泓澄煙水浸塵心。", "惟將道業為芳餌，釣得高名直到今。"]'),
('yuding-53','失題','方幹','唐','御定全唐诗','yuding','','[]','十六聲中運手輕，一聲聲似自然聲。',32,'御定全唐詩/json/653.json','["十六聲中運手輕，一聲聲似自然聲。", "不緣精妙過流輩，爭得江南別有名。"]'),
('yuding-54','句','方幹','唐','御定全唐诗','yuding','','[]','弟子已攀桂，先生猶臥雲。',56,'御定全唐詩/json/653.json','["弟子已攀桂，先生猶臥雲。", "把得新詩草裏論。（幹師徐凝，常刺凝云云，", "枯井夜聞鄰果落，廢巢寒見別禽來。（貽天目中峰客，"]'),
('yuding-0','歲仗','羅鄴','唐','御定全唐诗','yuding','','[]','玉帛朝元萬國來，雞人曉唱五門開。春排北極迎仙馭，',40,'御定全唐詩/json/654.json','["玉帛朝元萬國來，雞人曉唱五門開。春排北極迎仙馭，", "可憐四海車書共，重見蕭曹佐漢材。"]'),
('yuding-1','牡丹','羅鄴','唐','御定全唐诗','yuding','','[]','落盡春紅始著花，花時比屋事豪奢。買栽池館恐無地，',40,'御定全唐詩/json/654.json','["落盡春紅始著花，花時比屋事豪奢。買栽池館恐無地，", "歌鐘滿座爭歡賞，肯信流年鬢有華。"]'),
('yuding-2','長城','羅鄴','唐','御定全唐诗','yuding','','[]','當時無德禦乾坤，廣築徒勞萬古存。謾役生民防極塞，',40,'御定全唐詩/json/654.json','["當時無德禦乾坤，廣築徒勞萬古存。謾役生民防極塞，", "降虜至今猶自說，冤聲夜夜傍城根。"]'),
('yuding-3','秋夕寄友人','羅鄴','唐','御定全唐诗','yuding','','[]','秋夕蒼茫一雁過，西風白露滿宮莎。昨來京洛逢歸客，',40,'御定全唐詩/json/654.json','["秋夕蒼茫一雁過，西風白露滿宮莎。昨來京洛逢歸客，", "想君懷抱哀吟夜，銅雀台前皓月多。"]'),
('yuding-4','冬夕江上言事五首','羅鄴','唐','御定全唐诗','yuding','','[]','葉落才悲草又生，看看少壯是衰形。關中秋雨書難到，',192,'御定全唐詩/json/654.json','["葉落才悲草又生，看看少壯是衰形。關中秋雨書難到，", "幾時拋得歸山去，松下看雲讀道經。", "喔喔晨雞滿樹霜，喧喧曉渡簇舟航。數星昨夜寒爐火，", "逢人舉止皆言命，至竟謀閑可勝忙。", "野堂吟罷獨行行，點水微微凍不鳴。十裏溪山新雪後，", "日苦幾多心下見，那堪歲晏又無成。", "僻居多與懶相宜，吟擁寒爐過臘時。風柳欲生陽面葉，", "賴有陶情一尊酒，愁中相向展愁眉。", "一帶長溪淥浸門，數聲幽鳥啄雲根。", "松亭盡日唯空坐，難得儒翁共討論。"]'),
('yuding-5','春日宿崇賢裏','羅鄴','唐','御定全唐诗','yuding','','[]','柳暗榆飛春日深，水邊門巷獨來尋。舊山共是經年別，',40,'御定全唐詩/json/654.json','["柳暗榆飛春日深，水邊門巷獨來尋。舊山共是經年別，", "勞歌莫問秋風計，恐起江河垂釣心。"]'),
('yuding-6','征人','羅鄴','唐','御定全唐诗','yuding','','[]','青樓一別戍金微，力盡秋來破虜圍。錦字莫辭連夜織，',40,'御定全唐詩/json/654.json','["青樓一別戍金微，力盡秋來破虜圍。錦字莫辭連夜織，", "唯有夢魂南去日，故鄉山水路依稀。"]'),
('yuding-7','鶯','羅鄴','唐','御定全唐诗','yuding','','[]','暖辭雲穀背殘陽，飛下東風翅漸長。卻笑金籠是羈絆，',40,'御定全唐詩/json/654.json','["暖辭雲穀背殘陽，飛下東風翅漸長。卻笑金籠是羈絆，", "何事離人不堪聽，灞橋斜日嫋垂楊。"]'),
('yuding-8','槐花','羅鄴','唐','御定全唐诗','yuding','','[]','行宮門外陌銅駝，兩畔分栽此最多。欲到清秋近時節，',40,'御定全唐詩/json/654.json','["行宮門外陌銅駝，兩畔分栽此最多。欲到清秋近時節，", "愁殺江湖隨計者，年年為爾剩奔波。"]'),
('yuding-9','自蜀入關','羅鄴','唐','御定全唐诗','yuding','','[]','文戰連輸未息機，束書攜劍定前非。近來從聽事難得，',40,'御定全唐詩/json/654.json','["文戰連輸未息機，束書攜劍定前非。近來從聽事難得，", "斜陽驛路西風緊，遙指人煙宿翠微。"]'),
('yuding-10','上陽宮','羅鄴','唐','御定全唐诗','yuding','','[]','春半上陽花滿樓，太平天子昔巡遊。千門雖對嵩山在，',40,'御定全唐詩/json/654.json','["春半上陽花滿樓，太平天子昔巡遊。千門雖對嵩山在，", "翠華卻自登仙去，腸斷宮娥望不休。"]'),
('yuding-11','舊侯家','羅鄴','唐','御定全唐诗','yuding','','[]','台閣層層倚半空，繞軒澄碧禦溝通。金鈿座上歌春酒，',40,'御定全唐詩/json/654.json','["台閣層層倚半空，繞軒澄碧禦溝通。金鈿座上歌春酒，", "人間若算無榮辱，卻是扁舟一釣翁。"]'),
('yuding-12','宿武安山有懷','羅鄴','唐','御定全唐诗','yuding','','[]','野店暮來山畔逢，寒蕪漠漠露華濃。窗間燈在犬驚吠，',40,'御定全唐詩/json/654.json','["野店暮來山畔逢，寒蕪漠漠露華濃。窗間燈在犬驚吠，", "離心卻羨南飛翼，獨過吳江更數重。"]'),
('yuding-13','謁甯祠','羅鄴','唐','御定全唐诗','yuding','','[]','春生溪嶺雪初開，下馬雲亭酹一杯。好是精靈偏有感，',40,'御定全唐詩/json/654.json','["春生溪嶺雪初開，下馬雲亭酹一杯。好是精靈偏有感，", "盡室唯求多降福，新年歸去便風催。"]'),
('yuding-14','經故洛城','羅鄴','唐','御定全唐诗','yuding','','[]','一片危牆勢恐人，牆邊日日走蹄輪。築時驅盡千夫力，',40,'御定全唐詩/json/654.json','["一片危牆勢恐人，牆邊日日走蹄輪。築時驅盡千夫力，", "那堪又向荒城過，錦雉驚飛麥隴春。"]'),
('yuding-15','老將','羅鄴','唐','御定全唐诗','yuding','','[]','百戰辛勤歸帝鄉，南班班裏最南行。弓欺猿臂秋無力，',40,'御定全唐詩/json/654.json','["百戰辛勤歸帝鄉，南班班裏最南行。弓欺猿臂秋無力，", "年年宿衛天顏近，曾把功勳奏建章。"]'),
('yuding-16','曲江春望','羅鄴','唐','御定全唐诗','yuding','','[]','故國東歸澤國遙，曲江晴望憶漁樵。都緣北闕春先到，',40,'御定全唐詩/json/654.json','["故國東歸澤國遙，曲江晴望憶漁樵。都緣北闕春先到，", "雖然未得陪鴛鴦，亦酹金觴祝帝堯。"]'),
('yuding-17','帝裏','羅鄴','唐','御定全唐诗','yuding','','[]','喧喧蹄轂走紅塵，南北東西暮與晨。謾道青雲難得路，',40,'御定全唐詩/json/654.json','["喧喧蹄轂走紅塵，南北東西暮與晨。謾道青雲難得路，", "只合詠歌來大國，況逢文景化惟新。"]'),
('yuding-18','新安城','羅鄴','唐','御定全唐诗','yuding','','[]','若算防邊久遠名，新安豈更勝長城。謾興他役悲荒壘，',40,'御定全唐詩/json/654.json','["若算防邊久遠名，新安豈更勝長城。謾興他役悲荒壘，", "但將死節酬堯禹，版築無勞寇已平。"]'),
('yuding-19','自遣','羅鄴','唐','御定全唐诗','yuding','','[]','四十年來詩酒徒，一生緣興滯江湖。不愁世上無人識，',40,'御定全唐詩/json/654.json','["四十年來詩酒徒，一生緣興滯江湖。不愁世上無人識，", "焚魚酌醴醉堯代，吟向席門聊自娛。"]'),
('yuding-20','流水','羅鄴','唐','御定全唐诗','yuding','','[]','漾漾悠悠幾派分，中浮短艇與鷗群。天街帶雨淹芳草，',40,'御定全唐詩/json/654.json','["漾漾悠悠幾派分，中浮短艇與鷗群。天街帶雨淹芳草，", "隋家柳畔偏堪恨，東入長淮日又曛。"]'),
('yuding-21','送張逸人','羅鄴','唐','御定全唐诗','yuding','','[]','自說歸山人事賒，素琴丹灶是生涯。床頭殘藥鼠偷盡，',40,'御定全唐詩/json/654.json','["自說歸山人事賒，素琴丹灶是生涯。床頭殘藥鼠偷盡，", "遙知此去應稀出，獨臥晴窗夢曉霞。"]'),
('yuding-22','春晚渡河有懷','羅鄴','唐','御定全唐诗','yuding','','[]','煙收綠野遠連空，戍壘依稀入望中。萬里山河星拱北，',40,'御定全唐詩/json/654.json','["煙收綠野遠連空，戍壘依稀入望中。萬里山河星拱北，", "鄉思正多羈思苦，不須回首問漁翁。"]'),
('yuding-23','春望梁石頭城','羅鄴','唐','御定全唐诗','yuding','','[]','柳碧桑黃破國春，殘陽微雨望歸人。江山不改興亡地，',40,'御定全唐詩/json/654.json','["柳碧桑黃破國春，殘陽微雨望歸人。江山不改興亡地，", "六朝無限悲愁事，欲下荒城回首頻。"]'),
('yuding-24','早發宜陵即事','羅鄴','唐','御定全唐诗','yuding','','[]','霜白山村月落時，一聲雞後又登岐。居人猶自掩關在，',40,'御定全唐詩/json/654.json','["霜白山村月落時，一聲雞後又登岐。居人猶自掩關在，", "青萍委匣休哮吼，未有恩仇擬報誰。"]'),
('yuding-25','鴛鴦','羅鄴','唐','御定全唐诗','yuding','','[]','紅閑碧霽瑞煙開，錦翅雙飛去又回。一種鳥憐名字好，',40,'御定全唐詩/json/654.json','["紅閑碧霽瑞煙開，錦翅雙飛去又回。一種鳥憐名字好，", "相對若教春女見，便須攜向鳳凰台。"]'),
('yuding-26','春閨','羅鄴','唐','御定全唐诗','yuding','','[]','愁坐蘭閨日過遲，捲簾巢燕羨雙飛。管弦樓上春應在，',40,'御定全唐詩/json/654.json','["愁坐蘭閨日過遲，捲簾巢燕羨雙飛。管弦樓上春應在，", "梨花滿院東風急，惆悵無言倚錦機。"]'),
('yuding-27','贈東川梓桐縣韋德孫長官','羅鄴','唐','御定全唐诗','yuding','','[]','前代高門今宰邑，懷才重義古來無。笙歌厭聽吟清句，',40,'御定全唐詩/json/654.json','["前代高門今宰邑，懷才重義古來無。笙歌厭聽吟清句，", "何年期拜朱幡貴，馬上論詩在九衢。"]'),
('yuding-28','題水簾洞','羅鄴','唐','御定全唐诗','yuding','','[]','亂泉飛下翠屏中，名共真珠巧綴同。一片長垂今與古，',40,'御定全唐詩/json/654.json','["亂泉飛下翠屏中，名共真珠巧綴同。一片長垂今與古，", "每向暑天來往見，疑將仙子隔房櫳。"]'),
('yuding-29','野花','羅鄴','唐','御定全唐诗','yuding','','[]','拂露叢開血色殷，枉無名字對空山。時逢舞蝶尋香至，',40,'御定全唐詩/json/654.json','["拂露叢開血色殷，枉無名字對空山。時逢舞蝶尋香至，", "結根畢竟輸桃李，長近都城紫陌間。"]'),
('yuding-30','蘆花','羅鄴','唐','御定全唐诗','yuding','','[]','如練如霜幹複輕，西風處處拂江城。長垂釣叟看不足，',40,'御定全唐詩/json/654.json','["如練如霜幹複輕，西風處處拂江城。長垂釣叟看不足，", "最宜群鷺斜陽裏，閑捕纖鱗傍爾行。"]'),
('yuding-31','山陽貽友人','羅鄴','唐','御定全唐诗','yuding','','[]','性僻多將雲水便，山陽酒病動經年。行遲暖陌花攔馬，',40,'御定全唐詩/json/654.json','["性僻多將雲水便，山陽酒病動經年。行遲暖陌花攔馬，", "結茅更莫期深隱，聲價如今滿日邊。"]'),
('yuding-32','長安惜春','羅鄴','唐','御定全唐诗','yuding','','[]','千門共惜放春回，半鎖樓臺半複開。公子不能留落日，',40,'御定全唐詩/json/654.json','["千門共惜放春回，半鎖樓臺半複開。公子不能留落日，", "畢竟思量何足歎，明年時節又還來。"]'),
('yuding-33','謝友人遺華陽巾','羅鄴','唐','御定全唐诗','yuding','','[]','剪露裁煙勝角冠，來從玉洞五雲端。醉宜薤葉欹斜影，',40,'御定全唐詩/json/654.json','["剪露裁煙勝角冠，來從玉洞五雲端。醉宜薤葉欹斜影，", "真仙首飾勞相寄，塵土翻慚戴去難。"]'),
('yuding-34','早梅','羅鄴','唐','御定全唐诗','yuding','','[]','綴雪枝條似有情，淩寒澹注笑妝成。凍香飄處宜春早，',40,'御定全唐詩/json/654.json','["綴雪枝條似有情，淩寒澹注笑妝成。凍香飄處宜春早，", "滿園桃李雖堪賞，要且東風晚始生。"]'),
('yuding-35','留題張逸人草堂','羅鄴','唐','御定全唐诗','yuding','','[]','長懸青紫與芳枝，塵路無因免別離。馬上多於在家日，',40,'御定全唐詩/json/654.json','["長懸青紫與芳枝，塵路無因免別離。馬上多於在家日，", "卻羨高人此中老，軒車過盡不知誰。"]'),
('yuding-36','鐘陵崔大夫罷鎮攀隨再經匡廬寺宿','羅鄴','唐','御定全唐诗','yuding','','[]','一拋文戰學從公，兩逐旌旗宿梵宮。酒醒月移窗影畔，',40,'御定全唐詩/json/654.json','["一拋文戰學從公，兩逐旌旗宿梵宮。酒醒月移窗影畔，", "明發不堪山下路，幾程愁雨又愁風。"]'),
('yuding-37','留獻彭門郭常侍','羅鄴','唐','御定全唐诗','yuding','','[]','受得彭門擁信旗，一家將謂免羈離。到來門館空歸去，',40,'御定全唐詩/json/654.json','["受得彭門擁信旗，一家將謂免羈離。到來門館空歸去，", "到頭忍恥求名是，須向青雲覓路岐。"]'),
('yuding-38','洛水','羅鄴','唐','御定全唐诗','yuding','','[]','一道潺湲濺暖莎，年年惆悵是春過。莫言行路聽如此，',40,'御定全唐詩/json/654.json','["一道潺湲濺暖莎，年年惆悵是春過。莫言行路聽如此，", "縱然滿眼添歸思，未把漁竿奈爾何。"]'),
('yuding-39','聞杜鵑','羅鄴','唐','御定全唐诗','yuding','','[]','花時一宿碧山前，明月東風叫杜鵑。孤館覺來聽夜半，',40,'御定全唐詩/json/654.json','["花時一宿碧山前，明月東風叫杜鵑。孤館覺來聽夜半，", "爭得蒼蒼知有恨，汝身成鶴我成仙。"]'),
('yuding-40','趁職單于留別闕下知己','羅鄴','唐','御定全唐诗','yuding','','[]','職忝翩翩逐建牙，笈隨征騎入胡沙。定將千里書憑雁，',40,'御定全唐詩/json/654.json','["職忝翩翩逐建牙，笈隨征騎入胡沙。定將千里書憑雁，", "逢秋不擬同張翰，為憶鱸魚卻歎嗟。"]'),
('yuding-41','落第書懷寄友人','羅鄴','唐','御定全唐诗','yuding','','[]','清世誰能便陸沈，相逢休作憶山吟。若教仙桂在平地，',40,'御定全唐詩/json/654.json','["清世誰能便陸沈，相逢休作憶山吟。若教仙桂在平地，", "且安懷抱莫惆悵，瑤瑟調高尊酒深。"]'),
('yuding-42','鸚鵡詠','羅鄴','唐','御定全唐诗','yuding','','[]','玉檻瑤軒任所依，東風休憶嶺頭歸。金籠共惜好毛羽，',40,'御定全唐詩/json/654.json','["玉檻瑤軒任所依，東風休憶嶺頭歸。金籠共惜好毛羽，", "乘時得路何須貴，燕雀鸞凰各有機。"]'),
('yuding-43','題滄浪峽','羅鄴','唐','御定全唐诗','yuding','','[]','門向紅塵日日開，入門襟袖遠塵埃。暗香惹步澗花發，',40,'御定全唐詩/json/654.json','["門向紅塵日日開，入門襟袖遠塵埃。暗香惹步澗花發，", "可憐嚴子持竿處，雲水終年鎖綠苔。"]'),
('yuding-44','白角簟','羅鄴','唐','御定全唐诗','yuding','','[]','疊玉駢珪巧思長，露華煙魄讓清光。休搖雉尾當三伏，',40,'御定全唐詩/json/654.json','["疊玉駢珪巧思長，露華煙魄讓清光。休搖雉尾當三伏，", "杜陵他日重歸去，偏稱醉眠松桂堂。"]'),
('yuding-45','秋日懷江上友人','羅鄴','唐','御定全唐诗','yuding','','[]','行子豈知煙水勞，西風獨自泛征艘。酒醒孤館秋簾卷，',40,'御定全唐詩/json/654.json','["行子豈知煙水勞，西風獨自泛征艘。酒醒孤館秋簾卷，", "去年今日逢君處，雁下蘆花猿正號。"]'),
('yuding-46','題笙','羅鄴','唐','御定全唐诗','yuding','','[]','筠管參差排鳳翅，月堂淒切勝龍吟。最宜輕動纖纖玉，',40,'御定全唐詩/json/654.json','["筠管參差排鳳翅，月堂淒切勝龍吟。最宜輕動纖纖玉，", "好將宮征陪歌扇，莫遣新聲鄭衛侵。"]'),
('yuding-47','下第','羅鄴','唐','御定全唐诗','yuding','','[]','謾把青春酒一杯，愁襟未信酒能開。江邊依舊空歸去，',40,'御定全唐詩/json/654.json','["謾把青春酒一杯，愁襟未信酒能開。江邊依舊空歸去，", "此時惆悵便堪老，何用人間歲月催。"]'),
('yuding-48','秋晚','羅鄴','唐','御定全唐诗','yuding','','[]','殘星殘月一聲鐘，穀際岩隈爽氣濃。不向碧台驚醉夢，',40,'御定全唐詩/json/654.json','["殘星殘月一聲鐘，穀際岩隈爽氣濃。不向碧台驚醉夢，", "閒步幽林與苔徑，漸移棲鳥及鳴蛩。"]'),
('yuding-49','長安春夕旅懷','羅鄴','唐','御定全唐诗','yuding','','[]','幾年棲旅寄西秦，不識花枝醉過春。短艇閑思五湖浪，',40,'御定全唐詩/json/654.json','["幾年棲旅寄西秦，不識花枝醉過春。短艇閑思五湖浪，", "忽向太平時節過，一竿持去老遺民。"]'),
('yuding-50','洛陽春望','羅鄴','唐','御定全唐诗','yuding','','[]','洛陽春霽絕塵埃，嵩少煙嵐畫障開。草色花光惹襟袖，',40,'御定全唐詩/json/654.json','["洛陽春霽絕塵埃，嵩少煙嵐畫障開。草色花光惹襟袖，", "愁上中橋橋上望，碧波東去夕陽催。"]'),
('yuding-51','惜春','羅鄴','唐','御定全唐诗','yuding','','[]','燕歸巢後即離群，吟倚東風恨日曛。一別一年方見我，',40,'御定全唐詩/json/654.json','["燕歸巢後即離群，吟倚東風恨日曛。一別一年方見我，", "獨坐南樓正惆悵，柳塘花絮更紛紛。"]'),
('yuding-52','冬日旅懷','羅鄴','唐','御定全唐诗','yuding','','[]','烏焰才沈桂魄生，霜階擁褐暫吟行。閑思江市白醪滿，',40,'御定全唐詩/json/654.json','["烏焰才沈桂魄生，霜階擁褐暫吟行。閑思江市白醪滿，", "幾多悵望無窮事，空畫爐灰坐到明。"]'),
('yuding-53','春夕寄友人時有與歌者南北','羅鄴','唐','御定全唐诗','yuding','','[]','芳徑春歸花半開，碧山波暖雁初回。滿樓月色還依舊，',40,'御定全唐詩/json/654.json','["芳徑春歸花半開，碧山波暖雁初回。滿樓月色還依舊，", "中宵吟罷正惆悵，從此蘭堂鎖綠苔。"]'),
('yuding-54','春夜赤水驛旅懷','羅鄴','唐','御定全唐诗','yuding','','[]','一星殘燭照離堂，失計遊心歸渺茫。不自尋思無道路，',40,'御定全唐詩/json/654.json','["一星殘燭照離堂，失計遊心歸渺茫。不自尋思無道路，", "卻羨去年買山侶，月斜漁艇倚瀟湘。"]'),
('yuding-55','春山山館旅懷','羅鄴','唐','御定全唐诗','yuding','','[]','山館吟餘山月斜，東風搖曳拂窗華。豈知驅馬無閑日，',40,'御定全唐詩/json/654.json','["山館吟餘山月斜，東風搖曳拂窗華。豈知驅馬無閑日，", "燈前結束又前去，曉出石林啼亂鴉。"]'),
('yuding-56','秋夕旅懷','羅鄴','唐','御定全唐诗','yuding','','[]','階前月色與蛩聲，階上愁人坐複行。秦穀入霜空有夢，',40,'御定全唐詩/json/654.json','["階前月色與蛩聲，階上愁人坐複行。秦穀入霜空有夢，", "不似扁舟釣魚者，免將心事算浮榮。"]'),
('yuding-57','春過白遙嶺','羅鄴','唐','御定全唐诗','yuding','','[]','鳥道穿雲望峽遙，羸蹄經宿在岧嶢。到來山下春將半，',40,'御定全唐詩/json/654.json','["鳥道穿雲望峽遙，羸蹄經宿在岧嶢。到來山下春將半，", "未知遇此悽惶者，泣向東風鬢欲凋。"]'),
('yuding-58','別夜','羅鄴','唐','御定全唐诗','yuding','','[]','秋入江天河漢清，迢迢鐘漏出孤城。金波千里別來夜，',40,'御定全唐詩/json/654.json','["秋入江天河漢清，迢迢鐘漏出孤城。金波千里別來夜，", "人間誰有□□□，聚散自然惆悵生。"]'),
('yuding-59','費拾遺書堂','羅鄴','唐','御定全唐诗','yuding','','[]','滿袖歸來天桂香，紫泥重降舊書堂。自憐葦帶同巢許，',40,'御定全唐詩/json/654.json','["滿袖歸來天桂香，紫泥重降舊書堂。自憐葦帶同巢許，", "何人更肯追高躅，唯有樵童戲蘚床。"]'),
('yuding-60','溪上春望','羅鄴','唐','御定全唐诗','yuding','','[]','無端溪上看蘭橈，又是東風斷柳條。雙鬢多於愁裏鑷，',40,'御定全唐詩/json/654.json','["無端溪上看蘭橈，又是東風斷柳條。雙鬢多於愁裏鑷，", "吟水詠山心未已，可能終不勝漁樵。"]'),
('yuding-61','獻池州庾員外','羅鄴','唐','御定全唐诗','yuding','','[]','曾降瑤緘薦姓名，攀雲幾合到蓬瀛。須存彭壽千年在，',40,'御定全唐詩/json/654.json','["曾降瑤緘薦姓名，攀雲幾合到蓬瀛。須存彭壽千年在，", "琪花玉蔓應相笑，未得歌吟從酒行。"]'),
('yuding-62','春風','羅鄴','唐','御定全唐诗','yuding','','[]','每歲東來助發生，舞空悠颺遍寰瀛。暗添芳草池塘色，',40,'御定全唐詩/json/654.json','["每歲東來助發生，舞空悠颺遍寰瀛。暗添芳草池塘色，", "如何一瑞車書日，吹取青雲道路平。"]'),
('yuding-63','冬日寄獻庾員外','羅鄴','唐','御定全唐诗','yuding','','[]','曾謁仙宮最上仙，西風許醉桂花前。爭歡酒蟻浮金爵，',40,'御定全唐詩/json/654.json','["曾謁仙宮最上仙，西風許醉桂花前。爭歡酒蟻浮金爵，", "卻思紫陌觥籌地，兔缺烏沈欲半年。"]'),
('yuding-64','釣翁','羅鄴','唐','御定全唐诗','yuding','','[]','來往煙波非定居，生涯蓑褐外無餘。閑垂兩鬢任如鶴，',40,'御定全唐詩/json/654.json','["來往煙波非定居，生涯蓑褐外無餘。閑垂兩鬢任如鶴，", "行人誤話金張貴，笑指北邙丘與墟。"]'),
('yuding-65','聞友人入越幕因以詩贈','羅鄴','唐','御定全唐诗','yuding','','[]','稽嶺春生酒凍銷，煙鬟紅袖恃嬌饒。岸邊叢雪晴香老，',40,'御定全唐詩/json/654.json','["稽嶺春生酒凍銷，煙鬟紅袖恃嬌饒。岸邊叢雪晴香老，", "人間榮瘁真堪恨，坐想征軒鬢欲凋。"]'),
('yuding-66','東歸','羅鄴','唐','御定全唐诗','yuding','','[]','日日唯憂行役遲，東歸可是有家歸。都緣桂玉無門住，',40,'御定全唐詩/json/654.json','["日日唯憂行役遲，東歸可是有家歸。都緣桂玉無門住，", "桃夭李豔清明近，惆悵當年意盡違。"]'),
('yuding-67','入關','羅鄴','唐','御定全唐诗','yuding','','[]','古道槐花滿樹開，入關時節一蟬催。出門唯恐不先到，',40,'御定全唐詩/json/654.json','["古道槐花滿樹開，入關時節一蟬催。出門唯恐不先到，", "故園若有漁舟在，應掛雲帆早個回。"]'),
('yuding-68','覽陳丕卷','羅鄴','唐','御定全唐诗','yuding','','[]','雪宮詞客燕宮遊，一軸煙花象外搜。謾把蜀紋當晝展，',40,'御定全唐詩/json/654.json','["雪宮詞客燕宮遊，一軸煙花象外搜。謾把蜀紋當晝展，", "從北南歸明月夜，嶺猿灘鳥更悠悠。"]'),
('yuding-69','巴南旅舍言懷','羅鄴','唐','御定全唐诗','yuding','','[]','萬浪千岩首未回，無憀相倚上高臺。家山如畫不歸去，',40,'御定全唐詩/json/654.json','["萬浪千岩首未回，無憀相倚上高臺。家山如畫不歸去，", "後時若有青雲望，何事偏教羽翼摧。"]'),
('yuding-70','登淩歊台','羅鄴','唐','御定全唐诗','yuding','','[]','高臺今日竟長閑，因想興亡自慘顏。四海已歸新雨露，',40,'御定全唐詩/json/654.json','["高臺今日竟長閑，因想興亡自慘顏。四海已歸新雨露，", "好是輪蹄來往便，誰人不向此躋攀。"]'),
('yuding-71','僕射陂晚望','羅鄴','唐','御定全唐诗','yuding','','[]','離人到此倍堪傷，陂水蘆花似故鄉。身事未知何日了，',40,'御定全唐詩/json/654.json','["離人到此倍堪傷，陂水蘆花似故鄉。身事未知何日了，", "卻羨無愁是沙鳥，雙雙相趁下斜陽。"]'),
('yuding-72','芳草','羅鄴','唐','御定全唐诗','yuding','','[]','廢苑牆南殘雨中，似袍顏色正蒙茸。微香暗惹遊人步，',40,'御定全唐詩/json/654.json','["廢苑牆南殘雨中，似袍顏色正蒙茸。微香暗惹遊人步，", "年年縱有春風便，馬跡車輪一萬重。"]'),
('yuding-73','秋日留題蔣亭','羅鄴','唐','御定全唐诗','yuding','','[]','西風才起一蟬鳴，便算關河馬上程。碧浪鷁舟從此別，',40,'御定全唐詩/json/654.json','["西風才起一蟬鳴，便算關河馬上程。碧浪鷁舟從此別，", "回首橫塘更東望，露荷煙菊倍傷情。"]'),
('yuding-74','早發','羅鄴','唐','御定全唐诗','yuding','','[]','一點燈殘魯酒醒，已攜孤劍事離程。愁看飛雪聞雞唱，',40,'御定全唐詩/json/654.json','["一點燈殘魯酒醒，已攜孤劍事離程。愁看飛雪聞雞唱，", "此中來往本迢遞，況是驅羸客塞城。"]'),
('yuding-75','雁二首','羅鄴','唐','御定全唐诗','yuding','','[]','暮天新雁起汀洲，紅蓼花開水國愁。',64,'御定全唐詩/json/654.json','["暮天新雁起汀洲，紅蓼花開水國愁。", "想得故園今夜月，幾人相憶在江樓。", "早背胡霜過戍樓，又隨寒日下汀洲。", "江南江北多離別，忍報年年兩地愁。"]'),
('yuding-76','螢二首','羅鄴','唐','御定全唐诗','yuding','','[]','水殿清風玉戶開，飛光千點去還來。',64,'御定全唐詩/json/654.json','["水殿清風玉戶開，飛光千點去還來。", "無風無月長門夜，偏到階前點綠苔。", "裴回無燭冷無煙，秋徑莎庭入夜天。", "休向書窗來照字，近來紅蠟滿歌筵。"]'),
('yuding-77','看花','羅鄴','唐','御定全唐诗','yuding','','[]','花開只恐看來遲，及到愁如未看時。',32,'御定全唐詩/json/654.json','["花開只恐看來遲，及到愁如未看時。", "家在楚鄉身在蜀，一年春色負歸期。"]'),
('yuding-78','柳絮','羅鄴','唐','御定全唐诗','yuding','','[]','處處東風撲晚陽，輕輕醉粉落無香。',32,'御定全唐詩/json/654.json','["處處東風撲晚陽，輕輕醉粉落無香。", "就中堪恨隋堤上，曾惹龍舟舞鳳凰。"]'),
('yuding-79','雲','羅鄴','唐','御定全唐诗','yuding','','[]','紛紛靄靄遍江湖，得路為霖豈合無。',32,'御定全唐詩/json/654.json','["紛紛靄靄遍江湖，得路為霖豈合無。", "莫使悠颺只如此，帝鄉還更暖蒼梧。"]'),
('yuding-80','芳草','羅鄴','唐','御定全唐诗','yuding','','[]','曲江岸上天街裏，兩地縱生車馬多。',32,'御定全唐詩/json/654.json','["曲江岸上天街裏，兩地縱生車馬多。", "不似萋萋南浦見，晚來煙雨半相和。"]'),
('yuding-81','出都門','羅鄴','唐','御定全唐诗','yuding','','[]','青門春色一花開，長到花時把酒杯。',32,'御定全唐詩/json/654.json','["青門春色一花開，長到花時把酒杯。", "自覺無家似潮水，不知歸處去還來。"]'),
('yuding-82','宮中二首','羅鄴','唐','御定全唐诗','yuding','','[]','芳草長含玉輦塵，君王游幸此中頻。',64,'御定全唐詩/json/654.json','["芳草長含玉輦塵，君王游幸此中頻。", "今朝別有承恩處，鸚鵡飛來說似人。", "雖然自小屬梨園，不識先皇玉殿門。", "還是當時歌舞曲，今來何處最承恩。"]'),
('yuding-83','河湟','羅鄴','唐','御定全唐诗','yuding','','[]','河湟何計絕烽煙，免使征人更戍邊。',32,'御定全唐詩/json/654.json','["河湟何計絕烽煙，免使征人更戍邊。", "盡放農桑無一事，遣教知有太平年。"]'),
('yuding-84','聞子規','羅鄴','唐','御定全唐诗','yuding','','[]','蜀魄千年尚怨誰，聲聲啼血向花枝。',32,'御定全唐詩/json/654.json','["蜀魄千年尚怨誰，聲聲啼血向花枝。", "滿山明月東風夜，正是愁人不寐時。"]'),
('yuding-85','望仙','羅鄴','唐','御定全唐诗','yuding','','[]','千金壘土望三山，雲鶴無蹤羽衛還。',32,'御定全唐詩/json/654.json','["千金壘土望三山，雲鶴無蹤羽衛還。", "若說神仙求便得，茂陵何事在人間。"]'),
('yuding-86','放鷓鴣','羅鄴','唐','御定全唐诗','yuding','','[]','好傍青山與碧溪，刺桐毛竹待雙棲。',32,'御定全唐詩/json/654.json','["好傍青山與碧溪，刺桐毛竹待雙棲。", "花時遷客傷離別，莫向相思樹上啼。"]'),
('yuding-87','驪山','羅鄴','唐','御定全唐诗','yuding','','[]','風搖岩桂露聞香，白鹿驚時出繞牆。',32,'御定全唐詩/json/654.json','["風搖岩桂露聞香，白鹿驚時出繞牆。", "不向驪山鎖宮殿，可知仙去是明皇。"]'),
('yuding-88','梅花','羅鄴','唐','御定全唐诗','yuding','','[]','繁如瑞雪壓枝開，越嶺吳溪免用栽。',32,'御定全唐詩/json/654.json','["繁如瑞雪壓枝開，越嶺吳溪免用栽。", "卻是五侯家未識，春風不放過江來。"]'),
('yuding-89','雞冠花','羅鄴','唐','御定全唐诗','yuding','','[]','一枝穠豔對秋光，露滴風搖倚砌傍。',32,'御定全唐詩/json/654.json','["一枝穠豔對秋光，露滴風搖倚砌傍。", "曉景乍看何處似，謝家新染紫羅裳。"]'),
('yuding-90','汴河','羅鄴','唐','御定全唐诗','yuding','','[]','煬帝開河鬼亦悲，生民不獨力空疲。',32,'御定全唐詩/json/654.json','["煬帝開河鬼亦悲，生民不獨力空疲。", "至今嗚咽東流水，似向清平怨昔時。"]'),
('yuding-91','渡江有感','羅鄴','唐','御定全唐诗','yuding','','[]','岸落殘紅錦雉飛，渡江船上夕陽微。',32,'御定全唐詩/json/654.json','["岸落殘紅錦雉飛，渡江船上夕陽微。", "一枝猶負平生意，歸去何曾勝不歸。"]'),
('yuding-92','題終南山僧堂','羅鄴','唐','御定全唐诗','yuding','','[]','九衢終日見南山，名利何人肯掩關。',32,'御定全唐詩/json/654.json','["九衢終日見南山，名利何人肯掩關。", "唯有吾師達真理，坐看霜樹老雲間。"]'),
('yuding-93','大散嶺','羅鄴','唐','御定全唐诗','yuding','','[]','過往長逢日色稀，雪花如掌撲行衣。',32,'御定全唐詩/json/654.json','["過往長逢日色稀，雪花如掌撲行衣。", "嶺頭卻望人來處，特地身疑是鳥飛。"]'),
('yuding-94','嘉陵江','羅鄴','唐','御定全唐诗','yuding','','[]','嘉陵南岸雨初收，江似秋嵐不煞流。',32,'御定全唐詩/json/654.json','["嘉陵南岸雨初收，江似秋嵐不煞流。", "此地終朝有行客，無人一為棹扁舟。"]'),
('yuding-95','早行','羅鄴','唐','御定全唐诗','yuding','','[]','雨灑江聲風又吹，扁舟正與睡相宜。',32,'御定全唐詩/json/654.json','["雨灑江聲風又吹，扁舟正與睡相宜。", "無端戍鼓催前去，別卻青山向曉時。"]'),
('yuding-96','黃河曉渡','羅鄴','唐','御定全唐诗','yuding','','[]','大河平野正窮秋，羸馬羸僮古渡頭。',32,'御定全唐詩/json/654.json','["大河平野正窮秋，羸馬羸僮古渡頭。", "昨夜蓮花峰下月，隔簾相伴到明愁。"]'),
('yuding-97','溫泉','羅鄴','唐','御定全唐诗','yuding','','[]','一條春水漱莓苔，幾繞玄宗浴殿回。',32,'御定全唐詩/json/654.json','["一條春水漱莓苔，幾繞玄宗浴殿回。", "此水貴妃曾照影，不堪流入舊宮來。"]'),
('yuding-98','秋怨','羅鄴','唐','御定全唐诗','yuding','','[]','夢斷南窗啼曉烏，新霜昨夜下庭梧。',32,'御定全唐詩/json/654.json','["夢斷南窗啼曉烏，新霜昨夜下庭梧。", "不知簾外如珪月，還照邊城到曉無。"]'),
('yuding-99','歎別','羅鄴','唐','御定全唐诗','yuding','','[]','北來南去幾時休，人在光陰似箭流。',32,'御定全唐詩/json/654.json','["北來南去幾時休，人在光陰似箭流。", "直待江山盡無路，始因拋得別離愁。"]'),
('yuding-100','送春','羅鄴','唐','御定全唐诗','yuding','','[]','欲別東風剩黯然，亦知春去有明年。',32,'御定全唐詩/json/654.json','["欲別東風剩黯然，亦知春去有明年。", "世間爭那人先老，更對殘花一醉眠。"]'),
('yuding-101','蠟燭','羅鄴','唐','御定全唐诗','yuding','','[]','暖香紅焰一時燃，緹幕初垂月落天。',32,'御定全唐詩/json/654.json','["暖香紅焰一時燃，緹幕初垂月落天。", "堪恨蘭堂別離夜，如珠似淚滴樽前。"]'),
('yuding-102','陳宮','羅鄴','唐','御定全唐诗','yuding','','[]','白玉尊前紫桂香，迎春閣上燕雙雙。',32,'御定全唐詩/json/654.json','["白玉尊前紫桂香，迎春閣上燕雙雙。", "陳王半醉貴妃舞，不覺隋兵夜渡江。"]'),
('yuding-103','水簾','羅鄴','唐','御定全唐诗','yuding','','[]','萬點飛泉下白雲，似簾懸處望疑真。',32,'御定全唐詩/json/654.json','["萬點飛泉下白雲，似簾懸處望疑真。", "若將此水為霖雨，更勝長垂隔路塵。"]'),
('yuding-104','賞春','羅鄴','唐','御定全唐诗','yuding','','[]','芳草和煙暖更青，閑門要路一時生。',32,'御定全唐詩/json/654.json','["芳草和煙暖更青，閑門要路一時生。", "年年點檢人間事，唯有春風不世情。"]'),
('yuding-105','歎平泉','羅鄴','唐','御定全唐诗','yuding','','[]','生前幾到此亭台，尋歎投荒去不回。',32,'御定全唐詩/json/654.json','["生前幾到此亭台，尋歎投荒去不回。", "若遣春風會人意，花枝盡合向南開。"]'),
('yuding-106','長安春雨','羅鄴','唐','御定全唐诗','yuding','','[]','兼風颯颯灑皇州，能滯輕寒阻勝遊。',32,'御定全唐詩/json/654.json','["兼風颯颯灑皇州，能滯輕寒阻勝遊。", "半夜五侯池館裏，美人驚起為花愁。"]'),
('yuding-107','駕蜀回','羅鄴','唐','御定全唐诗','yuding','','[]','上皇西幸卻歸秦，花木依然滿禁春。',32,'御定全唐詩/json/654.json','["上皇西幸卻歸秦，花木依然滿禁春。", "唯有貴妃歌舞地，月明空殿鎖香塵。"]'),
('yuding-108','吳王古宮井二首','羅鄴','唐','御定全唐诗','yuding','','[]','古宮荒井曾平後，見說耕人又鑿開。',64,'御定全唐詩/json/654.json','["古宮荒井曾平後，見說耕人又鑿開。", "拾得玉釵鐫敕字，當時恩澤賜誰來。", "含青薜荔隨金甃，碧砌磷磷生綠苔。", "莫言數尺無波水，曾與如花並照來。"]'),
('yuding-109','江帆','羅鄴','唐','御定全唐诗','yuding','','[]','別離不獨恨蹄輪，渡口風帆發更頻。',32,'御定全唐詩/json/654.json','["別離不獨恨蹄輪，渡口風帆發更頻。", "何處青樓方憑檻，半江斜日認歸人。"]'),
('yuding-110','為人感贈','羅鄴','唐','御定全唐诗','yuding','','[]','歌舞從來最得名，如今老寄洛陽城。',32,'御定全唐詩/json/654.json','["歌舞從來最得名，如今老寄洛陽城。", "當時醉送龍驤曲，留與誰家唱月明。"]'),
('yuding-111','春江恨別','羅鄴','唐','御定全唐诗','yuding','','[]','望斷長川一葉舟，可堪歸路更沿流。',32,'御定全唐詩/json/654.json','["望斷長川一葉舟，可堪歸路更沿流。", "重來別處無人見，芳草斜陽滿渡頭。"]'),
('yuding-112','歎流水二首','羅鄴','唐','御定全唐诗','yuding','','[]','人間莫謾惜花落，花落明年依舊開。',64,'御定全唐詩/json/654.json','["人間莫謾惜花落，花落明年依舊開。", "卻最堪悲是流水，便同人事去無回。", "龍躍虯蟠旋作潭，繞紅濺綠下東南。", "春風散入侯家去，漱齒花前酒半酣。"]'),
('yuding-113','落第東歸','羅鄴','唐','御定全唐诗','yuding','','[]','年年春色獨懷羞，強向東歸懶舉頭。',32,'御定全唐詩/json/654.json','["年年春色獨懷羞，強向東歸懶舉頭。", "莫道還家便容易，人間多少事堪愁。"]'),
('yuding-114','鏡','羅鄴','唐','御定全唐诗','yuding','','[]','昔歲相知別有情，幾回磨拭始將行。',32,'御定全唐詩/json/654.json','["昔歲相知別有情，幾回磨拭始將行。", "如今老去愁無限，抱向閑窗卻怕明。"]'),
('yuding-115','南行','羅鄴','唐','御定全唐诗','yuding','','[]','臘晴江暖鸊鵜飛，梅雪香黏越女衣。',32,'御定全唐詩/json/654.json','["臘晴江暖鸊鵜飛，梅雪香黏越女衣。", "魚市酒村相識遍，短船歌月醉方歸。"]'),
('yuding-116','公子行','羅鄴','唐','御定全唐诗','yuding','','[]','金鞍玉勒照花明，過後春風特地生。',32,'御定全唐詩/json/654.json','["金鞍玉勒照花明，過後春風特地生。", "半醉五侯門裏出，月高猶在禁街行。"]'),
('yuding-117','春日偶題城南韋曲','羅鄴','唐','御定全唐诗','yuding','','[]','韋曲城南錦繡堆，千金不惜買花栽。',32,'御定全唐詩/json/654.json','["韋曲城南錦繡堆，千金不惜買花栽。", "誰知豪貴多羈束，落盡春紅不見來。"]'),
('yuding-118','上東川顧尚書','羅鄴','唐','御定全唐诗','yuding','','[]','輕財重義真公子，長策沈機繼武侯。',32,'御定全唐詩/json/654.json','["輕財重義真公子，長策沈機繼武侯。", "龍節坐持兵十萬，可憐三蜀盡無憂。"]'),
('yuding-119','過王浚墓','羅鄴','唐','御定全唐诗','yuding','','[]','埋骨千年近路塵，路傍碑號晉將軍。',32,'御定全唐詩/json/654.json','["埋骨千年近路塵，路傍碑號晉將軍。", "當時若使無功業，早個耕桑到此墳。"]'),
('yuding-120','灞上感別','羅鄴','唐','御定全唐诗','yuding','','[]','灞水何人不別離，無家南北倚空悲。',32,'御定全唐詩/json/654.json','["灞水何人不別離，無家南北倚空悲。", "十年此路花時節，立馬沾襟酒一卮。"]'),
('yuding-121','春日與友人話別','羅鄴','唐','御定全唐诗','yuding','','[]','酌坐對芳草，東風吹旅衣。最嫌驅馬倦，自未有山歸。',48,'御定全唐詩/json/654.json','["酌坐對芳草，東風吹旅衣。最嫌驅馬倦，自未有山歸。", "華髮將時逼，青雲計又非。離襟一沾灑，回首正殘暉。"]'),
('yuding-122','竹','羅鄴','唐','御定全唐诗','yuding','','[]','翠葉才分細細枝，清陰猶未上階墀。蕙蘭雖許相依日，',40,'御定全唐詩/json/654.json','["翠葉才分細細枝，清陰猶未上階墀。蕙蘭雖許相依日，", "渭濱若更征賢相，好作漁竿系釣絲。"]'),
('yuding-123','邊將','羅鄴','唐','御定全唐诗','yuding','','[]','馬上乘秋欲建勳，飛狐夜鬥出師頻。若無紫塞煙塵事，',40,'御定全唐詩/json/654.json','["馬上乘秋欲建勳，飛狐夜鬥出師頻。若無紫塞煙塵事，", "由來邊卒皆如此，只是君門合殺身。"]'),
('yuding-124','巴南旅泊','羅鄴','唐','御定全唐诗','yuding','','[]','巴山慘別魂，巴水徹荊門。此地若重到，居人誰複存。',48,'御定全唐詩/json/654.json','["巴山慘別魂，巴水徹荊門。此地若重到，居人誰複存。", "落帆紅葉渡，駐馬白雲村。卻羨南飛雁，年年到故園。"]'),
('yuding-125','河上逢友人','羅鄴','唐','御定全唐诗','yuding','','[]','知君意不淺，立馬問生涯。薄業無歸地，他鄉便是家。',48,'御定全唐詩/json/654.json','["知君意不淺，立馬問生涯。薄業無歸地，他鄉便是家。", "宵吟憐桂魄，朝起怯菱花。語盡黃河上，西風日又斜。"]'),
('yuding-126','偶題離亭','羅鄴','唐','御定全唐诗','yuding','','[]','萬般名利不關身，況待山平海變塵。五月波濤爭下峽，',40,'御定全唐詩/json/654.json','["萬般名利不關身，況待山平海變塵。五月波濤爭下峽，", "誰似雨蓬蓬底客，渚花汀鳥自相親。"]'),
('yuding-127','夏晚望嵩亭有懷','羅鄴','唐','御定全唐诗','yuding','','[]','正憐雲水與心違，湖上亭高對翠微。盡日不妨憑檻望，',40,'御定全唐詩/json/654.json','["正憐雲水與心違，湖上亭高對翠微。盡日不妨憑檻望，", "此地又愁無計住，一竿何處是因依。"]'),
('yuding-128','途中寄友人','羅鄴','唐','御定全唐诗','yuding','','[]','秋庭悵望別君初，折柳分襟十載餘。相見或因中夜夢，',40,'御定全唐詩/json/654.json','["秋庭悵望別君初，折柳分襟十載餘。相見或因中夜夢，", "裁得詩憑千里雁，吟來寧不憶吾廬。"]'),
('yuding-129','傷侯第','羅鄴','唐','御定全唐诗','yuding','','[]','世間榮辱半相和，昨日權門今雀羅。萬古明君方納諫，',40,'御定全唐詩/json/654.json','["世間榮辱半相和，昨日權門今雀羅。萬古明君方納諫，", "幾許樂僮無主後，不離鄰巷教笙歌。"]'),
('yuding-130','春日過壽安山館','羅鄴','唐','御定全唐诗','yuding','','[]','舊國多將泉石親，西遊愛此拂行塵。簾開山色離亭午，',40,'御定全唐詩/json/654.json','["舊國多將泉石親，西遊愛此拂行塵。簾開山色離亭午，", "歸期不及桃花水，江上何曾鱠雪鱗。"]'),
('yuding-131','吳門再逢方幹處士','羅鄴','唐','御定全唐诗','yuding','','[]','天上高名世上身，垂綸何不駕蒲輪。一朝卿相俱前席，',40,'御定全唐詩/json/654.json','["天上高名世上身，垂綸何不駕蒲輪。一朝卿相俱前席，", "吾王若致升平化，可獨成周只渭濱。"]'),
('yuding-132','蟬','羅鄴','唐','御定全唐诗','yuding','','[]','才入新秋百感生，就中蟬噪最堪驚。能催時節凋雙鬢，',40,'御定全唐詩/json/654.json','["才入新秋百感生，就中蟬噪最堪驚。能催時節凋雙鬢，", "故園聞處猶惆悵，況是經年萬里行。"]'),
('yuding-133','秋日留別義初上人','羅鄴','唐','御定全唐诗','yuding','','[]','塞寺窮秋別遠師，西風一雁倍傷悲。每嗟塵世長多事，',40,'御定全唐詩/json/654.json','["塞寺窮秋別遠師，西風一雁倍傷悲。每嗟塵世長多事，", "關河回首便千里，飛錫南歸詎可知。"]'),
('yuding-134','夏日宿靈岩寺宗公院','羅鄴','唐','御定全唐诗','yuding','','[]','寺入千岩石路長，孤吟一宿遠公房。臥聽半夜杉壇雨，',40,'御定全唐詩/json/654.json','["寺入千岩石路長，孤吟一宿遠公房。臥聽半夜杉壇雨，", "他年縱使重來此，息得心猿鬢已霜。"]'),
('yuding-135','冬日廟中書事呈棲白上人','羅鄴','唐','御定全唐诗','yuding','','[]','日高荒廟掩雙扉，杉徑無人鳥雀悲。昨日江潮起歸思，',40,'御定全唐詩/json/654.json','["日高荒廟掩雙扉，杉徑無人鳥雀悲。昨日江潮起歸思，", "賴有碧雲吟句客，禪餘相訪說新詩。"]'),
('yuding-136','夏日題遠公北閣','羅鄴','唐','御定全唐诗','yuding','','[]','危閣壓山岡，晴空疑鳥行。勝搜花界盡，響益梵音長。',72,'御定全唐詩/json/654.json','["危閣壓山岡，晴空疑鳥行。勝搜花界盡，響益梵音長。", "有月堪先到，無風亦自涼。人煙紛繞繞，諸樹共蒼蒼。", "榻戀高樓語，甌憐晝茗香。此身閑未得，驅馬入殘陽。"]'),
('yuding-137','秋蝶二首','羅鄴','唐','御定全唐诗','yuding','','[]','秦樓花發時，秦女笑相隨。及到秋風日，飛來欲問誰。',48,'御定全唐詩/json/654.json','["秦樓花發時，秦女笑相隨。及到秋風日，飛來欲問誰。", "似厭棲寒菊，翩翩占晚陽。愁人如見此，應下淚千行。"]'),
('yuding-138','秋別','羅鄴','唐','御定全唐诗','yuding','','[]','別路垂楊柳，秋風淒管弦。青樓君去後，明月為誰圓。',24,'御定全唐詩/json/654.json','["別路垂楊柳，秋風淒管弦。青樓君去後，明月為誰圓。"]'),
('yuding-139','共友人看花','羅鄴','唐','御定全唐诗','yuding','','[]','愁將萬里身，來伴看花人。何事獨惆悵，故園還又春。',24,'御定全唐詩/json/654.json','["愁將萬里身，來伴看花人。何事獨惆悵，故園還又春。"]'),
('yuding-140','行次','羅鄴','唐','御定全唐诗','yuding','','[]','終日長程複短程，一山行盡一山青。',32,'御定全唐詩/json/654.json','["終日長程複短程，一山行盡一山青。", "路傍君子莫相笑，天上由來有客星。"]'),
('yuding-141','鳳州北樓','羅鄴','唐','御定全唐诗','yuding','','[]','城上層樓北望時，閑雲遠水自相宜。',32,'御定全唐詩/json/654.json','["城上層樓北望時，閑雲遠水自相宜。", "人人盡道堪圖畫，枉遣山翁醉習池。"]'),
('yuding-142','贈僧','羅鄴','唐','御定全唐诗','yuding','','[]','繁華舉世皆如夢，今古何人肯暫閑。',32,'御定全唐詩/json/654.json','["繁華舉世皆如夢，今古何人肯暫閑。", "唯有東林學禪客，白頭閑坐對青山。"]'),
('yuding-0','曲江春感','羅隱','唐','御定全唐诗','yuding','','[]','江頭日暖花又開，江東行客心悠哉。高陽酒徒半凋落，',40,'御定全唐詩/json/655.json','["江頭日暖花又開，江東行客心悠哉。高陽酒徒半凋落，", "一船明月一竿竹，家住五湖歸去來。"]'),
('yuding-1','皇陂','羅隱','唐','御定全唐诗','yuding','','[]','皇陂瀲灩深複深，陂西下馬聊登臨。垂楊風輕弄翠帶，',40,'御定全唐詩/json/655.json','["皇陂瀲灩深複深，陂西下馬聊登臨。垂楊風輕弄翠帶，", "輸他谷口鄭夫子，偷得閒名說至今。"]'),
('yuding-2','寄鄭補闕','羅隱','唐','御定全唐诗','yuding','','[]','夫子門前數仞牆，每經過處憶游梁。路從青瑣無因見，',40,'御定全唐詩/json/655.json','["夫子門前數仞牆，每經過處憶游梁。路從青瑣無因見，", "別來愁悴知多少，兩度槐花馬上黃。"]'),
('yuding-3','牡丹花','羅隱','唐','御定全唐诗','yuding','','[]','似共東風別有因，絳羅高卷不勝春。若教解語應傾國，',40,'御定全唐詩/json/655.json','["似共東風別有因，絳羅高卷不勝春。若教解語應傾國，", "可憐韓令功成後，辜負穠華過此身。"]'),
('yuding-4','黃河','羅隱','唐','御定全唐诗','yuding','','[]','莫把阿膠向此傾，此中天意固難明。解通銀漢應須曲，',40,'御定全唐詩/json/655.json','["莫把阿膠向此傾，此中天意固難明。解通銀漢應須曲，", "三千年後知誰在，何必勞君報太平。"]'),
('yuding-5','汴河','羅隱','唐','御定全唐诗','yuding','','[]','當時天子是閒遊，今日行人特地愁。柳色縱饒妝故國，',40,'御定全唐詩/json/655.json','["當時天子是閒遊，今日行人特地愁。柳色縱饒妝故國，", "應笑秦皇用心錯，謾驅神鬼海東頭。"]'),
('yuding-6','西京崇德里居','羅隱','唐','御定全唐诗','yuding','','[]','進乏梯媒退又難，強隨豪貴殢長安。風從昨夜吹銀漢，',40,'御定全唐詩/json/655.json','["進乏梯媒退又難，強隨豪貴殢長安。風從昨夜吹銀漢，", "錦鱗赬尾平生事，卻被閒人把釣竿。"]'),
('yuding-7','投所思','羅隱','唐','御定全唐诗','yuding','','[]','憔悴長安何所為，旅魂窮命自相疑。滿川碧嶂無歸日，',40,'御定全唐詩/json/655.json','["憔悴長安何所為，旅魂窮命自相疑。滿川碧嶂無歸日，", "浮生七十今三十，從此悽惶未可知。"]'),
('yuding-8','經張舍人舊居','羅隱','唐','御定全唐诗','yuding','','[]','行塵不是昔時塵，謾向朱門憶侍臣。一榻已無開眼處，',40,'御定全唐詩/json/655.json','["行塵不是昔時塵，謾向朱門憶侍臣。一榻已無開眼處，", "從此恩深轉難報，夕陽衰草淚沾巾。"]'),
('yuding-9','雒城作','羅隱','唐','御定全唐诗','yuding','','[]','大鹵旌旗出洛濱，此中煙月已埃塵。更無樓閣尋行處，',40,'御定全唐詩/json/655.json','["大鹵旌旗出洛濱，此中煙月已埃塵。更無樓閣尋行處，", "舊游難得時難遇，回首空城百草春。"]'),
('yuding-10','姑蘇城南湖陪曹使君游','羅隱','唐','御定全唐诗','yuding','','[]','水蓼花紅稻穗黃，使君蘭棹泛回塘。倚風荇藻先開路，',40,'御定全唐詩/json/655.json','["水蓼花紅稻穗黃，使君蘭棹泛回塘。倚風荇藻先開路，", "少年太守勳庸盛，應笑燕台兩鬢霜。"]'),
('yuding-11','秋日有寄姑蘇曹使君','羅隱','唐','御定全唐诗','yuding','','[]','多病無因棹小舟，闔閭城下謁名侯。水寒不見雙魚信，',40,'御定全唐詩/json/655.json','["多病無因棹小舟，闔閭城下謁名侯。水寒不見雙魚信，", "須知謝奕依前醉，閑阻清談又一秋。"]'),
('yuding-12','送章碣赴舉','羅隱','唐','御定全唐诗','yuding','','[]','蘋鹿歌中別酒催，粉闈星彩動昭回。久經罹亂心應破，',40,'御定全唐詩/json/655.json','["蘋鹿歌中別酒催，粉闈星彩動昭回。久經罹亂心應破，", "龍門盛事無因見，費盡黃金老隗台。"]'),
('yuding-13','寄楊秘書','羅隱','唐','御定全唐诗','yuding','','[]','湖水平來見鯉魚，偶因烹處得瓊琚。披尋藻思千重後，',40,'御定全唐詩/json/655.json','["湖水平來見鯉魚，偶因烹處得瓊琚。披尋藻思千重後，", "錦衣公子憐君在，十載兵戈從板輿。"]'),
('yuding-14','往年進士趙能卿嘗話金庭勝事，見示敘','羅隱','唐','御定全唐诗','yuding','','[]','會稽詩客趙能卿，往歲相逢話石城。正恨故人無上壽，',40,'御定全唐詩/json/655.json','["會稽詩客趙能卿，往歲相逢話石城。正恨故人無上壽，", "兩火一刀罹亂後，會須乘興雪中行。"]'),
('yuding-15','得宣州竇尚書書因投寄二首','羅隱','唐','御定全唐诗','yuding','','[]','雙魚迢遞到江濱，傷感南陵舊主人。萬里朝台勞寄夢，',80,'御定全唐詩/json/655.json','["雙魚迢遞到江濱，傷感南陵舊主人。萬里朝台勞寄夢，", "時見齊山敬亭客，不堪戎馬戰征頻。", "曾逐旌旗過板橋，世途多難竟蓬飄。步兵校尉辭公府，", "遺簪墮履應留念，門客如今只下僚。"]'),
('yuding-16','雪','羅隱','唐','御定全唐诗','yuding','','[]','細玉羅紋下碧霄，杜門顏巷落偏饒。巢居只恐高柯折，',40,'御定全唐詩/json/655.json','["細玉羅紋下碧霄，杜門顏巷落偏饒。巢居只恐高柯折，", "寒窗呵筆尋詩句，一片飛來紙上銷。"]'),
('yuding-17','暇日有寄姑蘇曹使君兼呈張郎中郡中賓僚','羅隱','唐','御定全唐诗','yuding','','[]','嘉植陰陰覆劍池，此中能政動神祇。湖邊觀稼雨迎馬，',40,'御定全唐詩/json/655.json','["嘉植陰陰覆劍池，此中能政動神祇。湖邊觀稼雨迎馬，", "珊瑚筆架真珠履，曾和陳王幾首詩。"]'),
('yuding-18','寄右省王諫議','羅隱','唐','御定全唐诗','yuding','','[]','耳邊要靜不得靜，心裏欲閑終未閑。自是宿緣應有累，',40,'御定全唐詩/json/655.json','["耳邊要靜不得靜，心裏欲閑終未閑。自是宿緣應有累，", "看卻金庭芝朮老，又驅車入七人班。"]'),
('yuding-19','焚書坑','羅隱','唐','御定全唐诗','yuding','','[]','千載遺蹤一窖塵，路傍耕者亦傷神。',32,'御定全唐詩/json/655.json','["千載遺蹤一窖塵，路傍耕者亦傷神。", "祖龍算事渾乖角，將謂詩書活得人。"]'),
('yuding-20','始皇陵','羅隱','唐','御定全唐诗','yuding','','[]','荒堆無草樹無枝，懶向行人問昔時。',32,'御定全唐詩/json/655.json','["荒堆無草樹無枝，懶向行人問昔時。", "六國英雄漫多事，到頭徐福是男兒。"]'),
('yuding-21','送沈先輩歸送上嘉禮','羅隱','唐','御定全唐诗','yuding','','[]','青青月桂觸人香，白苧衫輕稱沈郎。好繼馬卿歸故里，',40,'御定全唐詩/json/655.json','["青青月桂觸人香，白苧衫輕稱沈郎。好繼馬卿歸故里，", "擬把金錢贈嘉禮，不堪棲屑困名場。"]'),
('yuding-22','春日葉秀才曲江','羅隱','唐','御定全唐诗','yuding','','[]','江花江草暖相隈，也向江邊把酒杯。春色惱人遮不得，',40,'御定全唐詩/json/655.json','["江花江草暖相隈，也向江邊把酒杯。春色惱人遮不得，", "一曲吳歌齊拍手，十年塵眼未曾開。"]'),
('yuding-23','西京道德裏','羅隱','唐','御定全唐诗','yuding','','[]','秦樹團團夕結陰，此中莊舄動悲吟。一枝丹桂未入手，',40,'御定全唐詩/json/655.json','["秦樹團團夕結陰，此中莊舄動悲吟。一枝丹桂未入手，", "七雄三傑今何在，休為閒人淚滿襟。"]'),
('yuding-24','憶夏口','羅隱','唐','御定全唐诗','yuding','','[]','漢陽渡口蘭為舟，漢陽城下多酒樓。當年不得盡一醉，',40,'御定全唐詩/json/655.json','["漢陽渡口蘭為舟，漢陽城下多酒樓。當年不得盡一醉，", "月明更想曾行處，吹笛橋邊木葉秋。"]'),
('yuding-25','武牢關','羅隱','唐','御定全唐诗','yuding','','[]','楚人曾此限封疆，不見清陰六裏長。一壑暮聲何怨望，',40,'御定全唐詩/json/655.json','["楚人曾此限封疆，不見清陰六裏長。一壑暮聲何怨望，", "欲學雞鳴試關吏，太平時節懶思量。"]'),
('yuding-26','途中獻晉州孟中丞','羅隱','唐','御定全唐诗','yuding','','[]','太平天子念蒲東，又委星郎養育功。昨日隼旟辭闕下，',40,'御定全唐詩/json/655.json','["太平天子念蒲東，又委星郎養育功。昨日隼旟辭闕下，", "不及政成應入拜，晉州何足展清通。"]'),
('yuding-27','長安秋夜','羅隱','唐','御定全唐诗','yuding','','[]','遠聞天子似羲皇，偶舍漁鄉入帝鄉。五等列侯無故舊，',40,'御定全唐詩/json/655.json','["遠聞天子似羲皇，偶舍漁鄉入帝鄉。五等列侯無故舊，", "歸計未知身已老，九衢雙闕夜蒼蒼。"]'),
('yuding-28','春晚寄鐘尚書','羅隱','唐','御定全唐诗','yuding','','[]','宰府初開忝末塵，四年談笑隔通津。官資肯便矜中路，',40,'御定全唐詩/json/655.json','["宰府初開忝末塵，四年談笑隔通津。官資肯便矜中路，", "如今莫問西禪塢，一炷寒香老病身。"]'),
('yuding-29','秋曉寄友人','羅隱','唐','御定全唐诗','yuding','','[]','洞庭霜落水雲秋，又泛輕漣任去留。世界高談今已得，',40,'御定全唐詩/json/655.json','["洞庭霜落水雲秋，又泛輕漣任去留。世界高談今已得，", "更見南來釣翁說，醉吟還上木蘭舟。"]'),
('yuding-30','秋日有酬','羅隱','唐','御定全唐诗','yuding','','[]','舊業傳家有寶刀，近聞餘力更揮毫。腰間印佩黃金重，',40,'御定全唐詩/json/655.json','["舊業傳家有寶刀，近聞餘力更揮毫。腰間印佩黃金重，", "分茅列土才三十，猶擬回頭賭錦袍。"]'),
('yuding-31','所思','羅隱','唐','御定全唐诗','yuding','','[]','梁王兔苑荊榛裏，煬帝雞台夢想中。只覺惘然悲謝傅，',40,'御定全唐詩/json/655.json','["梁王兔苑荊榛裏，煬帝雞台夢想中。只覺惘然悲謝傅，", "劃盡寒灰始堪歎，滿庭霜葉一窗風。"]'),
('yuding-32','送魏校書兼呈曹使君','羅隱','唐','御定全唐诗','yuding','','[]','亂離無計駐生涯，又事東游惜歲華。村店酒旗沽竹葉，',40,'御定全唐詩/json/655.json','["亂離無計駐生涯，又事東游惜歲華。村店酒旗沽竹葉，", "應見使君論世舊，掃門重得向曹家。"]'),
('yuding-33','四皓廟','羅隱','唐','御定全唐诗','yuding','','[]','漢惠秦皇事已聞，廟前高木眼前雲。',32,'御定全唐詩/json/655.json','["漢惠秦皇事已聞，廟前高木眼前雲。", "楚王謾費閒心力，六裏青山盡屬君。"]'),
('yuding-34','浮雲','羅隱','唐','御定全唐诗','yuding','','[]','溶溶曳曳自舒張，不向蒼梧即帝鄉。',32,'御定全唐詩/json/655.json','["溶溶曳曳自舒張，不向蒼梧即帝鄉。", "莫道無心便無事，也曾愁殺楚襄王。"]'),
('yuding-35','早發','羅隱','唐','御定全唐诗','yuding','','[]','北去南來無定居，此生生計竟何如。',32,'御定全唐詩/json/655.json','["北去南來無定居，此生生計竟何如。", "酷憐一覺平明睡，長被雞聲惡破除。"]'),
('yuding-36','香','羅隱','唐','御定全唐诗','yuding','','[]','沈水良材食柏珍，博山煙暖玉樓春。',32,'御定全唐詩/json/655.json','["沈水良材食柏珍，博山煙暖玉樓春。", "憐君亦是無端物，貪作馨香忘卻身。"]'),
('yuding-37','鄴城','羅隱','唐','御定全唐诗','yuding','','[]','臺上年年掩翠蛾，台前高樹夾漳河。',32,'御定全唐詩/json/655.json','["臺上年年掩翠蛾，台前高樹夾漳河。", "英雄亦到分香處，能共常人較幾多。"]'),
('yuding-0','七夕','羅隱','唐','御定全唐诗','yuding','','[]','絡角星河菡萏天，一家歡笑設紅筵。應傾謝女珠璣篋，',40,'御定全唐詩/json/656.json','["絡角星河菡萏天，一家歡笑設紅筵。應傾謝女珠璣篋，", "銅壺漏報天將曉，惆悵佳期又一年。"]'),
('yuding-1','送臧濆下第謁竇鄜州','羅隱','唐','御定全唐诗','yuding','','[]','賦得長楊不直錢，卻來京口看鶯遷。也知絳灌輕才子，',40,'御定全唐詩/json/656.json','["賦得長楊不直錢，卻來京口看鶯遷。也知絳灌輕才子，", "多情柱史應相問，與話歸心正浩然。"]'),
('yuding-2','清明日曲江懷友','羅隱','唐','御定全唐诗','yuding','','[]','君與田蘇即舊游，我於交分亦綢繆。二年隔絕黃泉下，',40,'御定全唐詩/json/656.json','["君與田蘇即舊游，我於交分亦綢繆。二年隔絕黃泉下，", "寡妻稚子應寒食，遙望江陵一淚流。"]'),
('yuding-3','送鄭州嚴員外','羅隱','唐','御定全唐诗','yuding','','[]','欲將刀筆潤王猷，東去先分聖主憂。滿扇好風吹鄭圃，',40,'御定全唐詩/json/656.json','["欲將刀筆潤王猷，東去先分聖主憂。滿扇好風吹鄭圃，", "從此文星在何處，武牢關外庾公樓。"]'),
('yuding-4','孫員外赴闕後重到三衢','羅隱','唐','御定全唐诗','yuding','','[]','遠山高枝思悠哉，重倚危樓盡一杯。謝守已隨征詔入，',40,'御定全唐詩/json/656.json','["遠山高枝思悠哉，重倚危樓盡一杯。謝守已隨征詔入，", "宣室夜闌如有問，可能全忘未然灰。"]'),
('yuding-5','衡陽泊木居士廟下作','羅隱','唐','御定全唐诗','yuding','','[]','烏噪殘陽草滿庭，此中枯木似人形。只應神物長為主，',40,'御定全唐詩/json/656.json','["烏噪殘陽草滿庭，此中枯木似人形。只應神物長為主，", "南朝庾信無因賦，牢落祠前水氣腥。"]'),
('yuding-6','鐘陵見楊秀才','羅隱','唐','御定全唐诗','yuding','','[]','孺亭滕閣少踟躕，三度南遊一事無。只覺流年如鳥逝，',40,'御定全唐詩/json/656.json','["孺亭滕閣少踟躕，三度南遊一事無。只覺流年如鳥逝，", "賴得與君同此醉，醒來愁被鬼揶揄。"]'),
('yuding-7','自湘川東下立春泊夏口阻風登孫權城','羅隱','唐','御定全唐诗','yuding','','[]','吳門此去逾千里，湘浦離來想數旬。只見風師長占路，',40,'御定全唐詩/json/656.json','["吳門此去逾千里，湘浦離來想數旬。只見風師長占路，", "事往時移何足問，且憑村酒暖精神。"]'),
('yuding-8','春日憶湖南舊游寄盧校書','羅隱','唐','御定全唐诗','yuding','','[]','旅榜前年過洞庭，曾提刀筆事甘寧。玳筵離隔將軍幕，',40,'御定全唐詩/json/656.json','["旅榜前年過洞庭，曾提刀筆事甘寧。玳筵離隔將軍幕，", "金貂見服嘉賓散，回首昭丘一涕零。"]'),
('yuding-9','賀淮南節度盧員外賜緋','羅隱','唐','御定全唐诗','yuding','','[]','儉蓮高貴九霄聞，粲粲朱衣降五雲。驄馬早年曾避路，',40,'御定全唐詩/json/656.json','["儉蓮高貴九霄聞，粲粲朱衣降五雲。驄馬早年曾避路，", "應笑當年老萊子，鮮華都自降明君。"]'),
('yuding-10','春日獨游禪智寺','羅隱','唐','御定全唐诗','yuding','','[]','樹遠連天水接空，幾年行樂舊隋宮。花開花謝還如此，',40,'御定全唐詩/json/656.json','["樹遠連天水接空，幾年行樂舊隋宮。花開花謝還如此，", "思量只合騰騰醉，煮海平陳一夢中。"]'),
('yuding-11','和淮南李司空同轉運員外','羅隱','唐','御定全唐诗','yuding','','[]','層層高閣舊瀛洲，此地須征第一流。丞相近年縈倚望，',40,'御定全唐詩/json/656.json','["層層高閣舊瀛洲，此地須征第一流。丞相近年縈倚望，", "誰繼伊皋送行句，梁王詩好郢人愁。"]'),
('yuding-12','後土廟','羅隱','唐','御定全唐诗','yuding','','[]','四海兵戈尚未甯，始於雲外學儀形。九天玄女猶無聖，',40,'御定全唐詩/json/656.json','["四海兵戈尚未甯，始於雲外學儀形。九天玄女猶無聖，", "韋郎年少知何在，端坐思量太白經。"]'),
('yuding-13','金陵夜泊','羅隱','唐','御定全唐诗','yuding','','[]','冷煙輕淡傍衰叢，此夕秦淮駐斷蓬。棲雁遠驚沽酒火，',40,'御定全唐詩/json/656.json','["冷煙輕淡傍衰叢，此夕秦淮駐斷蓬。棲雁遠驚沽酒火，", "六代精靈人不見，思量應在月明中。"]'),
('yuding-14','上江州陳員外','羅隱','唐','御定全唐诗','yuding','','[]','寒江九派轉城樓，東下鐘陵第一州。人自中台方貴盛，',40,'御定全唐詩/json/656.json','["寒江九派轉城樓，東下鐘陵第一州。人自中台方貴盛，", "應恨屬官無健令，異時佳節阻閒遊。"]'),
('yuding-15','廣陵開元寺閣上作','羅隱','唐','御定全唐诗','yuding','','[]','滿檻山川漾落暉，檻前前事去如飛。雲中雞犬劉安過，',40,'御定全唐詩/json/656.json','["滿檻山川漾落暉，檻前前事去如飛。雲中雞犬劉安過，", "紅樓翠幕知多少，長向東風有是非。"]'),
('yuding-16','上鄂州韋尚書','羅隱','唐','御定全唐诗','yuding','','[]','往歲先皇馭九州，侍臣才業最風流。文窮典誥雖餘力，',40,'御定全唐詩/json/656.json','["往歲先皇馭九州，侍臣才業最風流。文窮典誥雖餘力，", "都緣未負江山興，開濟生靈校一秋。"]'),
('yuding-17','早春巴陵道中','羅隱','唐','御定全唐诗','yuding','','[]','遠雪亭亭望未銷，岳陽春淺似相饒。短蘆冒土初生筍，',40,'御定全唐詩/json/656.json','["遠雪亭亭望未銷，岳陽春淺似相饒。短蘆冒土初生筍，", "中流菱唱泊何處，一隻畫船蘭作橈。"]'),
('yuding-18','廣陵秋日酬進士臧濆見寄','羅隱','唐','御定全唐诗','yuding','','[]','驛西斜日滿窗前，獨憑秋欄思渺綿。數尺斷蓬慚故國，',40,'御定全唐詩/json/656.json','["驛西斜日滿窗前，獨憑秋欄思渺綿。數尺斷蓬慚故國，", "空愧荀家好兄弟，雁來魚去是因緣。"]'),
('yuding-19','淮南送李司空朝覲','羅隱','唐','御定全唐诗','yuding','','[]','聖君宵旰望時雍，丹詔西來雨露濃。宣父道高休歎鳳，',40,'御定全唐詩/json/656.json','["聖君宵旰望時雍，丹詔西來雨露濃。宣父道高休歎鳳，", "臘後春前更何事，便看經度奏東封。"]'),
('yuding-20','秋日禪智寺見裴郎中題名寄韋瞻','羅隱','唐','御定全唐诗','yuding','','[]','野寺疏鐘萬木秋，偶尋題處認名侯。官離南郡應閒暇，',40,'御定全唐詩/json/656.json','["野寺疏鐘萬木秋，偶尋題處認名侯。官離南郡應閒暇，", "心知只有韋公在，更對真蹤話舊遊。"]'),
('yuding-21','廣陵春日憶池陽有寄','羅隱','唐','御定全唐诗','yuding','','[]','煙水濛濛接板橋，數年經歷駐征橈。醉憑危檻波千頃，',40,'御定全唐詩/json/656.json','["煙水濛濛接板橋，數年經歷駐征橈。醉憑危檻波千頃，", "清流夾宅千家住，會待閑乘一信潮。"]'),
('yuding-22','春中湘中題嶽麓寺僧舍','羅隱','唐','御定全唐诗','yuding','','[]','蟾宮虎穴兩皆休，來憑危欄送遠愁。多事林鶯還謾語，',40,'御定全唐詩/json/656.json','["蟾宮虎穴兩皆休，來憑危欄送遠愁。多事林鶯還謾語，", "欲共高僧話心跡，野花芳草奈相尤。"]'),
('yuding-23','出試後投所知','羅隱','唐','御定全唐诗','yuding','','[]','此日蓬壺兩日程，當時消息甚分明。桃須曼倩催方熟，',40,'御定全唐詩/json/656.json','["此日蓬壺兩日程，當時消息甚分明。桃須曼倩催方熟，", "莫教更似山西鼠，齧破愁腸恨一生。"]'),
('yuding-24','湘南春日懷古','羅隱','唐','御定全唐诗','yuding','','[]','晴江春暖蘭蕙熏，鳧鷖苒苒鷗著群。洛陽賈誼自無命，',40,'御定全唐詩/json/656.json','["晴江春暖蘭蕙熏，鳧鷖苒苒鷗著群。洛陽賈誼自無命，", "松醪酒好昭潭靜，閑過中流一吊君。"]'),
('yuding-25','江州望廬山','羅隱','唐','御定全唐诗','yuding','','[]','東南蒼翠何崔嵬，橫流一望幽抱開。影寒已令水底去，',40,'御定全唐詩/json/656.json','["東南蒼翠何崔嵬，橫流一望幽抱開。影寒已令水底去，", "仙人往往今誰在，紅杏花香重首回。"]'),
('yuding-26','金陵寄竇尚書','羅隱','唐','御定全唐诗','yuding','','[]','二年岐路有西東，長憶優遊楚驛中。虎帳談高無客繼，',40,'御定全唐詩/json/656.json','["二年岐路有西東，長憶優遊楚驛中。虎帳談高無客繼，", "此去此恩言不得，謾將閑淚對春風。"]'),
('yuding-27','清溪江令公宅','羅隱','唐','御定全唐诗','yuding','','[]','蠻箋象管夜深時，曾賦陳宮第一詩。宴罷風流人不見，',40,'御定全唐詩/json/656.json','["蠻箋象管夜深時，曾賦陳宮第一詩。宴罷風流人不見，", "還有往年金甃井，牧童樵叟等閒窺。"]'),
('yuding-28','鄭州獻盧舍人','羅隱','唐','御定全唐诗','yuding','','[]','海槎閒暇閬風輕，不是安流不肯行。雞省露濃湯餅熟，',40,'御定全唐詩/json/656.json','["海槎閒暇閬風輕，不是安流不肯行。雞省露濃湯餅熟，", "會待兩都收復後，右圖儀錶左題名。"]'),
('yuding-29','別池陽所居','羅隱','唐','御定全唐诗','yuding','','[]','黃塵初起此留連，火耨刀耕六七年。雨夜老農傷水旱，',40,'御定全唐詩/json/656.json','["黃塵初起此留連，火耨刀耕六七年。雨夜老農傷水旱，", "卻是九華山有意，列行相送到江邊。"]'),
('yuding-30','送內使周大夫自杭州朝貢','羅隱','唐','御定全唐诗','yuding','','[]','八都上將近平戎，便附輶軒奏聖聰。三接駕前朝覲禮，',40,'御定全唐詩/json/656.json','["八都上將近平戎，便附輶軒奏聖聰。三接駕前朝覲禮，", "知有殿庭餘力在，莫辭消息寄西風。"]'),
('yuding-31','酬黃從事懷舊見寄','羅隱','唐','御定全唐诗','yuding','','[]','舊遊不合到心中，把得君詩意亦同。水館酒闌清夜月，',40,'御定全唐詩/json/656.json','["舊遊不合到心中，把得君詩意亦同。水館酒闌清夜月，", "世事自隨蓬轉在，思量何處是飛蓬。"]'),
('yuding-32','繡','羅隱','唐','御定全唐诗','yuding','','[]','一片絲羅□□□，洞房西室女工勞。花隨玉指添春色，',40,'御定全唐詩/json/656.json','["一片絲羅□□□，洞房西室女工勞。花隨玉指添春色，", "可中用作鴛鴦被，紅葉枝枝不礙刀。"]'),
('yuding-33','西施','羅隱','唐','御定全唐诗','yuding','','[]','家國興亡自有時，吳人何苦怨西施。',32,'御定全唐詩/json/656.json','["家國興亡自有時，吳人何苦怨西施。", "西施若解傾吳國，越國亡來又是誰。"]'),
('yuding-34','自遣','羅隱','唐','御定全唐诗','yuding','','[]','得即高歌失即休，多愁多恨亦悠悠。',32,'御定全唐詩/json/656.json','["得即高歌失即休，多愁多恨亦悠悠。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('yuding-35','白角篦','羅隱','唐','御定全唐诗','yuding','','[]','白似瓊瑤滑似苔，隨梳伴鏡拂塵埃。',32,'御定全唐詩/json/656.json','["白似瓊瑤滑似苔，隨梳伴鏡拂塵埃。", "莫言此個尖頭物，幾度撩人惡發來。"]'),
('yuding-36','銅雀台','羅隱','唐','御定全唐诗','yuding','','[]','強歌強舞竟難勝，花落花開淚滿膺。',32,'御定全唐詩/json/656.json','["強歌強舞竟難勝，花落花開淚滿膺。", "只合當年伴君死，免交憔悴望西陵。"]'),
('yuding-37','鸚鵡','羅隱','唐','御定全唐诗','yuding','','[]','莫恨雕籠翠羽殘，江南地暖隴西寒。',32,'御定全唐詩/json/656.json','["莫恨雕籠翠羽殘，江南地暖隴西寒。", "勸君不用分明語，語得分明出轉難。"]'),
('yuding-38','金錢花','羅隱','唐','御定全唐诗','yuding','','[]','占得佳名繞樹芳，依依相伴向秋光。',32,'御定全唐詩/json/656.json','["占得佳名繞樹芳，依依相伴向秋光。", "若教此物堪收貯，應被豪門盡劚將。"]'),
('yuding-39','梅','羅隱','唐','御定全唐诗','yuding','','[]','天賜胭脂一抹腮，盤中磊落笛中哀。',32,'御定全唐詩/json/656.json','["天賜胭脂一抹腮，盤中磊落笛中哀。", "雖然未得和羹便，曾與將軍止渴來。"]'),
('yuding-0','錢尚父生日','羅隱','唐','御定全唐诗','yuding','','[]','大昴分光降鬥牛，興唐宗社作諸侯。伊夔事業扶千載，',40,'御定全唐詩/json/657.json','["大昴分光降鬥牛，興唐宗社作諸侯。伊夔事業扶千載，", "錦衣玉食將何報，更俟莊椿一舉頭。"]'),
('yuding-1','寄前戶部陸郎中','羅隱','唐','御定全唐诗','yuding','','[]','出馴桑雉入朝簪，簫灑清名映士林。近日篇章欺白雪，',40,'御定全唐詩/json/657.json','["出馴桑雉入朝簪，簫灑清名映士林。近日篇章欺白雪，", "離亂事多人不會，酒濃花暖且閑吟。"]'),
('yuding-2','登瓦棺寺閣','羅隱','唐','御定全唐诗','yuding','','[]','下盤空跡上雲浮，偶逐僧行步步愁。暫憩已知須用意，',40,'御定全唐詩/json/657.json','["下盤空跡上雲浮，偶逐僧行步步愁。暫憩已知須用意，", "懶指台城更東望，鵲飛龍鬥盡荒丘。"]'),
('yuding-3','九華山費征君所居','羅隱','唐','御定全唐诗','yuding','','[]','草堂何處試徘徊，見說遺蹤向此開。蟾桂自歸三徑後，',40,'御定全唐詩/json/657.json','["草堂何處試徘徊，見說遺蹤向此開。蟾桂自歸三徑後，", "盡夕為君思曩日，野泉嗚咽路莓苔。"]'),
('yuding-4','途中寄懷','羅隱','唐','御定全唐诗','yuding','','[]','不知何處是前程，合眼騰騰信馬行。兩鬢已衰時未遇，',40,'御定全唐詩/json/657.json','["不知何處是前程，合眼騰騰信馬行。兩鬢已衰時未遇，", "試哭軍門看誰問，舊來還似禰先生。"]'),
('yuding-5','京口見李侍郎','羅隱','唐','御定全唐诗','yuding','','[]','傞傞江柳欲矜春，鐵甕城邊見故人。屈指不堪言甲子，',40,'御定全唐詩/json/657.json','["傞傞江柳欲矜春，鐵甕城邊見故人。屈指不堪言甲子，", "還有杖頭沽酒物，待尋山寺話逡巡。"]'),
('yuding-6','秋日酬張特玄','羅隱','唐','御定全唐诗','yuding','','[]','病寄南徐兩度秋，故人依約亦揚州。偶因雁足思閒事，',40,'御定全唐詩/json/657.json','["病寄南徐兩度秋，故人依約亦揚州。偶因雁足思閒事，", "平生意氣消磨盡，甘露軒前看水流。"]'),
('yuding-7','登高詠菊盡','羅隱','唐','御定全唐诗','yuding','','[]','籬畔霜前偶得存，苦教遲晚避蘭蓀。能銷造化幾多力，',40,'御定全唐詩/json/657.json','["籬畔霜前偶得存，苦教遲晚避蘭蓀。能銷造化幾多力，", "陶公沒後無知己，露滴幽叢見淚痕。"]'),
('yuding-8','登夏州城樓','羅隱','唐','御定全唐诗','yuding','','[]','寒城獵獵戍旗風，獨倚危樓悵望中。萬里山河唐土地，',40,'御定全唐詩/json/657.json','["寒城獵獵戍旗風，獨倚危樓悵望中。萬里山河唐土地，", "好脫儒冠從校尉，一枝長戟六鈞弓。"]'),
('yuding-9','水邊偶題','羅隱','唐','御定全唐诗','yuding','','[]','野水無情去不回，水邊花好為誰開。只知事逐眼前去，',40,'御定全唐詩/json/657.json','["野水無情去不回，水邊花好為誰開。只知事逐眼前去，", "思量此理何人會，蒙邑先生最有才。"]'),
('yuding-10','故洛陽公鎮大梁時隱得遊門下今之經歷事往人非聊抒所懷以傷以謝','羅隱','唐','御定全唐诗','yuding','','[]','孤舟欲泊思何窮，曾憶西來值雪中。珠履少年初滿座，',40,'御定全唐詩/json/657.json','["孤舟欲泊思何窮，曾憶西來值雪中。珠履少年初滿座，", "今日斯文向誰說，淚碑棠樹兩成空。"]'),
('yuding-11','杜陵秋思','羅隱','唐','御定全唐诗','yuding','','[]','南望商於北帝都，兩堪棲托兩無圖。只聞斥逐張公子，',40,'御定全唐詩/json/657.json','["南望商於北帝都，兩堪棲托兩無圖。只聞斥逐張公子，", "一杯淥酒他年憶，瀝向清波寄五湖。"]');
